import React, { useState, useEffect, useRef } from 'react';
import { Wind, Heart, Sparkles, Play, Pause, Volume2, Loader2, Music, RotateCcw, CheckCircle } from 'lucide-react';
import { generateLouiseHayAffirmation, generateMeditationScript, generateBreathingVoice, generateSpeech } from '../services/geminiService';

// Helper functions for audio decoding
function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext
): Promise<AudioBuffer> {
  return await ctx.decodeAudioData(data.buffer.slice(0)); 
}

type BreathingPattern = '478' | 'box' | 'coherence';

const PATTERNS = {
  '478': { name: 'Relaxamento (4-7-8)', phases: ['Inspire', 'Segure', 'Expire'] },
  'box': { name: 'Foco (Quadrada)', phases: ['Inspire', 'Segure', 'Expire', 'Segure Vazio'] },
  'coherence': { name: 'Equilíbrio (Coerência)', phases: ['Inspire', 'Expire'] }
};

const Wellness: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'meditation' | 'emotional' | 'healing-ritual'>('meditation');
  const [generatedContent, setGeneratedContent] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  // Ritual State
  const [ritualStep, setRitualStep] = useState<'idle' | 'preparing' | 'feeling' | 'affirming' | 'forgiving' | 'checking'>('idle');
  const [personalMessage, setPersonalMessage] = useState('');
  const [ritualAudio, setRitualAudio] = useState<{ [key: string]: AudioBuffer | null }>({});

  // Breathing state
  const [pattern, setPattern] = useState<BreathingPattern>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('breathingPattern');
      if (saved === '478' || saved === 'box' || saved === 'coherence') {
        return saved;
      }
    }
    return '478';
  });

  const [isBreathing, setIsBreathing] = useState(false);
  const [breathPhase, setBreathPhase] = useState('Pronto');
  const [audioBuffers, setAudioBuffers] = useState<{ [key: string]: AudioBuffer | null }>({
    inspire: null,
    hold: null,
    exhale: null,
    holdEmpty: null
  });
  const [loadingAudio, setLoadingAudio] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Audio Playback State
  const [contentAudio, setContentAudio] = useState<AudioBuffer | null>(null);
  const [isPlayingContent, setIsPlayingContent] = useState(false);
  const contentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  useEffect(() => {
    localStorage.setItem('breathingPattern', pattern);
  }, [pattern]);

  const initAudioContext = async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }
  };

  const stopContentAudio = () => {
    if (contentSourceRef.current) {
      try {
        contentSourceRef.current.stop();
      } catch (e) {}
      contentSourceRef.current.disconnect();
      contentSourceRef.current = null;
    }
    setIsPlayingContent(false);
  };

  const preloadBreathingAudio = async () => {
    if (audioBuffers.inspire && audioBuffers.hold && audioBuffers.exhale) return;
    setLoadingAudio(true);
    try {
      await initAudioContext();
      const phrases = {
        inspire: "Inspire devagar... trazendo calma...",
        hold: "Segure o ar... sinta a paz...",
        exhale: "Solte o ar... relaxando tudo...",
        holdEmpty: "Fique no vazio... apenas sinta..."
      };
      const newBuffers = { ...audioBuffers };
      for (const [key, text] of Object.entries(phrases)) {
        if (!newBuffers[key]) {
          const base64 = await generateBreathingVoice(text);
          if (base64) {
            const bytes = decodeBase64(base64);
            const buffer = await decodeAudioData(bytes, audioContextRef.current!);
            newBuffers[key] = buffer;
          }
        }
      }
      setAudioBuffers(newBuffers);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingAudio(false);
    }
  };

  const playBuffer = async (buffer: AudioBuffer) => {
    await initAudioContext();
    const source = audioContextRef.current!.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContextRef.current!.destination);
    source.start();
    return new Promise(resolve => {
      source.onended = resolve;
    });
  };

  const handleTabChange = (tab: 'meditation' | 'emotional' | 'healing-ritual') => {
    setActiveTab(tab);
    setIsBreathing(false);
    setRitualStep('idle');
    stopContentAudio();
  };

  // Ritual Logic
  const startHealingRitual = async () => {
    setLoading(true);
    setRitualStep('preparing');
    await initAudioContext();

    try {
      const scripts = {
        feeling: "Feche os olhos suavemente... Entre em contato com algo muito doloroso para você... Sinta as emoções... Não fuja delas agora...",
        affirming: `Diga para si mesmo: eu sobrevivi a essas dores profundas... Não foi fácil, mas sobrevivi e me tornei ainda mais forte e resiliente... Essa situação não me define e me tornou um ser humano ainda melhor... ${personalMessage}`,
        forgiving: "Agora, fale para quem te magoou: eu te perdoo porque sei que você deu o seu melhor naquele momento... Eu te libero e me libero...",
        checking: "Abra os olhos devagar... Sinta o presente... Agora feche-os novamente... Se a dor voltar, repetiremos o processo até que ela suma completamente."
      };

      const buffers: { [key: string]: AudioBuffer } = {};
      for (const [key, text] of Object.entries(scripts)) {
        const base64 = await generateSpeech(text);
        if (base64) {
          const bytes = decodeBase64(base64);
          buffers[key] = await decodeAudioData(bytes, audioContextRef.current!);
        }
      }
      setRitualAudio(buffers);
      runRitualCycle(buffers);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const runRitualCycle = async (buffers = ritualAudio) => {
    setRitualStep('feeling');
    if (buffers.feeling) await playBuffer(buffers.feeling);
    await new Promise(r => setTimeout(r, 2000));

    setRitualStep('affirming');
    if (buffers.affirming) await playBuffer(buffers.affirming);
    await new Promise(r => setTimeout(r, 2000));

    setRitualStep('forgiving');
    if (buffers.forgiving) await playBuffer(buffers.forgiving);
    await new Promise(r => setTimeout(r, 2000));

    setRitualStep('checking');
    if (buffers.checking) await playBuffer(buffers.checking);
  };

  // Breathing Effects
  useEffect(() => {
    if (isBreathing) {
      const runCycle = async () => {
        const playCue = (key: string) => audioBuffers[key] && playBuffer(audioBuffers[key]!);
        if (pattern === '478') {
          setBreathPhase('Inspire (4s)'); playCue('inspire');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Segure (7s)'); playCue('hold');
          await new Promise(r => timerRef.current = setTimeout(r, 7000));
          if (!isBreathing) return;
          setBreathPhase('Expire (8s)'); playCue('exhale');
          await new Promise(r => timerRef.current = setTimeout(r, 8000));
        } else if (pattern === 'box') {
          setBreathPhase('Inspire (4s)'); playCue('inspire');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Segure (4s)'); playCue('hold');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Expire (4s)'); playCue('exhale');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Vazio (4s)'); playCue('holdEmpty');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
        } else if (pattern === 'coherence') {
          setBreathPhase('Inspire (6s)'); playCue('inspire');
          await new Promise(r => timerRef.current = setTimeout(r, 6000));
          if (!isBreathing) return;
          setBreathPhase('Expire (6s)'); playCue('exhale');
          await new Promise(r => timerRef.current = setTimeout(r, 6000));
        }
        if (isBreathing) runCycle();
      };
      runCycle();
    } else {
      if (timerRef.current) clearTimeout(timerRef.current);
      setBreathPhase('Pronto');
    }
  }, [isBreathing, pattern, audioBuffers]);

  return (
    <div className="p-4 pb-24 max-w-2xl mx-auto">
      <header className="mb-6">
        <h2 className="text-2xl font-serif text-nature-800">Santuário Interior</h2>
        <p className="text-nature-600 text-sm">Cura profunda e reconexão.</p>
      </header>

      <div className="flex bg-gray-100 p-1 rounded-xl mb-6 overflow-x-auto">
        <button 
          onClick={() => handleTabChange('meditation')}
          className={`flex-1 py-2 text-xs font-medium rounded-lg transition-all whitespace-nowrap px-3 ${activeTab === 'meditation' ? 'bg-white shadow text-nature-700' : 'text-gray-500'}`}
        >
          Respiração
        </button>
        <button 
          onClick={() => handleTabChange('emotional')}
          className={`flex-1 py-2 text-xs font-medium rounded-lg transition-all whitespace-nowrap px-3 ${activeTab === 'emotional' ? 'bg-white shadow text-pink-600' : 'text-gray-500'}`}
        >
          Afirmações
        </button>
        <button 
          onClick={() => handleTabChange('healing-ritual')}
          className={`flex-1 py-2 text-xs font-medium rounded-lg transition-all whitespace-nowrap px-3 ${activeTab === 'healing-ritual' ? 'bg-white shadow text-rose-600' : 'text-gray-500'}`}
        >
          Ritual de Cura
        </button>
      </div>

      {activeTab === 'meditation' && (
        <div className="space-y-6">
          <div className="bg-gradient-to-br from-blue-50 to-indigo-50 p-6 rounded-2xl flex flex-col items-center justify-center text-center relative overflow-hidden min-h-[350px]">
            <div className={`absolute bg-blue-200 rounded-full blur-2xl opacity-40 transition-all ease-in-out duration-1000 ${breathPhase.includes('Inspire') ? 'w-64 h-64' : breathPhase.includes('Segure') || breathPhase.includes('Vazio') ? 'w-60 h-60' : 'w-32 h-32'}`}></div>
            <div className="z-10 w-full mb-4">
               <div className="flex justify-center gap-2 mb-4">
                  {(Object.keys(PATTERNS) as BreathingPattern[]).map((p) => (
                    <button key={p} onClick={() => { setIsBreathing(false); setPattern(p); }} className={`text-[10px] px-3 py-1 rounded-full border transition-colors ${pattern === p ? 'bg-blue-500 text-white border-blue-500' : 'bg-white text-blue-400 border-blue-200 hover:bg-blue-50'}`}>
                        {PATTERNS[p].name}
                    </button>
                  ))}
               </div>
            </div>
            <Wind className={`text-blue-500 mb-4 z-10 transition-transform duration-[4000ms] ${breathPhase.includes('Inspire') ? 'scale-125' : 'scale-100'}`} size={32} />
            <h3 className="font-serif text-xl text-blue-900 mb-1 z-10">{PATTERNS[pattern].name}</h3>
            <div className="text-3xl font-bold text-blue-800 mb-8 z-10 h-10 flex items-center justify-center">
               {loadingAudio ? <Loader2 className="animate-spin" /> : breathPhase}
            </div>
            <button onClick={async () => { await initAudioContext(); if (!isBreathing) await preloadBreathingAudio(); setIsBreathing(!isBreathing); }} disabled={loadingAudio} className="bg-white text-blue-600 px-8 py-3 rounded-full font-bold shadow-sm flex items-center gap-2 hover:shadow-md transition-all z-10 disabled:opacity-70">
              {isBreathing ? <Pause size={18}/> : <Play size={18}/>}
              {isBreathing ? 'Pausar' : 'Iniciar'}
            </button>
          </div>
        </div>
      )}

      {activeTab === 'emotional' && (
        <div className="space-y-6">
           <div className="bg-gradient-to-br from-pink-50 to-rose-50 p-6 rounded-2xl">
              <div className="flex items-center gap-3 mb-4">
                <Heart className="text-pink-400" />
                <h3 className="font-serif text-xl text-pink-900">Espelho da Alma</h3>
              </div>
              <p className="text-pink-800/70 text-sm mb-4">Digite o que está sentindo para receber uma afirmação de cura.</p>
              <input type="text" value={personalMessage} onChange={(e) => setPersonalMessage(e.target.value)} placeholder="Ex: Medo, Culpa, Dor no estômago..." className="w-full p-3 rounded-lg border-pink-100 bg-white/80 mb-3 text-pink-900 placeholder:text-pink-300" />
              <button onClick={async () => {
                setLoading(true); setGeneratedContent(null);
                const textResult = await generateLouiseHayAffirmation(personalMessage);
                setGeneratedContent(textResult);
                const audioBase64 = await generateSpeech(textResult);
                if (audioBase64) {
                  const bytes = decodeBase64(audioBase64);
                  setContentAudio(await decodeAudioData(bytes, audioContextRef.current!));
                }
                setLoading(false);
              }} disabled={loading || !personalMessage} className="w-full bg-pink-400 text-white py-3 rounded-lg font-bold hover:bg-pink-500 transition-colors disabled:opacity-50">
                {loading ? 'Consultando sabedoria...' : 'Gerar Afirmação'}
              </button>
           </div>
           {generatedContent && (
             <div className="mt-4 p-6 bg-white rounded-2xl shadow-lg border border-nature-100 animate-in fade-in slide-in-from-bottom-4">
               <Sparkles className="text-yellow-400 mb-2 mx-auto" />
               <p className="text-center font-serif text-lg leading-relaxed text-gray-700 italic mb-4">"{generatedContent}"</p>
               {contentAudio && (
                 <button onClick={() => playBuffer(contentAudio)} className="w-full flex items-center justify-center gap-2 bg-pink-50 text-pink-700 py-3 rounded-xl font-medium">
                   <Volume2 size={20} /> Ouvir Guia
                 </button>
               )}
             </div>
           )}
        </div>
      )}

      {activeTab === 'healing-ritual' && (
        <div className="space-y-6">
           {ritualStep === 'idle' ? (
             <div className="bg-gradient-to-br from-rose-50 to-red-50 p-6 rounded-2xl border border-rose-100">
                <h3 className="font-serif text-xl text-rose-900 mb-2 flex items-center gap-2">
                  <Heart className="text-rose-500" fill="currentColor" /> Ritual de Cura Profunda
                </h3>
                <p className="text-rose-800/70 text-sm mb-6 leading-relaxed">
                  Este é um exercício de liberação para dores profundas. Vamos enfrentar o que dói, reconhecer nossa força e perdoar para sermos livres.
                </p>
                <label className="block text-xs font-bold text-rose-900 uppercase mb-2">O que você deseja falar para si mesmo agora?</label>
                <textarea 
                  value={personalMessage}
                  onChange={(e) => setPersonalMessage(e.target.value)}
                  placeholder="Ex: Eu mereço ser feliz, Eu sou digno de amor..."
                  className="w-full p-4 rounded-xl border-rose-200 bg-white mb-4 text-rose-900 focus:ring-2 focus:ring-rose-300 outline-none"
                  rows={3}
                />
                <button 
                  onClick={startHealingRitual}
                  disabled={loading || !personalMessage}
                  className="w-full bg-rose-600 text-white py-4 rounded-xl font-bold shadow-lg shadow-rose-200 flex items-center justify-center gap-2"
                >
                  {loading ? <Loader2 className="animate-spin" /> : <Sparkles size={20} />}
                  Iniciar Ritual Sagrado
                </button>
             </div>
           ) : (
             <div className="bg-white p-8 rounded-3xl shadow-xl border border-rose-50 flex flex-col items-center text-center animate-in zoom-in duration-500">
                <div className="w-24 h-24 bg-rose-100 rounded-full flex items-center justify-center mb-6 relative">
                   <div className={`absolute inset-0 bg-rose-200 rounded-full animate-ping opacity-20`}></div>
                   <Heart size={40} className="text-rose-500" fill={ritualStep === 'affirming' ? 'currentColor' : 'none'} />
                </div>

                <h4 className="text-rose-900 font-serif text-2xl mb-4">
                  {ritualStep === 'feeling' && "Sinta a Dor..."}
                  {ritualStep === 'affirming' && "Reconheça sua Força"}
                  {ritualStep === 'forgiving' && "O Poder do Perdão"}
                  {ritualStep === 'checking' && "Estado de Paz"}
                </h4>

                <div className="min-h-[120px] flex items-center px-4">
                  <p className="text-gray-600 text-lg italic leading-relaxed">
                    {ritualStep === 'feeling' && "Feche os olhos. Localize a dor em seu corpo. Sinta-a sem julgamento."}
                    {ritualStep === 'affirming' && "Eu sobrevivi a essas dores profundas. Sou forte, resiliente e nada disso me define."}
                    {ritualStep === 'forgiving' && "Eu te perdoo porque sei que você deu o seu melhor naquele momento. Eu me liberto."}
                    {ritualStep === 'checking' && "Abra os olhos... Respire. Como você se sente agora?"}
                  </p>
                </div>

                {ritualStep === 'checking' && (
                  <div className="grid grid-cols-1 gap-3 w-full mt-8">
                    <button 
                      onClick={() => runRitualCycle()}
                      className="flex items-center justify-center gap-2 bg-rose-50 text-rose-700 py-4 rounded-xl font-bold hover:bg-rose-100"
                    >
                      <RotateCcw size={20} /> Ainda sinto dor (Repetir)
                    </button>
                    <button 
                      onClick={() => setRitualStep('idle')}
                      className="flex items-center justify-center gap-2 bg-nature-600 text-white py-4 rounded-xl font-bold shadow-lg shadow-nature-100"
                    >
                      <CheckCircle size={20} /> Estou em paz
                    </button>
                  </div>
                )}
             </div>
           )}
        </div>
      )}
    </div>
  );
};

export default Wellness;

import React, { useState, useRef } from 'react';
import { Heart, MessageCircle, Share2, Image as ImageIcon, Video as VideoIcon, X, Check } from 'lucide-react';
import { CommunityPost } from '../types';

const MOCK_POSTS: CommunityPost[] = [
  {
    id: '0',
    author: 'Guia Essência',
    avatar: 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=100&auto=format&fit=crop',
    content: 'Olá Tribo! Segue uma orientação rápida sobre como lidar com a vontade de comer doces nos primeiros dias. Mantenham o foco! 🌱',
    likes: 156,
    comments: 42,
    timestamp: Date.now() - 1800000,
    video: 'https://www.w3schools.com/html/mov_bbb.mp4' // Sample video
  },
  {
    id: '1',
    author: 'Maria S.',
    avatar: 'https://picsum.photos/50/50?random=1',
    content: 'Hoje completei 10 dias sem glúten! O inchaço sumiu completamente. Tão feliz! 🌿 #JornadaSemGluten',
    likes: 24,
    comments: 5,
    timestamp: Date.now() - 3600000,
    image: 'https://picsum.photos/400/200?random=10'
  },
  {
    id: '2',
    author: 'João P.',
    avatar: 'https://picsum.photos/50/50?random=2',
    content: 'A meditação guiada de hoje para o estômago foi incrível. Senti uma paz que não sentia há tempos.',
    likes: 12,
    comments: 2,
    timestamp: Date.now() - 7200000
  },
];

const Community: React.FC = () => {
  const [posts, setPosts] = useState<CommunityPost[]>(MOCK_POSTS);
  const [newPost, setNewPost] = useState('');
  const [selectedVideo, setSelectedVideo] = useState<File | null>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const [showShareToast, setShowShareToast] = useState<string | null>(null);

  const handlePost = () => {
    if (!newPost.trim() && !selectedVideo) return;

    let videoUrl: string | undefined = undefined;
    if (selectedVideo) {
      videoUrl = URL.createObjectURL(selectedVideo);
    }

    const post: CommunityPost = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      content: newPost,
      likes: 0,
      comments: 0,
      timestamp: Date.now(),
      video: videoUrl
    };
    setPosts([post, ...posts]);
    setNewPost('');
    setSelectedVideo(null);
  };

  const handleVideoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.type.startsWith('video/')) {
        setSelectedVideo(file);
      } else {
        alert('Por favor, selecione um arquivo de vídeo válido.');
      }
    }
  };

  const handleShare = async (post: CommunityPost) => {
    const shareUrl = `https://reviva.app/tribo/${post.id}`;
    const shareData = {
      title: 'ReViva - Tribo Essência',
      text: `Veja o que ${post.author} compartilhou na Tribo Essência: "${post.content.substring(0, 60)}..."`,
      url: shareUrl,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        if ((err as Error).name !== 'AbortError') {
          console.error('Erro ao compartilhar:', err);
        }
      }
    } else {
      // Fallback para navegadores que não suportam a Web Share API
      const copyPrompt = window.prompt(
        "Compartilhe esta postagem copiando o link abaixo:",
        shareUrl
      );

      if (copyPrompt !== null) {
        try {
          await navigator.clipboard.writeText(shareUrl);
          setShowShareToast(post.id);
          setTimeout(() => setShowShareToast(null), 3000);
        } catch (e) {
          console.error("Falha ao copiar automaticamente.");
        }
      }
    }
  };

  return (
    <div className="p-4 pb-24 max-w-2xl mx-auto">
      <header className="mb-6">
        <h2 className="text-2xl font-serif text-nature-800">Tribo Essência</h2>
        <p className="text-nature-600 text-sm">Apoio mútuo e orientações em vídeo.</p>
      </header>

      {/* Input Area */}
      <div className="bg-white p-4 rounded-2xl shadow-sm mb-6 border border-gray-100">
        <textarea
          value={newPost}
          onChange={(e) => setNewPost(e.target.value)}
          placeholder="Compartilhe sua vitória, dúvida ou vídeo..."
          className="w-full bg-gray-50 rounded-lg p-3 text-sm focus:ring-2 focus:ring-nature-200 outline-none resize-none mb-3"
          rows={3}
        />

        {selectedVideo && (
          <div className="mb-3 bg-nature-50 p-2 rounded-lg flex items-center justify-between text-sm text-nature-700">
            <span className="truncate max-w-[200px] flex items-center gap-2">
              <VideoIcon size={16} /> {selectedVideo.name}
            </span>
            <button onClick={() => setSelectedVideo(null)} className="text-gray-400 hover:text-red-500">
              <X size={16} />
            </button>
          </div>
        )}

        <div className="flex justify-between items-center">
            <div className="flex gap-2">
              <button className="text-gray-400 hover:text-nature-600 p-2 rounded-full hover:bg-gray-100 transition-colors">
                  <ImageIcon size={20} />
              </button>
              <button 
                onClick={() => videoInputRef.current?.click()}
                className={`p-2 rounded-full hover:bg-gray-100 transition-colors ${selectedVideo ? 'text-nature-600' : 'text-gray-400 hover:text-nature-600'}`}
              >
                  <VideoIcon size={20} />
              </button>
              <input 
                type="file" 
                ref={videoInputRef} 
                onChange={handleVideoSelect} 
                accept="video/*" 
                className="hidden" 
              />
            </div>
            <button 
                onClick={handlePost}
                disabled={!newPost.trim() && !selectedVideo}
                className="bg-nature-600 text-white px-6 py-2 rounded-full text-sm font-bold disabled:opacity-50 hover:bg-nature-700 transition-colors shadow-md shadow-nature-100"
            >
                Publicar
            </button>
        </div>
      </div>

      {/* Feed */}
      <div className="space-y-4">
        {posts.map(post => (
