                    onClick={() => handleShare(post)}
                    className="flex items-center gap-1.5 text-gray-400 hover:text-nature-600 text-sm transition-colors bg-nature-50 p-2 rounded-full hover:bg-nature-100"
                    title="Compartilhar postagem"
                  >
                      <Share2 size={18} />
                  </button>
                </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

