import React, { useEffect, useState } from 'react';
import { UserProfile, DailyLog } from '../types';
import { ResponsiveContainer, LineChart, Line, XAxis, Tooltip } from 'recharts';
import { CheckCircle2, Circle, Info, Bell, BellRing, Sparkles } from 'lucide-react';
import { generateReminderNudge } from '../services/geminiService';

interface DashboardProps {
  userProfile: UserProfile;
  logs: DailyLog[];
}

const Dashboard: React.FC<DashboardProps> = ({ userProfile, logs }) => {
  const [notificationPermission, setNotificationPermission] = useState(
    typeof Notification !== 'undefined' ? Notification.permission : 'default'
  );
  const [isGeneratingReminder, setIsGeneratingReminder] = useState(false);

  const daysOnDiet = userProfile.startDate 
    ? Math.floor((new Date().getTime() - new Date(userProfile.startDate).getTime()) / (1000 * 3600 * 24))
    : 0;

  const progressPercentage = Math.min(100, (daysOnDiet / 21) * 100);

  const chartData = logs.slice(-7).map(log => ({
    name: new Date(log.date).toLocaleDateString('pt-BR', {weekday: 'short'}),
    humor: log.mood,
    sintomas: log.symptomsPresent.length
  }));

  const lastLog = logs[logs.length-1];

  const todaysGoals = [
    { label: 'Dieta (S/G, S/L, S/A)', completed: lastLog?.completedActions.diet, id: 'diet' },
    { label: 'Beber 2 Litros de Água', completed: lastLog?.completedActions.waterGoal, id: 'water' },
    { label: 'Registro no Diário', completed: lastLog?.completedActions.diary, id: 'diary' },
    { label: 'Meditação ou Respiração', completed: lastLog?.completedActions.meditationOrBreathing, id: 'meditation' },
    { label: 'Exercício Físico Leve', completed: lastLog?.completedActions.exercise, id: 'exercise' },
    { label: 'Aterramento (10 minutos)', completed: lastLog?.completedActions.earthing, id: 'earthing' },
    { label: 'Cura Emocional (Louise Hay)', completed: lastLog?.completedActions.emotionalWork, id: 'emotional' },
  ];

  const pendingGoals = todaysGoals.filter(g => !g.completed);
  const pendingGoalsCount = pendingGoals.length;

  // Auto-reminder logic
  useEffect(() => {
    const checkReminder = async () => {
      if (notificationPermission === 'granted' && pendingGoalsCount > 0) {
        const today = new Date().toDateString();
        const lastReminder = localStorage.getItem('lastReminderDate');

        if (lastReminder !== today) {
          await triggerReminder();
          localStorage.setItem('lastReminderDate', today);
        }
      }
    };
    checkReminder();
  }, [notificationPermission, pendingGoalsCount]);

  const requestNotificationPermission = async () => {
    if (!("Notification" in window)) {
      alert("Este navegador não suporta notificações.");
      return;
    }

    const permission = await Notification.requestPermission();
    setNotificationPermission(permission);

    if (permission === 'granted') {
      triggerReminder();
    }
  };

  const triggerReminder = async () => {
    if (isGeneratingReminder) return;
    setIsGeneratingReminder(true);

    try {
      if (pendingGoalsCount > 0) {
        const nudgeText = await generateReminderNudge(
          userProfile.name, 
          pendingGoals.map(g => g.label)
        );

        new Notification("ReViva - Lembrete Essencial", {
          body: nudgeText || `Olá ${userProfile.name}! Você ainda tem metas pendentes para hoje. 🌱`,
          icon: 'https://cdn-icons-png.flaticon.com/512/2964/2964514.png',
          tag: 'daily-nudge'
        });
      } else {
         new Notification("Parabéns!", {
          body: `Você já completou todas as metas de hoje! Sua essência está radiante. ✨`,
          icon: 'https://cdn-icons-png.flaticon.com/512/2964/2964514.png',
        });
      }
    } catch (e) {
      console.error("Reminder Error", e);
    } finally {
      setIsGeneratingReminder(false);
    }
  };

  return (
    <div className="p-4 pb-24 max-w-2xl mx-auto space-y-6">
      <header className="flex justify-between items-center">
        <div>
           <h2 className="text-2xl font-serif text-nature-800">Olá, {userProfile.name}</h2>
           <p className="text-nature-600 text-sm">Dia {daysOnDiet} de 21 da reconexão.</p>
        </div>
        <div className="flex items-center gap-3">
            <button 
              onClick={notificationPermission === 'granted' ? triggerReminder : requestNotificationPermission}
              disabled={isGeneratingReminder}
              className={`relative p-2.5 rounded-full bg-white border border-nature-100 shadow-sm transition-all ${
                pendingGoalsCount > 0 && notificationPermission === 'granted' 
                  ? 'text-nature-600 hover:bg-nature-50' 
                  : 'text-gray-300'
              }`}
            >
              {isGeneratingReminder ? <Sparkles size={20} className="animate-pulse text-nature-400" /> : 
               (pendingGoalsCount > 0 && notificationPermission === 'granted' ? <BellRing size={20} className="animate-bounce" /> : <Bell size={20} />)}

              {pendingGoalsCount > 0 && (
                <span className="absolute top-0 right-0 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white"></span>
              )}
            </button>

            <div className="w-12 h-12 rounded-full bg-nature-200 flex items-center justify-center text-nature-700 font-bold shrink-0 shadow-inner border border-nature-300">
                {Math.round(progressPercentage)}%
            </div>
        </div>
      </header>

      {/* Notification Banner Request */}
      {notificationPermission !== 'granted' && (
        <div className="bg-gradient-to-r from-blue-50 to-indigo-50 p-4 rounded-2xl border border-blue-100 flex items-center justify-between shadow-sm animate-in fade-in slide-in-from-top-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-white rounded-full text-blue-500 shadow-sm">
              <Bell size={20} />
            </div>
            <div>
              <p className="text-xs font-bold text-blue-900">Mantenha o Foco</p>
              <p className="text-[10px] text-blue-800/70">Ative lembretes para suas metas diárias.</p>
            </div>
          </div>
          <button 
            onClick={requestNotificationPermission}
            className="text-xs bg-blue-600 text-white px-4 py-2 rounded-xl font-bold shadow-md shadow-blue-200 hover:bg-blue-700 active:scale-95 transition-all"
          >
            Ativar
          </button>
        </div>
      )}

      {/* Progress Card */}
      <div className="bg-white p-5 rounded-2xl shadow-sm border border-nature-50">
        <div className="flex justify-between text-xs font-medium text-gray-400 mb-3">
            <span>Início da Jornada</span>
            <span>Meta: 21 Dias</span>
        </div>
        <div className="w-full bg-gray-100 rounded-full h-4 overflow-hidden p-0.5">
            <div 
                className="bg-gradient-to-r from-nature-300 via-nature-500 to-nature-600 h-full rounded-full transition-all duration-1000 shadow-sm"
                style={{ width: `${progressPercentage}%` }}
            ></div>
        </div>
        <p className="text-xs text-center mt-3 text-nature-600 italic">"Cada dia é um passo em direção ao seu verdadeiro eu."</p>
      </div>

      {/* Daily Goals */}
      <section className="bg-white p-5 rounded-2xl shadow-sm border border-nature-50">
        <div className="flex justify-between items-center mb-4">
            <h3 className="font-serif text-lg text-nature-800">Metas de Hoje</h3>
            {pendingGoalsCount > 0 ? (
                <span className="text-[10px] bg-orange-100 text-orange-700 px-2.5 py-1 rounded-full font-bold uppercase tracking-wider">
                    {pendingGoalsCount} pendentes
                </span>
            ) : (
                <span className="text-[10px] bg-green-100 text-green-700 px-2.5 py-1 rounded-full font-bold uppercase tracking-wider">
                    Tudo Pronto!
                </span>
            )}
        </div>

        <div className="bg-sand-50 p-3 rounded-xl mb-5 text-[11px] text-sand-800 border border-sand-200 flex gap-2">
           <Info size={14} className="text-sand-600 shrink-0 mt-0.5" />
           <div className="flex flex-wrap gap-x-4 gap-y-1">
             <span className="font-medium"><span className="text-nature-600 font-bold">S/G:</span> Sem Glúten</span>
             <span className="font-medium"><span className="text-blue-500 font-bold">S/L:</span> Sem Leite</span>
             <span className="font-medium"><span className="text-pink-500 font-bold">S/A:</span> Sem Açúcar</span>
           </div>
        </div>

        <div className="grid grid-cols-1 gap-2.5">
            {todaysGoals.map((goal, idx) => (
                <div key={idx} className={`flex items-center p-3.5 rounded-2xl border transition-all ${goal.completed ? 'bg-nature-50 border-nature-100 opacity-80' : 'bg-white border-gray-100 hover:border-nature-200 shadow-sm'}`}>
                    {goal.completed ? (
                        <CheckCircle2 className="text-nature-500 mr-3 shrink-0" size={20} />
                    ) : (
                        <Circle className="text-gray-200 mr-3 shrink-0" size={20} />
                    )}
                    <span className={`text-sm ${goal.completed ? 'text-nature-800 line-through' : 'text-gray-700 font-medium'}`}>
                        {goal.label}
                    </span>
                </div>
            ))}
        </div>
      </section>

      {/* Chart */}
      {chartData.length > 0 && (
        <section className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
           <div className="flex items-center justify-between mb-6">
             <h3 className="font-serif text-lg text-nature-800">Seu Bem-Estar</h3>
             <div className="flex gap-4 text-[10px] font-bold uppercase tracking-tighter">
                <span className="flex items-center text-nature-600"><span className="w-2 h-2 rounded-full bg-nature-500 mr-1.5"></span> Humor</span>
                <span className="flex items-center text-orange-600"><span className="w-2 h-2 rounded-full bg-orange-500 mr-1.5"></span> Sintomas</span>
             </div>
           </div>
           <div className="h-48 w-full">
             <ResponsiveContainer width="100%" height="100%">
               <LineChart data={chartData}>
                  <XAxis dataKey="name" stroke="#cbd5e1" fontSize={10} tickLine={false} axisLine={false} />
                  <Tooltip 
                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', fontSize: '12px' }}
                  />
                  <Line type="monotone" dataKey="humor" stroke="#6a9c5b" strokeWidth={3} dot={{r: 4, fill: '#6a9c5b', strokeWidth: 2, stroke: '#fff'}} />
                  <Line type="monotone" dataKey="sintomas" stroke="#f59e0b" strokeWidth={3} dot={{r: 4, fill: '#f59e0b', strokeWidth: 2, stroke: '#fff'}} />
               </LineChart>
             </ResponsiveContainer>
           </div>
        </section>
      )}
    </div>
  );
};

