import React, { useEffect, useState } from 'react';
import { Sun, Utensils, Footprints, Check, Coffee, Moon, Apple, Share2 } from 'lucide-react';
import { generateDailyContent } from '../services/geminiService';
import { DailyContent, Recipe } from '../types';

const Guidance: React.FC = () => {
  const [content, setContent] = useState<DailyContent | null>(null);
  const [loading, setLoading] = useState(true);
  const [showShareToast, setShowShareToast] = useState<number | null>(null);

  useEffect(() => {
    // In a real app, cache this by date so we don't regenerate on every refresh
    const load = async () => {
        setLoading(true);
        const data = await generateDailyContent();
        setContent(data);
        setLoading(false);
    };
    load();
  }, []);

  const getMealIcon = (type: string) => {
    const t = type.toLowerCase();
    if (t.includes('café') || t.includes('manhã')) return <Coffee size={20} className="text-white" />;
    if (t.includes('lanche')) return <Apple size={20} className="text-white" />;
    if (t.includes('jantar') || t.includes('noite')) return <Moon size={20} className="text-white" />;
    return <Utensils size={20} className="text-white" />;
  };

  const getMealColor = (type: string) => {
    const t = type.toLowerCase();
    if (t.includes('café')) return 'bg-orange-400';
    if (t.includes('lanche')) return 'bg-purple-400';
    if (t.includes('jantar')) return 'bg-indigo-400';
    return 'bg-nature-600'; // Lunch/Default
  };

  const handleShare = async (recipe: Recipe, index: number) => {
    const shareUrl = `https://reviva.app/receita/${index}-${recipe.title.toLowerCase().replace(/\s+/g, '-')}`;
    const shareData = {
      title: `Receita ReViva: ${recipe.title}`,
      text: `Confira esta receita saudável (${recipe.type}): ${recipe.title}. Estritamente sem glúten, sem leite e sem açúcar! 🌱`,
      url: shareUrl,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        if ((err as Error).name !== 'AbortError') {
          console.error('Erro ao compartilhar:', err);
        }
      }
    } else {
      // Fallback para navegadores que não suportam a Web Share API
      const copyPrompt = window.prompt(
        "Compartilhe esta receita copiando o link abaixo:",
        shareUrl
      );

      if (copyPrompt !== null) {
        try {
          await navigator.clipboard.writeText(shareUrl);
          setShowShareToast(index);
          setTimeout(() => setShowShareToast(null), 3000);
        } catch (e) {
