              <button onClick={async () => {
                setLoading(true); setGeneratedContent(null); stopContentAudio();
                const textResult = await generateLouiseHayAffirmation(personalMessage);
                setGeneratedContent(textResult);
                const audioBase64 = await generateSpeech(textResult);
                if (audioBase64) {
                  const bytes = decodeBase64(audioBase64);
                  const buffer = await decodeAudioData(bytes, audioContextRef.current!);
                  setContentAudio(buffer);
                  playBuffer(buffer, true); // Automatic playback after generation
                }
                setLoading(false);
              }} disabled={loading || !personalMessage} className="w-full bg-pink-400 text-white py-3 rounded-lg font-bold hover:bg-pink-500 transition-colors disabled:opacity-50">
                {loading ? 'Consultando sabedoria...' : 'Gerar Afirmação'}
