import { Heart, MessageCircle, Share2, Image as ImageIcon, Video as VideoIcon, X, Check, Users, Send } from 'lucide-react';
import { CommunityPost, Comment } from '../types';

const MOCK_POSTS: CommunityPost[] = [
  {
    id: '0',
    author: 'Guia Essência',
    avatar: 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=100&auto=format&fit=crop',
    content: 'Olá Tribo! Segue uma orientação rápida sobre como lidar com a vontade de comer doces nos primeiros dias. Mantenham o foco! 🌱',
    likes: 156,
    comments: 1,
    commentList: [
      {
        id: 'c1',
        author: 'Ana Clara',
        avatar: 'https://picsum.photos/50/50?random=10',
        text: 'Dica maravilhosa! Estava mesmo precisando desse incentivo hoje.',
        timestamp: Date.now() - 600000
      }
    ],
    timestamp: Date.now() - 1800000,
    video: 'https://www.w3schools.com/html/mov_bbb.mp4'
  },
  {
    id: '1',
    author: 'Maria S.',
    avatar: 'https://picsum.photos/50/50?random=1',
    content: 'Hoje completei 10 dias sem glúten! O inchaço sumiu completamente. Tão feliz! 🌿 #JornadaSemGluten',
    likes: 24,
    comments: 0,
    commentList: [],
    timestamp: Date.now() - 3600000,
    image: 'https://picsum.photos/400/200?random=10'
  },
  {
    id: '2',
    author: 'João P.',
    avatar: 'https://picsum.photos/50/50?random=2',
    content: 'A meditação guiada de hoje para o estômago foi incrível. Senti uma paz que não sentia há tempos.',
    likes: 12,
    comments: 0,
    commentList: [],
    timestamp: Date.now() - 7200000
  },
];

const Community: React.FC = () => {
  const [posts, setPosts] = useState<CommunityPost[]>(MOCK_POSTS);
  const [likedPosts, setLikedPosts] = useState<Set<string>>(new Set());
  const [expandedComments, setExpandedComments] = useState<Set<string>>(new Set());
  const [commentInputs, setCommentInputs] = useState<{ [key: string]: string }>({});
  const [newPost, setNewPost] = useState('');
  const [selectedVideo, setSelectedVideo] = useState<File | null>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const [showShareToast, setShowShareToast] = useState<string | null>(null);

  const activeMembersCount = 1248;

  const handleLike = (postId: string) => {
    const isAlreadyLiked = likedPosts.has(postId);
    setPosts(prevPosts =>
      prevPosts.map(post => post.id === postId ? {
        ...post,
        likes: isAlreadyLiked ? post.likes - 1 : post.likes + 1
      } : post)
    );
    setLikedPosts(prev => {
      const next = new Set(prev);
      if (isAlreadyLiked) {
        next.delete(postId);
      } else {
        next.add(postId);
      }
      return next;
    });
  };

  const toggleComments = (postId: string) => {
    setExpandedComments(prev => {
      const next = new Set(prev);
      if (next.has(postId)) {
        next.delete(postId);
      } else {
        next.add(postId);
      }
      return next;
    });
  };

  const handleCommentSubmit = (postId: string) => {
    const text = commentInputs[postId];
    if (!text?.trim()) return;

    const newComment: Comment = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      text: text,
      timestamp: Date.now()
    };

    setPosts(prevPosts =>
      prevPosts.map(post => post.id === postId ? {
        ...post,
        comments: post.comments + 1,
        commentList: [...(post.commentList || []), newComment]
      } : post)
    );

    setCommentInputs(prev => ({ ...prev, [postId]: '' }));
  };

  const handlePost = () => {
    if (!newPost.trim() && !selectedVideo) return;

    let videoUrl: string | undefined = undefined;
    if (selectedVideo) {
      videoUrl = URL.createObjectURL(selectedVideo);
    }

    const post: CommunityPost = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      content: newPost,
      likes: 0,
      comments: 0,
      commentList: [],
      timestamp: Date.now(),
      video: videoUrl
    };
    setPosts([post, ...posts]);
    setNewPost('');
    setSelectedVideo(null);
  };

  const handleVideoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.type.startsWith('video/')) {
        setSelectedVideo(file);
      } else {
        alert('Por favor, selecione um arquivo de vídeo válido.');
      }
    }
  };

  const handleShare = async (post: CommunityPost) => {
    const shareUrl = `https://reviva.app/tribo/${post.id}`;
    const shareData = {
      title: 'ReViva - Tribo Essência',
      text: `Veja o que ${post.author} compartilhou na Tribo Essência: "${post.content.substring(0, 60)}..."`,
      url: shareUrl,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        if ((err as Error).name !== 'AbortError') console.error('Erro ao compartilhar:', err);
      }
    } else {
      try {
        await navigator.clipboard.writeText(shareUrl);
        setShowShareToast(post.id);
        setTimeout(() => setShowShareToast(null), 3000);
      } catch (e) {
        window.prompt("Copie o link da postagem:", shareUrl);
      }
    }
  };

  return (
    <div className="p-4 pb-24 max-w-2xl mx-auto">
      <header className="mb-6">
        <div className="flex flex-col gap-1">
          <div className="flex items-center justify-between">
            <h2 className="text-2xl font-serif text-nature-800">Tribo Essência</h2>
            <div className="flex items-center gap-2 bg-nature-50 px-3 py-1 rounded-full border border-nature-100">
              <Users size={14} className="text-nature-600" />
              <span className="text-[10px] font-bold text-nature-700 uppercase tracking-tight">
                {activeMembersCount} ativos
              </span>
            </div>
          </div>
          <p className="text-nature-600 text-sm flex items-center gap-2">
            Apoio mútuo e orientações • <span className="font-semibold">{posts.length} postagens recentes</span>
          </p>
        </div>
      </header>

      {/* Input Area */}
      <div className="bg-white p-4 rounded-2xl shadow-sm mb-6 border border-gray-100">
        <textarea
          value={newPost}
          onChange={(e) => setNewPost(e.target.value)}
          placeholder="Compartilhe sua vitória, dúvida ou vídeo..."
          className="w-full bg-gray-50 rounded-lg p-3 text-sm focus:ring-2 focus:ring-nature-200 outline-none resize-none mb-3"
          rows={3}
        />

        {selectedVideo && (
          <div className="mb-3 bg-nature-50 p-2 rounded-lg flex items-center justify-between text-sm text-nature-700">
            <span className="truncate max-w-[200px] flex items-center gap-2">
              <VideoIcon size={16} /> {selectedVideo.name}
            </span>
            <button onClick={() => setSelectedVideo(null)} className="text-gray-400 hover:text-red-500">
              <X size={16} />
            </button>
          </div>
        )}

        <div className="flex justify-between items-center">
            <div className="flex gap-2">
              <button className="text-gray-400 hover:text-nature-600 p-2 rounded-full hover:bg-gray-100 transition-colors">
                  <ImageIcon size={20} />
              </button>
              <button 
                onClick={() => videoInputRef.current?.click()}
                className={`p-2 rounded-full hover:bg-gray-100 transition-colors ${selectedVideo ? 'text-nature-600' : 'text-gray-400 hover:text-nature-600'}`}
              >
                  <VideoIcon size={20} />
              </button>
              <input type="file" ref={videoInputRef} onChange={handleVideoSelect} accept="video/*" className="hidden" />
            </div>
            <button 
                onClick={handlePost}
                disabled={!newPost.trim() && !selectedVideo}
                className="bg-nature-600 text-white px-6 py-2 rounded-full text-sm font-bold disabled:opacity-50 hover:bg-nature-700 transition-colors shadow-md shadow-nature-100"
            >
                Publicar
            </button>
        </div>
      </div>

      {/* Feed */}
      <div className="space-y-4">
        {posts.map(post => {
          const isLiked = likedPosts.has(post.id);
          const isCommentsExpanded = expandedComments.has(post.id);
          return (
            <div key={post.id} className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 transition-all hover:shadow-md animate-in fade-in slide-in-from-bottom-3 duration-500">
              <div className="flex items-center mb-3">
                <img src={post.avatar} alt={post.author} className="w-10 h-10 rounded-full mr-3 object-cover border border-nature-100" />
                <div>
                  <h4 className="font-bold text-gray-800 text-sm flex items-center gap-1">
                    {post.author}
                    {post.author.includes('Guia') && <span className="bg-nature-100 text-nature-700 text-[10px] px-1.5 py-0.5 rounded-full border border-nature-200">Admin</span>}
                  </h4>
                  <span className="text-xs text-gray-400">há algumas horas</span>
                </div>
              </div>
              <p className="text-gray-700 text-sm mb-3 whitespace-pre-line leading-relaxed">{post.content}</p>

              {post.image && (
                  <img src={post.image} alt="Post attachment" className="w-full h-48 object-cover rounded-xl mb-3 border border-gray-50" />
              )}

              {post.video && (
                <div className="mb-3 rounded-xl overflow-hidden bg-black shadow-inner">
                  <video src={post.video} controls className="w-full max-h-64 mx-auto" playsInline>
                    Seu navegador não suporta vídeos.
                  </video>
                </div>
              )}

              <div className="flex items-center gap-6 pt-3 border-t border-gray-50 relative">
                  <button 
                    onClick={() => handleLike(post.id)}
                    className={`flex items-center gap-1.5 text-sm transition-all group px-2 py-1 rounded-lg ${isLiked ? 'text-rose-600 bg-rose-50' : 'text-gray-400 hover:text-rose-500 hover:bg-gray-50'}`}
                  >
                      <Heart 
                        size={18} 
                        fill={isLiked ? 'currentColor' : 'none'} 
                        className={`transition-transform duration-200 ${isLiked ? 'scale-110' : 'group-hover:scale-110'} active:scale-125`} 
                      /> 
                      <span className={isLiked ? 'font-bold' : ''}>{post.likes}</span>
                      <span className="ml-1 text-[10px] uppercase font-bold tracking-tight">Curtir</span>
                  </button>
                  <button 
                    onClick={() => toggleComments(post.id)}
                    className={`flex items-center gap-1.5 text-sm transition-colors px-2 py-1 rounded-lg ${isCommentsExpanded ? 'text-blue-600 bg-blue-50' : 'text-gray-400 hover:text-blue-500 hover:bg-gray-50'}`}
                  >
                      <MessageCircle size={18} /> 
                      <span className={isCommentsExpanded ? 'font-bold' : ''}>{post.comments}</span>
                      <span className="ml-1 text-[10px] uppercase font-bold tracking-tight">Comentários</span>
                  </button>

                  <div className="ml-auto flex items-center gap-2">
                    {showShareToast === post.id && (
                      <span className="text-[10px] bg-nature-600 text-white px-2 py-1 rounded-full animate-in fade-in slide-in-from-right-2 shadow-sm font-medium">
                        Link copiado! ✨
                      </span>
                    )}
                    <button 
                      onClick={() => handleShare(post)}
                      className={`flex items-center gap-1.5 text-sm transition-all p-2 rounded-full ${showShareToast === post.id ? 'bg-nature-100 text-nature-700' : 'bg-nature-50 text-gray-400 hover:text-nature-600 hover:bg-nature-100'}`}
                    >
                        <Share2 size={18} />
                    </button>
                  </div>
              </div>

              {/* Comments Section */}
              {isCommentsExpanded && (
                <div className="mt-4 pt-4 border-t border-gray-50 space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                  <div className="space-y-4">
                    {post.commentList && post.commentList.length > 0 ? (
                      post.commentList.map(comment => (
                        <div key={comment.id} className="flex gap-3">
                          <img src={comment.avatar} alt={comment.author} className="w-8 h-8 rounded-full object-cover shrink-0 border border-gray-100" />
                          <div className="bg-gray-50 p-3 rounded-2xl flex-1">
                            <h5 className="text-[11px] font-bold text-gray-800 mb-0.5">{comment.author}</h5>
                            <p className="text-xs text-gray-600 leading-normal">{comment.text}</p>
                          </div>
                        </div>
                      ))
                    ) : (
                      <p className="text-center text-[10px] text-gray-400 py-2 italic">Seja o primeiro a comentar...</p>
                    )}
                  </div>

                  <div className="flex gap-2 pt-2 items-center">
                    <img src="https://picsum.photos/50/50?random=99" className="w-8 h-8 rounded-full border border-gray-100" alt="Sua foto" />
                    <div className="relative flex-1">
                      <input 
                        type="text" 
                        value={commentInputs[post.id] || ''}
                        onChange={(e) => setCommentInputs(prev => ({ ...prev, [post.id]: e.target.value }))}
                        onKeyPress={(e) => e.key === 'Enter' && handleCommentSubmit(post.id)}
                        placeholder="Escreva um comentário..."
                        className="w-full bg-gray-50 border-none rounded-full py-2 px-4 text-xs focus:ring-1 focus:ring-nature-200 outline-none pr-10"
                      />
                      <button 
                        onClick={() => handleCommentSubmit(post.id)}
                        disabled={!commentInputs[post.id]?.trim()}
                        className="absolute right-2 top-1/2 -translate-y-1/2 text-nature-600 disabled:text-gray-300 hover:scale-110 transition-transform"
                      >
                        <Send size={16} />
                      </button>
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

