type FilterType = 'recent' | 'liked' | 'following';

const Community: React.FC = () => {
  const [posts, setPosts] = useState<CommunityPost[]>(MOCK_POSTS);
  const [activeFilter, setActiveFilter] = useState<FilterType>('recent');
  const [likedPosts, setLikedPosts] = useState<Set<string>>(new Set());
  const [followedAuthors, setFollowedAuthors] = useState<Set<string>>(new Set());
  const [expandedComments, setExpandedComments] = useState<Set<string>>(new Set());
  const [commentInputs, setCommentInputs] = useState<{ [key: string]: string }>({});
  const [newPost, setNewPost] = useState('');

  // Media states
  const [selectedVideo, setSelectedVideo] = useState<File | null>(null);
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [mediaPreview, setMediaPreview] = useState<string | null>(null);

  const videoInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const [showShareToast, setShowShareToast] = useState<string | null>(null);

  const activeMembersCount = 1248;

  // Logic for filtering and sorting posts
  const filteredPosts = useMemo(() => {
    let result = [...posts];

    if (activeFilter === 'recent') {
      result.sort((a, b) => b.timestamp - a.timestamp);
    } else if (activeFilter === 'liked') {
      result.sort((a, b) => b.likes - a.likes);
    } else if (activeFilter === 'following') {
      result = result.filter(post => followedAuthors.has(post.author) || post.author === 'Você');
      // Sort by recent within following
      result.sort((a, b) => b.timestamp - a.timestamp);
    }

    return result;
  }, [posts, activeFilter, followedAuthors]);

  const handleLike = (postId: string) => {
    const isAlreadyLiked = likedPosts.has(postId);
    setPosts(prevPosts =>
      prevPosts.map(post => post.id === postId ? {
        ...post,
        likes: isAlreadyLiked ? post.likes - 1 : post.likes + 1
      } : post)
    );
    setLikedPosts(prev => {
      const next = new Set(prev);
      if (isAlreadyLiked) {
        next.delete(postId);
      } else {
        next.add(postId);
      }
      return next;
    });
  };

  const toggleFollow = (authorName: string) => {
    setFollowedAuthors(prev => {
      const next = new Set(prev);
      if (next.has(authorName)) {
        next.delete(authorName);
      } else {
        next.add(authorName);
      }
      return next;
    });
  };

  const toggleComments = (postId: string) => {
    setExpandedComments(prev => {
      const next = new Set(prev);
      if (next.has(postId)) {
        next.delete(postId);
      } else {
        next.add(postId);
      }
      return next;
    });
  };

  const handleCommentSubmit = (postId: string) => {
    const text = commentInputs[postId];
    if (!text?.trim()) return;

    const newComment: Comment = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      text: text,
      timestamp: Date.now()
    };

    setPosts(prevPosts =>
      prevPosts.map(post => post.id === postId ? {
        ...post,
        comments: (post.commentList?.length || 0) + 1,
        commentList: [...(post.commentList || []), newComment]
      } : post)
    );

    setCommentInputs(prev => ({ ...prev, [postId]: '' }));

    if (!expandedComments.has(postId)) {
      setExpandedComments(prev => new Set(prev).add(postId));
    }
  };

  const handlePost = () => {
    if (!newPost.trim() && !selectedVideo && !selectedImage) return;

    let videoUrl: string | undefined = undefined;
    let imageUrl: string | undefined = undefined;

    if (selectedVideo) {
      videoUrl = URL.createObjectURL(selectedVideo);
    }
    if (selectedImage) {
      imageUrl = URL.createObjectURL(selectedImage);
    }

    const post: CommunityPost = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      content: newPost,
      likes: 0,
      comments: 0,
      commentList: [],
      timestamp: Date.now(),
      video: videoUrl,
      image: imageUrl
    };

    setPosts([post, ...posts]);
    setNewPost('');
    setSelectedVideo(null);
    setSelectedImage(null);
    setMediaPreview(null);
    // Switch to recent filter to see the new post
    setActiveFilter('recent');
  };

  const handleVideoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.type.startsWith('video/')) {
        setSelectedVideo(file);
        setSelectedImage(null);
        setMediaPreview(URL.createObjectURL(file));
      } else {
        alert('Por favor, selecione um arquivo de vídeo válido.');
      }
    }
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.type.startsWith('image/')) {
        setSelectedImage(file);
        setSelectedVideo(null);
        setMediaPreview(URL.createObjectURL(file));
      } else {
        alert('Por favor, selecione um arquivo de imagem válido.');
      }
    }
  };

  const clearMedia = () => {
    setSelectedVideo(null);
    setSelectedImage(null);
    setMediaPreview(null);
    if (videoInputRef.current) videoInputRef.current.value = '';
    if (imageInputRef.current) imageInputRef.current.value = '';
  };

  const handleShare = async (post: CommunityPost) => {
    const shareUrl = `https://reviva.app/tribo/${post.id}`;
    const shareData = {
      title: 'ReViva - Tribo Essência',
      text: `Veja o que ${post.author} compartilhou na Tribo Essência: "${post.content.substring(0, 60)}..."`,
      url: shareUrl,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        if ((err as Error).name !== 'AbortError') console.error('Erro ao compartilhar:', err);
      }
    } else {
      try {
        await navigator.clipboard.writeText(shareUrl);
        setShowShareToast(post.id);
        setTimeout(() => setShowShareToast(null), 3000);
      } catch (e) {
        window.prompt("Copie o link da postagem:", shareUrl);
      }
    }
  };

  return (
    <div className="p-4 pb-24 max-w-2xl mx-auto">
      <header className="mb-6">
        <div className="flex flex-col gap-1">
          <div className="flex items-center justify-between">
            <h2 className="text-2xl font-serif text-nature-800">Tribo Essência</h2>
            <div className="flex items-center gap-2 bg-nature-50 px-3 py-1 rounded-full border border-nature-100">
              <Users size={14} className="text-nature-600" />
              <span className="text-[10px] font-bold text-nature-700 uppercase tracking-tight">
                {activeMembersCount} ativos
              </span>
            </div>
          </div>
          <p className="text-nature-600 text-sm flex items-center gap-2">
            Apoio mútuo e orientações • <span className="font-semibold">{posts.length} postagens</span>
          </p>
        </div>
      </header>

      {/* Filtros do Feed */}
      <div className="flex items-center gap-2 mb-6 overflow-x-auto pb-2 no-scrollbar">
        <button 
          onClick={() => setActiveFilter('recent')}
          className={`flex items-center gap-1.5 px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${
            activeFilter === 'recent' 
            ? 'bg-nature-600 text-white shadow-md shadow-nature-100' 
            : 'bg-nature-50 text-nature-600 border border-nature-100 hover:bg-nature-100'
          }`}
        >
          <Clock size={14} /> Recentes
        </button>
        <button 
          onClick={() => setActiveFilter('liked')}
          className={`flex items-center gap-1.5 px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${
            activeFilter === 'liked' 
            ? 'bg-nature-600 text-white shadow-md shadow-nature-100' 
            : 'bg-nature-50 text-nature-600 border border-nature-100 hover:bg-nature-100'
          }`}
        >
          <TrendingUp size={14} /> Mais Curtidas
        </button>
        <button 
          onClick={() => setActiveFilter('following')}
          className={`flex items-center gap-1.5 px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${
            activeFilter === 'following' 
            ? 'bg-nature-600 text-white shadow-md shadow-nature-100' 
            : 'bg-nature-50 text-nature-600 border border-nature-100 hover:bg-nature-100'
          }`}
        >
          <Users size={14} /> Seguindo
        </button>
      </div>

      {/* Input Area para Novo Post */}
      <div className="bg-white p-4 rounded-2xl shadow-sm mb-6 border border-gray-100 transition-all focus-within:ring-2 focus-within:ring-nature-100">
        <textarea
          value={newPost}
          onChange={(e) => setNewPost(e.target.value)}
          placeholder="Compartilhe sua vitória, dúvida, foto ou vídeo..."
          className="w-full bg-gray-50 rounded-xl p-3 text-sm outline-none resize-none mb-3 min-h-[100px] transition-colors focus:bg-white"
          rows={3}
        />

        {mediaPreview && (
          <div className="mb-4 relative group">
            <div className="rounded-xl overflow-hidden border border-nature-100 bg-nature-50 aspect-video flex items-center justify-center">
              {selectedImage ? (
                <img src={mediaPreview} alt="Preview" className="w-full h-full object-cover" />
              ) : (
                <video src={mediaPreview} className="w-full max-h-48" />
              )}
            </div>
            <button 
              onClick={clearMedia} 
              className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full shadow-lg hover:bg-red-600 transition-colors"
              title="Remover mídia"
            >
              <X size={16} />
            </button>
          </div>
        )}

        <div className="flex justify-between items-center border-t border-gray-50 pt-3">
            <div className="flex gap-1">
              <button 
                onClick={() => imageInputRef.current?.click()}
                className={`p-2.5 rounded-full transition-all ${selectedImage ? 'bg-nature-100 text-nature-700' : 'text-gray-400 hover:bg-nature-50 hover:text-nature-600'}`}
                title="Adicionar foto"
              >
                  <ImageIcon size={20} />
              </button>
              <button 
                onClick={() => videoInputRef.current?.click()}
                className={`p-2.5 rounded-full transition-all ${selectedVideo ? 'bg-nature-100 text-nature-700' : 'text-gray-400 hover:bg-nature-50 hover:text-nature-600'}`}
                title="Adicionar vídeo"
              >
                  <VideoIcon size={20} />
              </button>

              <input type="file" ref={imageInputRef} onChange={handleImageSelect} accept="image/*" className="hidden" />
              <input type="file" ref={videoInputRef} onChange={handleVideoSelect} accept="video/*" className="hidden" />
            </div>

            <button 
                onClick={handlePost}
                disabled={!newPost.trim() && !selectedVideo && !selectedImage}
                className="bg-nature-600 text-white px-8 py-2.5 rounded-full text-sm font-bold disabled:opacity-30 hover:bg-nature-700 transition-all shadow-lg shadow-nature-100 active:scale-95 flex items-center gap-2"
            >
                Publicar
                <Send size={16} />
            </button>
        </div>
      </div>

      {/* Feed de Postagens */}
      <div className="space-y-6">
        {filteredPosts.length > 0 ? (
          filteredPosts.map(post => {
            const isLiked = likedPosts.has(post.id);
            const isFollowing = followedAuthors.has(post.author);
            const isCommentsExpanded = expandedComments.has(post.id);

            return (
              <div key={post.id} className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100 transition-all hover:shadow-md animate-in fade-in slide-in-from-bottom-3 duration-500">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center">
                    <img src={post.avatar} alt={post.author} className="w-10 h-10 rounded-full mr-3 object-cover border-2 border-nature-50 shadow-sm" />
                    <div>
                      <h4 className="font-bold text-gray-800 text-sm flex items-center gap-2">
                        {post.author}
                        {post.author.includes('Guia') && (
                          <span className="bg-nature-500 text-white text-[9px] px-2 py-0.5 rounded-full font-bold uppercase tracking-wider">Staff</span>
                        )}
                      </h4>
                      <div className="flex items-center gap-1.5 text-[10px] text-gray-400">
                        <Clock size={10} />
                        <span>há algumas horas</span>
                      </div>
                    </div>
                  </div>

                  {post.author !== 'Você' && (
                    <button 
                      onClick={() => toggleFollow(post.author)}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-bold transition-all duration-300 ${
                        isFollowing 
                        ? 'bg-nature-700 text-white shadow-inner' 
                        : 'bg-white border border-nature-200 text-nature-600 hover:bg-nature-50'
                      }`}
                    >
                      {isFollowing ? (
                        <><UserCheck size={14} /> Seguindo</>
                      ) : (
                        <><UserPlus size={14} /> Seguir</>
                      )}
                    </button>
                  )}
                </div>

                <p className="text-gray-700 text-[13px] mb-4 whitespace-pre-line leading-relaxed">{post.content}</p>

                {post.image && (
                  <div className="mb-4 rounded-2xl overflow-hidden border border-gray-50 shadow-inner">
                    <img src={post.image} alt="Post attachment" className="w-full h-auto max-h-[400px] object-cover" />
                  </div>
                )}

                {post.video && (
                  <div className="mb-4 rounded-2xl overflow-hidden bg-black shadow-inner aspect-video flex items-center">
                    <video src={post.video} controls className="w-full" playsInline>
                      Seu navegador não suporta vídeos.
                    </video>
                  </div>
                )}

                <div className="flex items-center gap-4 pt-4 border-t border-gray-50 relative">
                    <button 
                      onClick={() => handleLike(post.id)}
                      className={`flex items-center gap-2 text-sm transition-all group px-3 py-2 rounded-xl ${isLiked ? 'text-rose-600 bg-rose-50' : 'text-gray-400 hover:text-rose-500 hover:bg-gray-50'}`}
                    >
                        <Heart 
                          size={18} 
                          fill={isLiked ? 'currentColor' : 'none'} 
                          className={`transition-transform duration-300 ${isLiked ? 'scale-110' : 'group-hover:scale-110'} active:scale-150`} 
                        /> 
                        <span className={`font-bold transition-all ${isLiked ? 'scale-110' : ''}`}>{post.likes}</span>
                    </button>

                    <button 
                      onClick={() => toggleComments(post.id)}
                      className={`flex items-center gap-2 text-sm transition-colors px-3 py-2 rounded-xl ${isCommentsExpanded ? 'text-nature-700 bg-nature-50' : 'text-gray-400 hover:text-nature-600 hover:bg-gray-50'}`}
                    >
                        <MessageCircle size={18} /> 
                        <span className={isCommentsExpanded ? 'font-bold' : ''}>{post.commentList?.length || 0}</span>
                    </button>

                    <div className="ml-auto flex items-center gap-2">
                      {showShareToast === post.id && (
                        <span className="text-[10px] bg-nature-700 text-white px-3 py-1.5 rounded-full animate-in fade-in slide-in-from-right-4 shadow-lg shadow-nature-100 font-bold">
                          Copiado!
                        </span>
                      )}
                      <button 
                        onClick={() => handleShare(post)}
                        className="p-2.5 rounded-full bg-nature-50 text-gray-400 hover:text-nature-600 hover:bg-nature-100 transition-all active:rotate-12"
                      >
                          <Share2 size={18} />
                      </button>
                    </div>
                </div>

                <div className={`mt-4 pt-4 border-t border-gray-50 space-y-4 transition-all duration-500 overflow-hidden ${isCommentsExpanded ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0 pointer-events-none'}`}>
                    <div className="space-y-4 max-h-72 overflow-y-auto pr-2 custom-scrollbar">
                      {post.commentList && post.commentList.length > 0 ? (
                        post.commentList.map(comment => (
                          <div key={comment.id} className="flex gap-3 animate-in fade-in slide-in-from-left-4">
                            <img src={comment.avatar} alt={comment.author} className="w-8 h-8 rounded-full object-cover shrink-0 border border-gray-100 shadow-sm" />
                            <div className="bg-gray-50 p-3 rounded-2xl flex-1 border border-gray-100 relative">
                              <div className="flex justify-between items-center mb-1">
                                <h5 className="text-[11px] font-bold text-nature-800">{comment.author}</h5>
                                <span className="text-[9px] text-gray-400 flex items-center gap-1">
                                  <Clock size={10} /> agora
                                </span>
                              </div>
                              <p className="text-[12px] text-gray-600 leading-normal">{comment.text}</p>
                            </div>
                          </div>
                        ))
                      ) : (
                        <div className="flex flex-col items-center py-8 text-gray-300">
                          <div className="w-12 h-12 rounded-full bg-gray-50 flex items-center justify-center mb-3">
                            <MessageCircle size={24} strokeWidth={1} />
                          </div>
                          <p className="text-[11px] font-medium">Seja o primeiro a comentar!</p>
                        </div>
                      )}
                    </div>

                    <div className="flex gap-3 pt-4 items-center border-t border-gray-50">
                      <img src="https://picsum.photos/50/50?random=99" className="w-9 h-9 rounded-full border-2 border-nature-50 shadow-sm" alt="Sua foto" />
                      <div className="relative flex-1">
                        <input 
                          type="text" 
                          value={commentInputs[post.id] || ''}
                          onChange={(e) => setCommentInputs(prev => ({ ...prev, [post.id]: e.target.value }))}
                          onKeyPress={(e) => e.key === 'Enter' && handleCommentSubmit(post.id)}
                          placeholder="Adicione um comentário..."
                          className="w-full bg-nature-50 border-none rounded-2xl py-2.5 px-5 text-[13px] focus:ring-2 focus:ring-nature-200 outline-none pr-12 placeholder:text-gray-400 transition-all focus:bg-white"
                        />
                        <button 
                          onClick={() => handleCommentSubmit(post.id)}
                          disabled={!commentInputs[post.id]?.trim()}
                          className="absolute right-2 top-1/2 -translate-y-1/2 text-nature-600 disabled:text-gray-200 hover:scale-110 transition-transform p-1.5 rounded-full hover:bg-nature-50"
                        >
                          <Send size={18} />
                        </button>
                      </div>
                    </div>
                </div>
              </div>
            );
          })
        ) : (
          <div className="flex flex-col items-center justify-center py-20 text-center animate-in fade-in zoom-in duration-700">
            <div className="w-20 h-20 bg-nature-50 rounded-full flex items-center justify-center mb-6 text-nature-200">
              <Sparkles size={40} />
            </div>
            <h3 className="text-xl font-serif text-nature-800 mb-2">Nada por aqui ainda</h3>
            <p className="text-nature-600 text-sm max-w-[250px]">
              {activeFilter === 'following' 
                ? "Você ainda não segue ninguém ou ninguém que você segue postou hoje. Que tal seguir novos membros?" 
                : "Ainda não há postagens neste filtro."}
            </p>
            {activeFilter === 'following' && (
              <button 
                onClick={() => setActiveFilter('recent')}
                className="mt-6 text-nature-600 font-bold text-sm underline underline-offset-4"
              >
                Ver postagens recentes
              </button>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Community;

import React, { useState, useRef, useMemo } from 'react';
import { Heart, MessageCircle, Share2, Image as ImageIcon, Video as VideoIcon, X, Check, Users, Send, Clock, UserPlus, UserCheck, TrendingUp, Sparkles, PlayCircle } from 'lucide-react';
import { CommunityPost, Comment } from '../types';

const MOCK_POSTS: CommunityPost[] = [
  {
    id: '0',
    author: 'Guia Essência',
    avatar: 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=100&auto=format&fit=crop',
    content: 'Olá Tribo! Segue uma orientação rápida sobre como lidar com a vontade de comer doces nos primeiros dias. Mantenham o foco! 🌱',
    likes: 156,
    comments: 2,
    commentList: [
      {
        id: 'c1',
        author: 'Ana Clara',
        avatar: 'https://picsum.photos/50/50?random=10',
        text: 'Dica maravilhosa! Estava mesmo precisando desse incentivo hoje.',
        timestamp: Date.now() - 600000
      },
      {
        id: 'c2',
        author: 'Ricardo M.',
        avatar: 'https://picsum.photos/50/50?random=15',
        text: 'Beber um copo de água com limão tem me ajudado muito nesses momentos.',
        timestamp: Date.now() - 300000
      }
    ],
    timestamp: Date.now() - 1800000,
    video: 'https://www.w3schools.com/html/mov_bbb.mp4'
  },
  {
    id: '1',
    author: 'Maria S.',
    avatar: 'https://picsum.photos/50/50?random=1',
    content: 'Hoje completei 10 dias sem glúten! O inchaço sumiu completamente. Tão feliz! 🌿 #JornadaSemGluten',
    likes: 24,
    comments: 0,
    commentList: [],
    timestamp: Date.now() - 3600000,
    image: 'https://images.unsplash.com/photo-1547592166-23ac45744acd?q=80&w=800&auto=format&fit=crop'
  },
  {
    id: '2',
    author: 'João P.',
    avatar: 'https://picsum.photos/50/50?random=2',
    content: 'A meditação guiada de hoje para o estômago foi incrível. Senti uma paz que não sentia há tempos.',
    likes: 12,
    comments: 0,
    commentList: [],
    timestamp: Date.now() - 7200000
  },
];

type FilterType = 'recent' | 'liked' | 'following';

const Community: React.FC = () => {
  const [posts, setPosts] = useState<CommunityPost[]>(MOCK_POSTS);
  const [activeFilter, setActiveFilter] = useState<FilterType>('recent');
  const [likedPosts, setLikedPosts] = useState<Set<string>>(new Set());
  const [followedAuthors, setFollowedAuthors] = useState<Set<string>>(new Set());
  const [expandedComments, setExpandedComments] = useState<Set<string>>(new Set());
  const [commentInputs, setCommentInputs] = useState<{ [key: string]: string }>({});
  const [newPost, setNewPost] = useState('');

  // Media states
  const [selectedVideo, setSelectedVideo] = useState<File | null>(null);
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [mediaPreview, setMediaPreview] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);

  const videoInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const [showShareToast, setShowShareToast] = useState<string | null>(null);

  const activeMembersCount = 1248;

  // Logic for filtering and sorting posts
  const filteredPosts = useMemo(() => {
    let result = [...posts];

    if (activeFilter === 'recent') {
      result.sort((a, b) => b.timestamp - a.timestamp);
    } else if (activeFilter === 'liked') {
      result.sort((a, b) => b.likes - a.likes);
    } else if (activeFilter === 'following') {
      result = result.filter(post => followedAuthors.has(post.author) || post.author === 'Você');
      result.sort((a, b) => b.timestamp - a.timestamp);
    }

    return result;
  }, [posts, activeFilter, followedAuthors]);

  const handleLike = (postId: string) => {
    const isAlreadyLiked = likedPosts.has(postId);
    setPosts(prevPosts =>
      prevPosts.map(post => post.id === postId ? {
        ...post,
        likes: isAlreadyLiked ? post.likes - 1 : post.likes + 1
      } : post)
    );
    setLikedPosts(prev => {
      const next = new Set(prev);
      if (isAlreadyLiked) {
        next.delete(postId);
      } else {
        next.add(postId);
      }
      return next;
    });
  };

  const toggleFollow = (authorName: string) => {
    setFollowedAuthors(prev => {
      const next = new Set(prev);
      if (next.has(authorName)) {
        next.delete(authorName);
      } else {
        next.add(authorName);
      }
      return next;
    });
  };

  const toggleComments = (postId: string) => {
    setExpandedComments(prev => {
      const next = new Set(prev);
      if (next.has(postId)) {
        next.delete(postId);
      } else {
        next.add(postId);
      }
      return next;
    });
  };

  const handleCommentSubmit = (postId: string) => {
    const text = commentInputs[postId];
    if (!text?.trim()) return;

    const newComment: Comment = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      text: text,
      timestamp: Date.now()
    };

    setPosts(prevPosts =>
      prevPosts.map(post => post.id === postId ? {
        ...post,
        comments: (post.commentList?.length || 0) + 1,
        commentList: [...(post.commentList || []), newComment]
      } : post)
    );

    setCommentInputs(prev => ({ ...prev, [postId]: '' }));

    if (!expandedComments.has(postId)) {
      setExpandedComments(prev => new Set(prev).add(postId));
    }
  };

  const handlePost = async () => {
    if (!newPost.trim() && !selectedVideo && !selectedImage) return;

    setIsUploading(true);

    // Simulate upload delay
    await new Promise(r => setTimeout(r, 800));

    let videoUrl: string | undefined = undefined;
    let imageUrl: string | undefined = undefined;

    if (selectedVideo) {
      videoUrl = URL.createObjectURL(selectedVideo);
    }
    if (selectedImage) {
      imageUrl = URL.createObjectURL(selectedImage);
    }

    const post: CommunityPost = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      content: newPost,
      likes: 0,
      comments: 0,
      commentList: [],
      timestamp: Date.now(),
      video: videoUrl,
      image: imageUrl
    };

    setPosts([post, ...posts]);
    setNewPost('');
    setSelectedVideo(null);
    setSelectedImage(null);
    setMediaPreview(null);
    setIsUploading(false);
    setActiveFilter('recent');
  };

  const handleVideoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];

      // Validação de vídeo curto (simulada por tamanho de arquivo < 30MB)
      if (file.size > 30 * 1024 * 1024) {
        alert('Para manter o feed leve, envie vídeos de até 30MB (aprox. 1 minuto).');
        return;
      }

      if (file.type.startsWith('video/')) {
        setSelectedVideo(file);
        setSelectedImage(null);
        setMediaPreview(URL.createObjectURL(file));
      } else {
        alert('Por favor, selecione um arquivo de vídeo válido.');
      }
    }
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.type.startsWith('image/')) {
        setSelectedImage(file);
        setSelectedVideo(null);
        setMediaPreview(URL.createObjectURL(file));
      } else {
        alert('Por favor, selecione um arquivo de imagem válido.');
      }
    }
  };

  const clearMedia = () => {
    setSelectedVideo(null);
    setSelectedImage(null);
    setMediaPreview(null);
    if (videoInputRef.current) videoInputRef.current.value = '';
    if (imageInputRef.current) imageInputRef.current.value = '';
  };

  const handleShare = async (post: CommunityPost) => {
    const shareUrl = `https://reviva.app/tribo/${post.id}`;
    const shareData = {
      title: 'ReViva - Tribo Essência',
      text: `Veja o que ${post.author} compartilhou na Tribo Essência: "${post.content.substring(0, 60)}..."`,
      url: shareUrl,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        if ((err as Error).name !== 'AbortError') console.error('Erro ao compartilhar:', err);
      }
    } else {
      try {
        await navigator.clipboard.writeText(shareUrl);
        setShowShareToast(post.id);
        setTimeout(() => setShowShareToast(null), 3000);
      } catch (e) {
        window.prompt("Copie o link da postagem:", shareUrl);
      }
    }
  };

  return (
    <div className="p-4 pb-24 max-w-2xl mx-auto">
      <header className="mb-6">
        <div className="flex flex-col gap-1">
          <div className="flex items-center justify-between">
            <h2 className="text-2xl font-serif text-nature-800">Tribo Essência</h2>
            <div className="flex items-center gap-2 bg-nature-50 px-3 py-1 rounded-full border border-nature-100">
              <Users size={14} className="text-nature-600" />
              <span className="text-[10px] font-bold text-nature-700 uppercase tracking-tight">
                {activeMembersCount} ativos
              </span>
            </div>
          </div>
          <p className="text-nature-600 text-sm flex items-center gap-2">
            Apoio mútuo e orientações • <span className="font-semibold">{posts.length} postagens</span>
          </p>
        </div>
      </header>

      {/* Filtros do Feed */}
      <div className="flex items-center gap-2 mb-6 overflow-x-auto pb-2 no-scrollbar">
        <button 
          onClick={() => setActiveFilter('recent')}
          className={`flex items-center gap-1.5 px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${
            activeFilter === 'recent' 
            ? 'bg-nature-600 text-white shadow-md shadow-nature-100' 
            : 'bg-nature-50 text-nature-600 border border-nature-100 hover:bg-nature-100'
          }`}
        >
          <Clock size={14} /> Recentes
        </button>
        <button 
          onClick={() => setActiveFilter('liked')}
          className={`flex items-center gap-1.5 px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${
            activeFilter === 'liked' 
            ? 'bg-nature-600 text-white shadow-md shadow-nature-100' 
            : 'bg-nature-50 text-nature-600 border border-nature-100 hover:bg-nature-100'
          }`}
        >
          <TrendingUp size={14} /> Mais Curtidas
        </button>
        <button 
          onClick={() => setActiveFilter('following')}
          className={`flex items-center gap-1.5 px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${
            activeFilter === 'following' 
            ? 'bg-nature-600 text-white shadow-md shadow-nature-100' 
            : 'bg-nature-50 text-nature-600 border border-nature-100 hover:bg-nature-100'
          }`}
        >
          <Users size={14} /> Seguindo
        </button>
      </div>

      {/* Input Area para Novo Post */}
      <div className="bg-white p-4 rounded-2xl shadow-sm mb-6 border border-gray-100 transition-all focus-within:ring-2 focus-within:ring-nature-100">
        <textarea
          value={newPost}
          onChange={(e) => setNewPost(e.target.value)}
          placeholder="Compartilhe sua vitória, dúvida, foto ou vídeo..."
          className="w-full bg-gray-50 rounded-xl p-3 text-sm outline-none resize-none mb-3 min-h-[100px] transition-colors focus:bg-white"
          rows={3}
        />

        {mediaPreview && (
          <div className="mb-4 relative group">
            <div className="rounded-xl overflow-hidden border border-nature-100 bg-nature-50 aspect-video flex items-center justify-center">
              {selectedImage ? (
                <img src={mediaPreview} alt="Preview" className="w-full h-full object-cover" />
              ) : (
                <div className="relative w-full h-full flex items-center justify-center bg-black">
                  <video src={mediaPreview} className="w-full max-h-48" />
                  <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                    <PlayCircle className="text-white/50" size={48} />
                  </div>
                </div>
              )}
            </div>
            <button 
              onClick={clearMedia} 
              className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full shadow-lg hover:bg-red-600 transition-colors z-10"
              title="Remover mídia"
            >
              <X size={16} />
            </button>
          </div>
        )}

        <div className="flex justify-between items-center border-t border-gray-50 pt-3">
            <div className="flex gap-1">
              <button 
                onClick={() => imageInputRef.current?.click()}
                className={`p-2.5 rounded-full transition-all ${selectedImage ? 'bg-nature-100 text-nature-700' : 'text-gray-400 hover:bg-nature-50 hover:text-nature-600'}`}
                title="Adicionar foto"
              >
                  <ImageIcon size={20} />
              </button>
              <button 
                onClick={() => videoInputRef.current?.click()}
                className={`p-2.5 rounded-full transition-all ${selectedVideo ? 'bg-nature-100 text-nature-700' : 'text-gray-400 hover:bg-nature-50 hover:text-nature-600'}`}
                title="Adicionar vídeo curto"
              >
                  <VideoIcon size={20} />
              </button>

              <input type="file" ref={imageInputRef} onChange={handleImageSelect} accept="image/*" className="hidden" />
              <input type="file" ref={videoInputRef} onChange={handleVideoSelect} accept="video/*" className="hidden" />
            </div>

            <button 
                onClick={handlePost}
                disabled={isUploading || (!newPost.trim() && !selectedVideo && !selectedImage)}
                className="bg-nature-600 text-white px-8 py-2.5 rounded-full text-sm font-bold disabled:opacity-30 hover:bg-nature-700 transition-all shadow-lg shadow-nature-100 active:scale-95 flex items-center gap-2"
            >
                {isUploading ? 'Enviando...' : 'Publicar'}
                <Send size={16} className={isUploading ? 'animate-pulse' : ''} />
            </button>
        </div>
      </div>

      {/* Feed de Postagens */}
      <div className="space-y-6">
        {filteredPosts.length > 0 ? (
          filteredPosts.map(post => {
            const isLiked = likedPosts.has(post.id);
            const isFollowing = followedAuthors.has(post.author);
            const isCommentsExpanded = expandedComments.has(post.id);

            return (
              <div key={post.id} className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100 transition-all hover:shadow-md animate-in fade-in slide-in-from-bottom-3 duration-500">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center">
                    <img src={post.avatar} alt={post.author} className="w-10 h-10 rounded-full mr-3 object-cover border-2 border-nature-50 shadow-sm" />
                    <div>
                      <h4 className="font-bold text-gray-800 text-sm flex items-center gap-2">
                        {post.author}
                        {post.author.includes('Guia') && (
                          <span className="bg-nature-500 text-white text-[9px] px-2 py-0.5 rounded-full font-bold uppercase tracking-wider">Staff</span>
                        )}
                      </h4>
                      <div className="flex items-center gap-1.5 text-[10px] text-gray-400">
                        <Clock size={10} />
                        <span>há algumas horas</span>
                      </div>
                    </div>
                  </div>

                  {post.author !== 'Você' && (
                    <button 
                      onClick={() => toggleFollow(post.author)}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-bold transition-all duration-300 ${
                        isFollowing 
                        ? 'bg-nature-700 text-white shadow-inner' 
                        : 'bg-white border border-nature-200 text-nature-600 hover:bg-nature-50'
                      }`}
                    >
                      {isFollowing ? (
                        <><UserCheck size={14} /> Seguindo</>
                      ) : (
                        <><UserPlus size={14} /> Seguir</>
                      )}
                    </button>
                  )}
                </div>

                <p className="text-gray-700 text-[13px] mb-4 whitespace-pre-line leading-relaxed">{post.content}</p>

                {post.image && (
                  <div className="mb-4 rounded-2xl overflow-hidden border border-gray-50 shadow-inner">
                    <img src={post.image} alt="Post attachment" className="w-full h-auto max-h-[400px] object-cover" />
                  </div>
                )}

                {post.video && (
                  <div className="mb-4 rounded-2xl overflow-hidden bg-black shadow-inner aspect-video flex items-center relative group">
                    <video 
                      src={post.video} 
                      controls 
                      className="w-full" 
                      playsInline 
                      controlsList="nodownload"
                    >
                      Seu navegador não suporta vídeos.
                    </video>
                  </div>
                )}

                <div className="flex items-center gap-4 pt-4 border-t border-gray-50 relative">
                    <button 
                      onClick={() => handleLike(post.id)}
                      className={`flex items-center gap-2 text-sm transition-all group px-3 py-2 rounded-xl ${isLiked ? 'text-rose-600 bg-rose-50' : 'text-gray-400 hover:text-rose-500 hover:bg-gray-50'}`}
                    >
                        <Heart 
                          size={18} 
                          fill={isLiked ? 'currentColor' : 'none'} 
                          className={`transition-transform duration-300 ${isLiked ? 'scale-110' : 'group-hover:scale-110'} active:scale-150`} 
                        /> 
                        <span className={`font-bold transition-all ${isLiked ? 'scale-110' : ''}`}>{post.likes}</span>
                    </button>

                    <button 
                      onClick={() => toggleComments(post.id)}
                      className={`flex items-center gap-2 text-sm transition-colors px-3 py-2 rounded-xl ${isCommentsExpanded ? 'text-nature-700 bg-nature-50' : 'text-gray-400 hover:text-nature-600 hover:bg-gray-50'}`}
                    >
                        <MessageCircle size={18} /> 
                        <span className={isCommentsExpanded ? 'font-bold' : ''}>{post.commentList?.length || 0}</span>
                    </button>

                    <div className="ml-auto flex items-center gap-2">
                      {showShareToast === post.id && (
                        <span className="text-[10px] bg-nature-700 text-white px-3 py-1.5 rounded-full animate-in fade-in slide-in-from-right-4 shadow-lg shadow-nature-100 font-bold">
                          Copiado!
                        </span>
                      )}
                      <button 
                        onClick={() => handleShare(post)}
                        className="p-2.5 rounded-full bg-nature-50 text-gray-400 hover:text-nature-600 hover:bg-nature-100 transition-all active:rotate-12"
                      >
                          <Share2 size={18} />
                      </button>
                    </div>
                </div>

                <div className={`mt-4 pt-4 border-t border-gray-50 space-y-4 transition-all duration-500 overflow-hidden ${isCommentsExpanded ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0 pointer-events-none'}`}>
                    <div className="space-y-4 max-h-72 overflow-y-auto pr-2 custom-scrollbar">
                      {post.commentList && post.commentList.length > 0 ? (
                        post.commentList.map(comment => (
                          <div key={comment.id} className="flex gap-3 animate-in fade-in slide-in-from-left-4">
                            <img src={comment.avatar} alt={comment.author} className="w-8 h-8 rounded-full object-cover shrink-0 border border-gray-100 shadow-sm" />
                            <div className="bg-gray-50 p-3 rounded-2xl flex-1 border border-gray-100 relative">
                              <div className="flex justify-between items-center mb-1">
                                <h5 className="text-[11px] font-bold text-nature-800">{comment.author}</h5>
                                <span className="text-[9px] text-gray-400 flex items-center gap-1">
                                  <Clock size={10} /> agora
                                </span>
                              </div>
                              <p className="text-[12px] text-gray-600 leading-normal">{comment.text}</p>
                            </div>
                          </div>
                        ))
                      ) : (
                        <div className="flex flex-col items-center py-8 text-gray-300">
                          <div className="w-12 h-12 rounded-full bg-gray-50 flex items-center justify-center mb-3">
                            <MessageCircle size={24} strokeWidth={1} />
                          </div>
                          <p className="text-[11px] font-medium">Seja o primeiro a comentar!</p>
                        </div>
                      )}
                    </div>

                    <div className="flex gap-3 pt-4 items-center border-t border-gray-50">
                      <img src="https://picsum.photos/50/50?random=99" className="w-9 h-9 rounded-full border-2 border-nature-50 shadow-sm" alt="Sua foto" />
                      <div className="relative flex-1">
                        <input 
                          type="text" 
                          value={commentInputs[post.id] || ''}
                          onChange={(e) => setCommentInputs(prev => ({ ...prev, [post.id]: e.target.value }))}
                          onKeyPress={(e) => e.key === 'Enter' && handleCommentSubmit(post.id)}
                          placeholder="Adicione um comentário..."
                          className="w-full bg-nature-50 border-none rounded-2xl py-2.5 px-5 text-[13px] focus:ring-2 focus:ring-nature-200 outline-none pr-12 placeholder:text-gray-400 transition-all focus:bg-white"
                        />
                        <button 
                          onClick={() => handleCommentSubmit(post.id)}
                          disabled={!commentInputs[post.id]?.trim()}
                          className="absolute right-2 top-1/2 -translate-y-1/2 text-nature-600 disabled:text-gray-200 hover:scale-110 transition-transform p-1.5 rounded-full hover:bg-nature-50"
                        >
                          <Send size={18} />
                        </button>
                      </div>
                    </div>
                </div>
              </div>
            );
          })
        ) : (
          <div className="flex flex-col items-center justify-center py-20 text-center animate-in fade-in zoom-in duration-700">
            <div className="w-20 h-20 bg-nature-50 rounded-full flex items-center justify-center mb-6 text-nature-200">
              <Sparkles size={40} />
            </div>
            <h3 className="text-xl font-serif text-nature-800 mb-2">Nada por aqui ainda</h3>
            <p className="text-nature-600 text-sm max-w-[250px]">
              {activeFilter === 'following' 
                ? "Você ainda não segue ninguém ou ninguém que você segue postou hoje. Que tal seguir novos membros?" 
                : "Ainda não há postagens neste filtro."}
            </p>
            {activeFilter === 'following' && (
              <button 
                onClick={() => setActiveFilter('recent')}
                className="mt-6 text-nature-600 font-bold text-sm underline underline-offset-4"
              >
                Ver postagens recentes
              </button>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Community;

export enum AppView {
  DASHBOARD = 'dashboard',
  DIAGNOSIS = 'diagnosis',
  TRACKER = 'tracker',
  GUIDANCE = 'guidance',
  WELLNESS = 'wellness',
  COMMUNITY = 'community',
}

