  id: string;
  name: string;
  category: 'digestivo' | 'neurologico' | 'pele' | 'emocional' | 'outro';
  weight: number;
}

export interface UserProfile {
  name: string;
  startDate: string | null; // ISO date string
  diagnosisScore: number;
  hasSeenWarning: boolean;
  isOnDiet: boolean;
}

export interface DailyLog {
  date: string; // YYYY-MM-DD
  meals: {
    breakfast: string;
    lunch: string;
    dinner: string;
    snacks: string;
  };
  symptomsPresent: string[]; // IDs of symptoms
  relievedSymptoms?: string[]; // IDs of relieved symptoms
  mood: number; // 1-5
  waterIntake: number; // glasses (approx 250ml each)
  completedActions: {
    diet: boolean; // S/G S/L S/A
    diary: boolean;
    meditationOrBreathing: boolean;
    emotionalWork: boolean;
    exercise: boolean;
    earthing: boolean;
    waterGoal: boolean; // 2L reached
  };
}

export interface Comment {
  id: string;
  author: string;
  avatar: string;
  text: string;
  timestamp: number;
}

export interface CommunityPost {
