}

export interface Recipe {
  type: string; // e.g. 'Café da Manhã'
  title: string;
  ingredients: string[];
  instructions: string[];
}

export interface DailyContent {
  menu: Recipe[];
  motivation: string;
  dailyChallenge: string; // e.g., "10 min de sol"
}

