import { Heart, MessageCircle, Share2, Image as ImageIcon, Video as VideoIcon, X, Check, Users, Send, Clock, UserPlus, UserCheck, TrendingUp, Sparkles, PlayCircle, Edit3, Save } from 'lucide-react';
import { CommunityPost, Comment } from '../types';

