import { GoogleGenAI, Type, Modality } from "@google/genai";
import { DailyLog } from "../types";

// Always use named parameter for apiKey
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using gemini-3-flash-preview for general text tasks as per guidelines
const modelId = "gemini-3-flash-preview";
// TTS model as specified in guidelines
const ttsModelId = "gemini-2.5-flash-preview-tts";

export const generateDailyContent = async () => {
  try {
    const prompt = `
      Crie um plano alimentar diário completo para uma pessoa em uma jornada de reconexão com a essência e dieta restritiva (sem glúten, sem caseína/leite, sem açúcar).

      Gere um objeto JSON com:
      1. Um MENU COM 4 RECEITAS (Café da Manhã, Almoço, Lanche, Jantar). Todas devem ser estritamente sem glúten (S/G), sem leite (S/L) e sem açúcar (S/A).
      2. Uma frase ou pequeno texto motivacional focado em saúde, reconexão com a natureza e disciplina.
      3. Um pequeno desafio de estilo de vida (ex: "Caminhar descalço na grama", "Tomar 10 min de sol", "Escrever 3 coisas pelas quais é grato").
    `;

    // Use property .text directly as per guidelines
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            menu: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING, description: "Tipo da refeição (Café da Manhã, Almoço, Lanche, Jantar)" },
                  title: { type: Type.STRING },
                  ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
                  instructions: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            motivation: { type: Type.STRING },
            dailyChallenge: { type: Type.STRING }
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    throw new Error("No content generated");
  } catch (error) {
    console.error("Gemini Content Error:", error);
    // Fallback content
    return {
      menu: [
        {
          type: "Café da Manhã",
          title: "Panqueca de Banana com Aveia (S/G)",
          ingredients: ["1 banana madura", "1 ovo", "2 colheres de aveia sem glúten", "Canela a gosto"],
          instructions: ["Amasse a banana.", "Misture com o ovo e a aveia.", "Asse em frigideira antiaderente até dourar."]
        },
        {
          type: "Almoço",
          title: "Frango com Cúrcuma e Legumes",
          ingredients: ["Peito de frango em cubos", "Cúrcuma (açafrão)", "Abobrinha", "Cenoura", "Azeite"],
          instructions: ["Refogue o frango com azeite e cúrcuma.", "Adicione os legumes picados e deixe cozinhar.", "Sirva com salada verde."]
        },
        {
          type: "Lanche",
          title: "Mix de Castanhas e Frutas Secas",
          ingredients: ["Castanha do Pará", "Nozes", "Damasco seco (sem açúcar)", "Sementes de abóbora"],
          instructions: ["Misture as porções em um pote.", "Consuma uma porção moderada para energia."]
        },
        {
          type: "Jantar",
          title: "Sopa Creme de Abóbora com Gengibre",
          ingredients: ["Abóbora cabotiá", "Gengibre ralado", "Cebola", "Azeite", "Sal"],
          instructions: ["Cozinhe a abóbora até desmanchar.", "Bata no liquidificador com um pouco da água do cozimento.", "Refogue cebola e gengibre no azeite e misture o creme."]
        }
      ],
      motivation: "Seu corpo é seu templo. Cuide dele com amor e ele retribuirá com energia.",
      dailyChallenge: "Respire fundo por 2 minutos olhando para o céu."
    };
  }
};

export const generateLouiseHayAffirmation = async (feeling: string) => {
  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: `Gere uma afirmação positiva curta, poética e poderosa no estilo de Louise Hay para alguém que está sentindo "${feeling}". 
      Use pontuação como reticências (...) para indicar pausas de respiração, pois este texto será lido por uma IA com voz suave. Foque em autoaceitação.`,
    });
    return response.text;
  } catch (error) {
    return "Eu me amo... e me aprovo... exatamente como sou.";
  }
};

