           </div>
           {generatedContent && (
             <div className="mt-4 p-6 bg-white rounded-2xl shadow-lg border border-nature-100 animate-in fade-in slide-in-from-bottom-4">
               <Sparkles className="text-yellow-400 mb-2 mx-auto" />
               <p className="text-center font-serif text-lg leading-relaxed text-gray-700 italic mb-4">"{generatedContent}"</p>
               {contentAudio && (
                 <button 
