                  className={`w-full flex items-center justify-center gap-2 py-3 rounded-xl font-medium transition-colors ${isPlayingContent ? 'bg-pink-500 text-white' : 'bg-pink-50 text-pink-700'}`}
                >
                   {isPlayingContent ? <Pause size={20} /> : <Volume2 size={20} />} 
                   {isPlayingContent ? 'Pausar Guia' : 'Ouvir Guia'}
                 </button>
               )}
             </div>
           )}
        </div>
      )}

      {activeTab === 'healing-ritual' && (
        <div className="space-y-6">
           {ritualStep === 'idle' ? (
             <div className="bg-gradient-to-br from-rose-50 to-red-50 p-6 rounded-2xl border border-rose-100">
                <h3 className="font-serif text-xl text-rose-900 mb-2 flex items-center gap-2">
                  <Heart className="text-rose-500" fill="currentColor" /> Ritual de Cura Profunda
                </h3>
                <p className="text-rose-800/70 text-sm mb-6 leading-relaxed">
                  Este é um exercício de liberação para dores profundas. Vamos enfrentar o que dói, reconhecer nossa força e perdoar para sermos livres.
                </p>
                <label className="block text-xs font-bold text-rose-900 uppercase mb-2">O que você deseja falar para si mesmo agora?</label>
                <textarea 
                  value={personalMessage}
                  onChange={(e) => setPersonalMessage(e.target.value)}
                  placeholder="Ex: Eu mereço ser feliz, Eu sou digno de amor..."
