                  rows={3}
                />
                <button 
                  onClick={startHealingRitual}
                  disabled={loading || !personalMessage}
                  className="w-full bg-rose-600 text-white py-4 rounded-xl font-bold shadow-lg shadow-rose-200 flex items-center justify-center gap-2"
                >
                  {loading ? <Loader2 className="animate-spin" /> : <Sparkles size={20} />}
