                <div>
                  <h4 className="font-bold text-gray-800 text-sm">{post.author}</h4>
                  <div className="flex items-center gap-1 text-[10px] text-gray-400">
                    <Clock size={10} /> {new Date(post.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>
              {post.author !== 'Você' && post.author !== 'Guia Essência' && (
                <button 
                  onClick={() => toggleFollow(post.author)}
                  className={`p-2 rounded-full transition-colors ${followedAuthors.has(post.author) ? 'text-nature-600 bg-nature-50' : 'text-gray-300 hover:text-nature-500'}`}
                >
                  {followedAuthors.has(post.author) ? <UserCheck size={20} /> : <UserPlus size={20} />}
                </button>
              )}
            </div>

            <div className="px-4 pb-4">
              <p className="text-gray-700 text-sm leading-relaxed">{post.content}</p>
            </div>

            {post.image && (
              <div className="px-2">
                <img src={post.image} className="w-full h-64 object-cover rounded-xl" alt="Post content" />
              </div>
            )}

