// Helper function for base64 decoding
function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Fixed audio decoding logic for raw PCM data from TTS
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

type BreathingPattern = '478' | 'box' | 'coherence';

const PATTERNS = {
  '478': { name: 'Relaxamento (4-7-8)', phases: ['Inspire', 'Segure', 'Expire'] },
  'box': { name: 'Foco (Quadrada)', phases: ['Inspire', 'Segure', 'Expire', 'Segure Vazio'] },
  'coherence': { name: 'Equilíbrio (Coerência)', phases: ['Inspire', 'Expire'] }
};

const Wellness: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'meditation' | 'emotional' | 'healing-ritual'>('meditation');
  const [generatedContent, setGeneratedContent] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  // Ritual State
  const [ritualStep, setRitualStep] = useState<'idle' | 'preparing' | 'feeling' | 'affirming' | 'forgiving' | 'checking'>('idle');
  const [personalMessage, setPersonalMessage] = useState('');
  const [ritualAudio, setRitualAudio] = useState<{ [key: string]: AudioBuffer | null }>({});

  // Breathing state
  const [pattern, setPattern] = useState<BreathingPattern>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('breathingPattern');
      if (saved === '478' || saved === 'box' || saved === 'coherence') {
        return saved;
      }
    }
    return '478';
  });

  const [isBreathing, setIsBreathing] = useState(false);
  const [breathPhase, setBreathPhase] = useState('Pronto');
  const [audioBuffers, setAudioBuffers] = useState<{ [key: string]: AudioBuffer | null }>({
    inspire: null,
    hold: null,
    exhale: null,
    holdEmpty: null
  });
  const [loadingAudio, setLoadingAudio] = useState(false);

  // Ref Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Advanced Audio Player State
  const [contentAudio, setContentAudio] = useState<AudioBuffer | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackSpeed, setPlaybackSpeed] = useState(1);

  const sourceRef = useRef<AudioBufferSourceNode | null>(null);
  const startTimeRef = useRef<number>(0);
  const offsetRef = useRef<number>(0);
  const animationFrameRef = useRef<number | null>(null);

  useEffect(() => {
    localStorage.setItem('breathingPattern', pattern);
  }, [pattern]);

  const initAudioContext = async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }
  };

  // Advanced Player Logic
  const updateProgress = () => {
    if (!isPlaying || !audioContextRef.current) return;

    const elapsed = (audioContextRef.current.currentTime - startTimeRef.current) * playbackSpeed;
    const currentPos = offsetRef.current + elapsed;

    if (currentPos >= duration) {
      setIsPlaying(false);
      setCurrentTime(duration);
      offsetRef.current = 0;
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      return;
    }

    setCurrentTime(currentPos);
    animationFrameRef.current = requestAnimationFrame(updateProgress);
  };

  const playAudio = async (buffer: AudioBuffer, startOffset: number = 0) => {
    await initAudioContext();
    stopAudio();

    const source = audioContextRef.current!.createBufferSource();
    source.buffer = buffer;
    source.playbackRate.value = playbackSpeed;
    source.connect(audioContextRef.current!.destination);

    startTimeRef.current = audioContextRef.current!.currentTime;
    offsetRef.current = startOffset;

    source.start(0, startOffset);
    sourceRef.current = source;
    setIsPlaying(true);

    animationFrameRef.current = requestAnimationFrame(updateProgress);

    source.onended = () => {
      // Solo manejar el final si no fue una detención manual por seek
      const elapsed = (audioContextRef.current!.currentTime - startTimeRef.current) * playbackSpeed;
      if (offsetRef.current + elapsed >= duration - 0.1) {
        setIsPlaying(false);
        setCurrentTime(duration);
        offsetRef.current = 0;
      }
    };
  };

  const stopAudio = () => {
    if (sourceRef.current) {
      try { sourceRef.current.stop(); } catch (e) {}
      sourceRef.current.disconnect();
      sourceRef.current = null;
    }
    if (animationFrameRef.current) {
      cancelAnimationFrame(animationFrameRef.current);
    }
    setIsPlaying(false);
  };

  const togglePlayback = () => {
    if (isPlaying) {
      const elapsed = (audioContextRef.current!.currentTime - startTimeRef.current) * playbackSpeed;
      offsetRef.current += elapsed;
      stopAudio();
    } else {
      if (contentAudio) {
        // If finished, restart
        const targetOffset = currentTime >= duration ? 0 : currentTime;
        playAudio(contentAudio, targetOffset);
      }
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newTime = parseFloat(e.target.value);
    setCurrentTime(newTime);
    if (contentAudio) {
      if (isPlaying) {
        playAudio(contentAudio, newTime);
      } else {
        offsetRef.current = newTime;
      }
    }
  };

  const skipTime = (seconds: number) => {
    const newTime = Math.min(Math.max(0, currentTime + seconds), duration);
    setCurrentTime(newTime);
    if (contentAudio && isPlaying) {
      playAudio(contentAudio, newTime);
    } else {
      offsetRef.current = newTime;
    }
  };

  const changeSpeed = () => {
    const speeds = [0.75, 1, 1.25, 1.5];
    const currentIndex = speeds.indexOf(playbackSpeed);
    const nextSpeed = speeds[(currentIndex + 1) % speeds.length];
    setPlaybackSpeed(nextSpeed);

    if (isPlaying && contentAudio) {
      const elapsed = (audioContextRef.current!.currentTime - startTimeRef.current) * playbackSpeed;
      const currentPos = offsetRef.current + elapsed;
      // We must restart to apply new speed effectively or update playbackRate
      if (sourceRef.current) {
        sourceRef.current.playbackRate.value = nextSpeed;
        // Recalcular startTime para que updateProgress funcione con el nuevo speed
        startTimeRef.current = audioContextRef.current!.currentTime;
        offsetRef.current = currentPos;
      }
    }
  };

  const formatTime = (time: number) => {
    const mins = Math.floor(time / 60);
    const secs = Math.floor(time % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
