    if (!text?.trim()) return;

    const newComment: Comment = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      text: text,
      timestamp: Date.now()
    };

    setPosts(prevPosts =>
      prevPosts.map(post => post.id === postId ? {
        ...post,
        comments: (post.commentList?.length || 0) + 1,
        commentList: [...(post.commentList || []), newComment]
      } : post)
    );

    setCommentInputs(prev => ({ ...prev, [postId]: '' }));

    if (!expandedComments.has(postId)) {
      setExpandedComments(prev => new Set(prev).add(postId));
    }
  };

  const handlePost = async () => {
    if (!newPost.trim() && !selectedVideo && !selectedImage) return;

    setIsUploading(true);
    await new Promise(r => setTimeout(r, 800));

    let videoUrl: string | undefined = undefined;
    let imageUrl: string | undefined = undefined;

    if (selectedVideo) {
      videoUrl = URL.createObjectURL(selectedVideo);
    }
    if (selectedImage) {
      imageUrl = URL.createObjectURL(selectedImage);
    }

    const post: CommunityPost = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      content: newPost,
      likes: 0,
      comments: 0,
      commentList: [],
      timestamp: Date.now(),
      video: videoUrl,
      image: imageUrl,
      caption: (selectedVideo || selectedImage) ? newCaption : undefined
    };

    setPosts([post, ...posts]);
    setNewPost('');
    setNewCaption('');
    setSelectedVideo(null);
    setSelectedImage(null);
    setMediaPreview(null);
    setIsUploading(false);
    setActiveFilter('recent');
  };

  const handleVideoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedVideo(file);
      setSelectedImage(null);
      setMediaPreview(URL.createObjectURL(file));
    }
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedImage(file);
      setSelectedVideo(null);
      setMediaPreview(URL.createObjectURL(file));
    }
  };

  const clearMedia = () => {
    setSelectedVideo(null);
    setSelectedImage(null);
    setMediaPreview(null);
    setNewCaption('');
  };

  const startEditingCaption = (post: CommunityPost) => {
    setEditingCaptionId(post.id);
    setEditCaptionValue(post.caption || '');
  };

  const saveCaption = (postId: string) => {
    setPosts(prev => prev.map(p => p.id === postId ? { ...p, caption: editCaptionValue } : p));
    setEditingCaptionId(null);
  };

  const handleShare = async (post: CommunityPost) => {
    const shareUrl = `https://reviva.app/tribo/${post.id}`;
    const shareData: any = {
      title: 'Tribo Essência - ReViva',
      text: `${post.author} compartilhou na Tribo Essência: "${post.content.substring(0, 80)}..."`,
      url: shareUrl,
    };

    const mediaUrl = post.image || post.video;
    setIsSharing(post.id);

    try {
      if (navigator.share) {
        if (mediaUrl) {
          try {
            const response = await fetch(mediaUrl);
            const blob = await response.blob();
            const extension = post.image ? 'png' : 'mp4';
            const fileName = `media-${post.id}.${extension}`;
            const file = new File([blob], fileName, { type: blob.type });

            if (navigator.canShare && navigator.canShare({ files: [file] })) {
              shareData.files = [file];
            }
          } catch (fetchError) {
            console.warn("Mídia não pôde ser incluída no compartilhamento.", fetchError);
          }
        }
        await navigator.share(shareData);
      } else {
        await navigator.clipboard.writeText(shareUrl);
        alert("Link da postagem copiado!");
      }
    } catch (err) {
      if ((err as Error).name !== 'AbortError') {
        console.error('Erro ao compartilhar:', err);
      }
    } finally {
      setIsSharing(null);
    }
  };

  return (
    <div className="p-4 pb-24 max-w-2xl mx-auto space-y-6">
      <header>
        <h2 className="text-2xl font-serif text-nature-800">Tribo Essência</h2>
        <p className="text-nature-600 text-sm">Compartilhe sua jornada de cura.</p>
      </header>

      {/* New Post Input */}
      <div className="bg-white p-4 rounded-2xl shadow-sm border border-nature-100">
        <textarea
          className="w-full bg-sand-50 rounded-xl p-4 text-sm focus:ring-2 focus:ring-nature-200 outline-none resize-none"
          placeholder="O que você está sentindo hoje?"
          rows={3}
          value={newPost}
          onChange={(e) => setNewPost(e.target.value)}
        />

        {mediaPreview && (
          <div className="mt-3 relative rounded-xl overflow-hidden border border-nature-200">
            {selectedVideo ? (
              <video src={mediaPreview} className="w-full h-48 object-cover" />
            ) : (
              <img src={mediaPreview} className="w-full h-48 object-cover" alt="Preview" />
            )}
            <button onClick={clearMedia} className="absolute top-2 right-2 p-1 bg-black/50 text-white rounded-full">
              <X size={16} />
            </button>
            <input
              className="w-full p-2 text-xs bg-white/90 focus:outline-none"
              placeholder="Adicione uma legenda..."
              value={newCaption}
              onChange={(e) => setNewCaption(e.target.value)}
            />
          </div>
        )}

        <div className="mt-3 flex justify-between items-center">
          <div className="flex gap-2">
            <button onClick={() => imageInputRef.current?.click()} className="p-2 text-nature-600 hover:bg-nature-50 rounded-full transition-colors">
              <ImageIcon size={20} />
              <input type="file" ref={imageInputRef} hidden accept="image/*" onChange={handleImageSelect} />
            </button>
            <button onClick={() => videoInputRef.current?.click()} className="p-2 text-nature-600 hover:bg-nature-50 rounded-full transition-colors">
              <VideoIcon size={20} />
              <input type="file" ref={videoInputRef} hidden accept="video/*" onChange={handleVideoSelect} />
            </button>
          </div>
          <button 
            onClick={handlePost}
            disabled={isUploading || (!newPost.trim() && !mediaPreview)}
            className="bg-nature-600 text-white px-6 py-2 rounded-full font-bold text-sm shadow-md hover:bg-nature-700 disabled:opacity-50 flex items-center gap-2"
          >
            {isUploading ? 'Enviando...' : <><Send size={16} /> Postar</>}
          </button>
        </div>
      </div>

      {/* Feed Filters */}
      <div className="flex gap-2">
        {(['recent', 'liked', 'following'] as FilterType[]).map(f => (
          <button
            key={f}
            onClick={() => setActiveFilter(f)}
            className={`px-4 py-2 rounded-full text-xs font-bold transition-all ${
              activeFilter === f ? 'bg-nature-600 text-white' : 'bg-white text-nature-600 border border-nature-100 hover:bg-nature-50'
            }`}
          >
            {f === 'recent' ? 'Recentes' : f === 'liked' ? 'Populares' : 'Seguindo'}
          </button>
        ))}
      </div>

      {/* Posts List */}
      <div className="space-y-6">
        {filteredPosts.map(post => (
          <div key={post.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-4 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <img src={post.avatar} className="w-10 h-10 rounded-full object-cover" alt={post.author} />
                <div>
                  <h4 className="font-bold text-gray-800 text-sm">{post.author}</h4>
                  <div className="flex items-center gap-1 text-[10px] text-gray-400">
                    <Clock size={10} /> {new Date(post.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>
              {post.author !== 'Você' && post.author !== 'Guia Essência' && (
                <button 
                  onClick={() => toggleFollow(post.author)}
                  className={`p-2 rounded-full transition-colors ${followedAuthors.has(post.author) ? 'text-nature-600 bg-nature-50' : 'text-gray-300 hover:text-nature-500'}`}
                >
                  {followedAuthors.has(post.author) ? <UserCheck size={20} /> : <UserPlus size={20} />}
                </button>
              )}
            </div>

            <div className="px-4 pb-4">
              <p className="text-gray-700 text-sm leading-relaxed">{post.content}</p>
            </div>

            {post.image && (
              <div className="px-2">
                <img src={post.image} className="w-full h-64 object-cover rounded-xl" alt="Post content" />
              </div>
            )}

            {post.video && (
              <div className="px-2">
                <video src={post.video} controls className="w-full h-64 object-cover rounded-xl bg-black" />
              </div>
            )}

            {(post.image || post.video) && post.caption && (
              <div className="px-4 pt-2 flex items-start gap-2">
                {editingCaptionId === post.id ? (
                  <div className="flex-1 flex gap-2">
                    <input 
                      className="flex-1 text-xs border-b border-nature-300 focus:outline-none" 
                      value={editCaptionValue} 
                      onChange={(e) => setEditCaptionValue(e.target.value)} 
                    />
                    <button onClick={() => saveCaption(post.id)} className="text-nature-600"><Save size={16} /></button>
                  </div>
                ) : (
                  <>
                    <p className="text-xs text-gray-500 italic flex-1">"{post.caption}"</p>
                    {post.author === 'Você' && <button onClick={() => startEditingCaption(post)} className="text-gray-300 hover:text-nature-500"><Edit3 size={14} /></button>}
                  </>
                )}
              </div>
            )}

            <div className="p-4 border-t border-gray-50 flex items-center justify-between">
              <div className="flex gap-4">
                <button 
                  onClick={() => handleLike(post.id)}
                  className={`flex items-center gap-1.5 text-xs font-medium transition-all active:scale-125 ${likedPosts.has(post.id) ? 'text-rose-500' : 'text-gray-400 hover:text-rose-500'}`}
                >
                  <Heart size={18} fill={likedPosts.has(post.id) ? 'currentColor' : 'none'} className="transition-transform" />
                  {post.likes}
                </button>
                <button 
                  onClick={() => toggleComments(post.id)}
                  className={`flex items-center gap-1.5 text-xs font-medium transition-colors ${expandedComments.has(post.id) ? 'text-nature-600' : 'text-gray-400 hover:text-nature-600'}`}
                >
                  <MessageCircle size={18} />
                  {post.comments}
                </button>
              </div>
              <button 
                onClick={() => handleShare(post)}
                className={`transition-all ${isSharing === post.id ? 'text-nature-600 scale-110' : 'text-gray-300 hover:text-nature-600'}`}
              >
                <Share2 size={18} className={isSharing === post.id ? 'animate-pulse' : ''} />
              </button>
            </div>

            {/* Comments Section */}
            {expandedComments.has(post.id) && (
              <div className="bg-nature-50 p-4 border-t border-nature-100 space-y-4 animate-in slide-in-from-top-2 duration-300">
                <div className="space-y-3 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
                  {post.commentList && post.commentList.length > 0 ? (
                    post.commentList.map(comment => (
                      <div key={comment.id} className="flex gap-3 items-start animate-in fade-in">
                        <img src={comment.avatar} className="w-8 h-8 rounded-full object-cover shrink-0 border border-white shadow-sm" alt={comment.author} />
                        <div className="bg-white p-3 rounded-2xl shadow-sm text-[12px] flex-1 border border-nature-100">
                          <div className="flex justify-between items-center mb-1">
                            <span className="font-bold text-nature-900">{comment.author}</span>
                            <span className="text-[10px] text-gray-400 italic">há pouco</span>
                          </div>
                          <p className="text-gray-600 leading-normal">{comment.text}</p>
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-4 text-gray-400 text-xs italic">
                      Seja o primeiro a comentar! ✨
                    </div>
                  )}
                </div>

                <div className="flex gap-2 items-center pt-2 border-t border-nature-100">
                  <img src="https://picsum.photos/50/50?random=99" className="w-8 h-8 rounded-full border border-white shadow-sm" alt="Você" />
                  <div className="relative flex-1">
                    <input
                      className="w-full bg-white border border-nature-200 rounded-full px-4 py-2 text-xs focus:ring-2 focus:ring-nature-200 outline-none pr-10 transition-all shadow-inner"
                      placeholder="Deixe uma palavra de apoio..."
                      value={commentInputs[post.id] || ''}
                      onChange={(e) => setCommentInputs({ ...commentInputs, [post.id]: e.target.value })}
                      onKeyPress={(e) => e.key === 'Enter' && handleCommentSubmit(post.id)}
                    />
                    <button 
                      onClick={() => handleCommentSubmit(post.id)} 
                      disabled={!commentInputs[post.id]?.trim()}
                      className="absolute right-2 top-1/2 -translate-y-1/2 text-nature-600 disabled:text-gray-200 p-1.5 hover:scale-110 transition-transform"
                    >
                      <Send size={16} />
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default Community;

