  const sourceRef = useRef<AudioBufferSourceNode | null>(null);
  const startTimeRef = useRef<number>(0);
  const offsetRef = useRef<number>(0);
  const animationFrameRef = useRef<number | null>(null);

  // Load saved meditations
  useEffect(() => {
    const saved = localStorage.getItem('savedMeditations');
    if (saved) {
      try {
        setSavedMeditations(JSON.parse(saved));
      } catch (e) {
        console.error("Error loading saved meditations", e);
      }
    }
  }, []);

  // Save meditations to localStorage
  useEffect(() => {
    localStorage.setItem('savedMeditations', JSON.stringify(savedMeditations));
  }, [savedMeditations]);

  useEffect(() => {
    localStorage.setItem('breathingPattern', pattern);
  }, [pattern]);

  const initAudioContext = async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }
  };

  // Advanced Player Logic
  const updateProgress = () => {
    if (!isPlaying || !audioContextRef.current) return;

    const elapsed = (audioContextRef.current.currentTime - startTimeRef.current) * playbackSpeed;
    const currentPos = offsetRef.current + elapsed;

    if (currentPos >= duration) {
      setIsPlaying(false);
      setCurrentTime(duration);
      offsetRef.current = 0;
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      return;
    }

    setCurrentTime(currentPos);
    animationFrameRef.current = requestAnimationFrame(updateProgress);
  };

  const playAudio = async (buffer: AudioBuffer, startOffset: number = 0) => {
    await initAudioContext();
    stopAudio();

    const source = audioContextRef.current!.createBufferSource();
    source.buffer = buffer;
    source.playbackRate.value = playbackSpeed;
    source.connect(audioContextRef.current!.destination);

    startTimeRef.current = audioContextRef.current!.currentTime;
    offsetRef.current = startOffset;

    source.start(0, startOffset);
    sourceRef.current = source;
    setIsPlaying(true);

    animationFrameRef.current = requestAnimationFrame(updateProgress);

    source.onended = () => {
      const elapsed = (audioContextRef.current!.currentTime - startTimeRef.current) * playbackSpeed;
      if (offsetRef.current + elapsed >= duration - 0.1) {
        setIsPlaying(false);
        setCurrentTime(duration);
        offsetRef.current = 0;
      }
    };
  };

  const stopAudio = () => {
    if (sourceRef.current) {
      try { sourceRef.current.stop(); } catch (e) {}
      sourceRef.current.disconnect();
      sourceRef.current = null;
    }
    if (animationFrameRef.current) {
      cancelAnimationFrame(animationFrameRef.current);
    }
    setIsPlaying(false);
  };

  const togglePlayback = () => {
    if (isPlaying) {
      const elapsed = (audioContextRef.current!.currentTime - startTimeRef.current) * playbackSpeed;
      offsetRef.current += elapsed;
      stopAudio();
    } else {
      if (contentAudio) {
        const targetOffset = currentTime >= duration ? 0 : currentTime;
        playAudio(contentAudio, targetOffset);
      }
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newTime = parseFloat(e.target.value);
    setCurrentTime(newTime);
    if (contentAudio) {
      if (isPlaying) {
        playAudio(contentAudio, newTime);
      } else {
        offsetRef.current = newTime;
      }
    }
  };

  const skipTime = (seconds: number) => {
    const newTime = Math.min(Math.max(0, currentTime + seconds), duration);
    setCurrentTime(newTime);
    if (contentAudio && isPlaying) {
      playAudio(contentAudio, newTime);
    } else {
      offsetRef.current = newTime;
    }
  };

  const changeSpeed = () => {
    const speeds = [0.75, 1, 1.25, 1.5];
    const currentIndex = speeds.indexOf(playbackSpeed);
    const nextSpeed = speeds[(currentIndex + 1) % speeds.length];
    setPlaybackSpeed(nextSpeed);

    if (isPlaying && contentAudio) {
      const elapsed = (audioContextRef.current!.currentTime - startTimeRef.current) * playbackSpeed;
      const currentPos = offsetRef.current + elapsed;
      if (sourceRef.current) {
        sourceRef.current.playbackRate.value = nextSpeed;
        startTimeRef.current = audioContextRef.current!.currentTime;
        offsetRef.current = currentPos;
      }
    }
  };

  const formatTime = (time: number) => {
    const mins = Math.floor(time / 60);
    const secs = Math.floor(time % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleTabChange = (tab: 'breathing' | 'meditation' | 'emotional' | 'healing-ritual') => {
    setActiveTab(tab);
    setIsBreathing(false);
    setRitualStep('idle');
    setGeneratedContent(null);
    setCurrentBase64(null);
    setContentAudio(null);
    stopAudio();
  };

  // Breathing simple play (for cues)
  const playCue = async (buffer: AudioBuffer) => {
    await initAudioContext();
    const source = audioContextRef.current!.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContextRef.current!.destination);
    source.start();
  };

  const preloadBreathingAudio = async () => {
    if (audioBuffers.inspire && audioBuffers.hold && audioBuffers.exhale) return;
    setLoadingAudio(true);
    try {
      await initAudioContext();
      const phrases = {
        inspire: "Inspire devagar... trazendo calma...",
        hold: "Segure o ar... sinta a paz...",
        exhale: "Solte o ar... relaxando tudo...",
        holdEmpty: "Fique no vazio... apenas sinta..."
      };
      const newBuffers = { ...audioBuffers };
      for (const [key, text] of Object.entries(phrases)) {
        if (!newBuffers[key]) {
          const base64 = await generateBreathingVoice(text);
          if (base64) {
            const bytes = decodeBase64(base64);
            const buffer = await decodeAudioData(bytes, audioContextRef.current!, 24000, 1);
            newBuffers[key] = buffer;
          }
        }
      }
      setAudioBuffers(newBuffers);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingAudio(false);
    }
  };

  // Ritual Logic
  const startHealingRitual = async () => {
    setLoading(true);
    setRitualStep('preparing');
    await initAudioContext();

    try {
      const scripts = {
        feeling: "Feche os olhos suavemente... Entre em contato com algo muito doloroso para você... Sinta as emoções... Não fuja delas agora...",
        affirming: `Diga para si mesmo: eu sobrevivi a essas dores profundas... Não foi fácil, mas sobrevivi e me tornei ainda mais forte e resiliente... Essa situação não me define e me tornou um ser humano ainda melhor... ${personalMessage}`,
        forgiving: "Agora, fale para quem te magoou: eu te perdoo porque sei que você deu o seu melhor naquele momento... Eu te libero e me libero...",
        checking: "Abra os olhos devagar... Sinta o presente... Agora feche-os novamente... Se a dor voltar, repetiremos o processo até que ela suma completamente."
      };

      const buffers: { [key: string]: AudioBuffer } = {};
      for (const [key, text] of Object.entries(scripts)) {
        const base64 = await generateSpeech(text);
        if (base64) {
          const bytes = decodeBase64(base64);
          buffers[key] = await decodeAudioData(bytes, audioContextRef.current!, 24000, 1);
        }
      }
      setRitualAudio(buffers);
      runRitualCycle(buffers);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const runRitualCycle = async (buffers = ritualAudio) => {
    setRitualStep('feeling');
    if (buffers.feeling) {
      setDuration(buffers.feeling.duration);
      setContentAudio(buffers.feeling);
      await playAudio(buffers.feeling, 0);
      await new Promise(r => setTimeout(r, (buffers.feeling!.duration / playbackSpeed) * 1000 + 1000));
    }

    setRitualStep('affirming');
    if (buffers.affirming) {
      setDuration(buffers.affirming.duration);
      setContentAudio(buffers.affirming);
      await playAudio(buffers.affirming, 0);
      await new Promise(r => setTimeout(r, (buffers.affirming!.duration / playbackSpeed) * 1000 + 1000));
    }

    setRitualStep('forgiving');
    if (buffers.forgiving) {
      setDuration(buffers.forgiving.duration);
      setContentAudio(buffers.forgiving);
      await playAudio(buffers.forgiving, 0);
      await new Promise(r => setTimeout(r, (buffers.forgiving!.duration / playbackSpeed) * 1000 + 1000));
    }

    setRitualStep('checking');
    if (buffers.checking) {
      setDuration(buffers.checking.duration);
      setContentAudio(buffers.checking);
      await playAudio(buffers.checking, 0);
    }
  };

  // Guided Meditation Logic
  const handleGenerateMeditation = async () => {
    setLoading(true);
    setGeneratedContent(null);
    setCurrentBase64(null);
    stopAudio();
    try {
      const script = await generateMeditationScript('consciência corporal');
      setGeneratedContent(script);
      const audioBase64 = await generateSpeech(script);
      if (audioBase64) {
        setCurrentBase64(audioBase64);
        const bytes = decodeBase64(audioBase64);
        const buffer = await decodeAudioData(bytes, audioContextRef.current!, 24000, 1);
        setContentAudio(buffer);
        setDuration(buffer.duration);
        setCurrentTime(0);
        playAudio(buffer, 0);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleSaveMeditation = () => {
    if (!generatedContent || !currentBase64) return;

    const newMeditation: SavedMeditation = {
      id: Date.now().toString(),
      title: `Meditação Corporal - ${new Date().toLocaleDateString('pt-BR')}`,
      script: generatedContent,
      audioBase64: currentBase64,
      timestamp: Date.now()
    };

    setSavedMeditations([newMeditation, ...savedMeditations]);
    alert("Meditação salva na sua biblioteca!");
