  const playSavedMeditation = async (meditation: SavedMeditation) => {
    setGeneratedContent(meditation.script);
    setCurrentBase64(meditation.audioBase64);
    await initAudioContext();
    const bytes = decodeBase64(meditation.audioBase64);
