          if (!isBreathing) return;
          setBreathPhase('Segure (7s)'); cue('hold');
          await new Promise(r => timerRef.current = setTimeout(r, 7000));
          if (!isBreathing) return;
          setBreathPhase('Expire (8s)'); cue('exhale');
          await new Promise(r => timerRef.current = setTimeout(r, 8000));
        } else if (pattern === 'box') {
          setBreathPhase('Inspire (4s)'); cue('inspire');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Segure (4s)'); cue('hold');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Expire (4s)'); cue('exhale');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Vazio (4s)'); cue('holdEmpty');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
        } else if (pattern === 'coherence') {
          setBreathPhase('Inspire (6s)'); cue('inspire');
          await new Promise(r => timerRef.current = setTimeout(r, 6000));
          if (!isBreathing) return;
          setBreathPhase('Expire (6s)'); cue('exhale');
          await new Promise(r => timerRef.current = setTimeout(r, 6000));
        }
        if (isBreathing) runCycle();
      };
      runCycle();
    } else {
      if (timerRef.current) clearTimeout(timerRef.current);
      setBreathPhase('Pronto');
