        </button>
        <button 
          onClick={() => handleTabChange('healing-ritual')}
          className={`flex-1 py-2 text-[10px] font-bold rounded-lg transition-all whitespace-nowrap px-3 ${activeTab === 'healing-ritual' ? 'bg-white shadow text-rose-600' : 'text-gray-500'}`}
