                    <Bookmark size={16} /> Salvar na Biblioteca
                  </button>
               </div>
               <div className="max-h-32 overflow-y-auto mb-6 text-center">
                 <p className="font-serif text-sm leading-relaxed text-gray-500 italic">"{generatedContent}"</p>
               </div>

               {contentAudio && (
                 <div className="space-y-4">
                   <div className="flex items-center gap-4 text-[10px] font-bold text-emerald-500 uppercase tracking-wider mb-2">
                     <span>{formatTime(currentTime)}</span>
