import React, { useState, useMemo } from 'react';
import { AlertTriangle, CheckCircle, Info, Sparkles, User, Filter, Search, X } from 'lucide-react';
import { Symptom, UserProfile } from '../types';

interface DiagnosisProps {
  onComplete: (score: number, name: string) => void;
  userProfile: UserProfile;
}

const SYMPTOMS: Symptom[] = [
  // Digestivo
  { id: '1', name: 'Inchaço abdominal frequente', category: 'digestivo', weight: 3 },
  { id: '2', name: 'Gases excessivos após refeições', category: 'digestivo', weight: 2 },
  { id: '3', name: 'Diarreia ou constipação crônica', category: 'digestivo', weight: 3 },
  { id: '12', name: 'Azia ou refluxo frequente', category: 'digestivo', weight: 2 },
  { id: '13', name: 'Sensação de estufamento imediato', category: 'digestivo', weight: 2 },
  { id: '14', name: 'Náuseas matinais ou pós-refeição', category: 'digestivo', weight: 2 },

  // Neurológico
  { id: '4', name: 'Névoa mental (Brain Fog)', category: 'neurologico', weight: 3 },
  { id: '5', name: 'Dor de cabeça ou enxaqueca', category: 'neurologico', weight: 2 },
  { id: '11', name: 'Tontura ou vertigem', category: 'neurologico', weight: 2 },
  { id: '15', name: 'Dificuldade de concentração', category: 'neurologico', weight: 2 },
  { id: '16', name: 'Insônia ou sono não reparador', category: 'neurologico', weight: 3 },

  // Pele
  { id: '8', name: 'Dermatites, acne ou coceiras', category: 'pele', weight: 2 },
  { id: '17', name: 'Eczema ou psoríase', category: 'pele', weight: 3 },
  { id: '18', name: 'Olheiras profundas ou rosto inchado', category: 'pele', weight: 1 },
  { id: '19', name: 'Unhas fracas ou queda de cabelo', category: 'pele', weight: 1 },

  // Emocional
  { id: '9', name: 'Ansiedade ou irritabilidade', category: 'emocional', weight: 1 },
  { id: '20', name: 'Alterações bruscas de humor', category: 'emocional', weight: 2 },
  { id: '21', name: 'Desânimo ou fadiga emocional', category: 'emocional', weight: 2 },

  // Outro
  { id: '6', name: 'Cansaço extremo após comer', category: 'outro', weight: 2 },
  { id: '7', name: 'Dores articulares sem causa aparente', category: 'outro', weight: 2 },
  { id: '10', name: 'Congestão nasal ou rinite frequente', category: 'outro', weight: 1 },
  { id: '22', name: 'Vontade incontrolável de doces', category: 'outro', weight: 2 },
];

const CATEGORIES = [
  { id: 'todos', label: 'Todos' },
  { id: 'digestivo', label: 'Digestivo' },
  { id: 'neurologico', label: 'Neurológico' },
  { id: 'pele', label: 'Pele' },
  { id: 'emocional', label: 'Emocional' },
  { id: 'outro', label: 'Outro' },
];

const Diagnosis: React.FC<DiagnosisProps> = ({ onComplete, userProfile }) => {
  const [selectedSymptoms, setSelectedSymptoms] = useState<string[]>([]);
  const [step, setStep] = useState<'warning' | 'quiz' | 'result'>('warning');
  const [activeCategory, setActiveCategory] = useState<string>('todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [userName, setUserName] = useState('');

  const handleToggleSymptom = (id: string) => {
    setSelectedSymptoms(prev => 
      prev.includes(id) ? prev.filter(s => s !== id) : [...prev, id]
    );
  };

  const calculateScore = () => {
    return selectedSymptoms.reduce((acc, id) => {
      const symptom = SYMPTOMS.find(s => s.id === id);
      return acc + (symptom?.weight || 0);
    }, 0);
  };

  const handleFinish = () => {
    setStep('result');
  };

  const handleStartJourney = () => {
    const score = calculateScore();
    const finalName = userName.trim() || 'Viajante';
    onComplete(score, finalName);
  };

  const filteredSymptoms = useMemo(() => {
    return SYMPTOMS.filter(s => {
      const matchesCategory = activeCategory === 'todos' || s.category === activeCategory;
      const matchesSearch = s.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [activeCategory, searchQuery]);

  const getCategoryCount = (categoryId: string) => {
    if (categoryId === 'todos') return selectedSymptoms.length;
    return SYMPTOMS.filter(s => s.category === categoryId && selectedSymptoms.includes(s.id)).length;
  };

  if (step === 'warning') {
    return (
      <div className="p-6 bg-red-50 min-h-screen flex flex-col justify-center items-center text-center">
        <AlertTriangle size={64} className="text-red-500 mb-6" />
        <h2 className="text-2xl font-bold text-red-800 mb-4 uppercase tracking-tight">Atenção Médica</h2>
        <div className="bg-white p-6 rounded-2xl shadow-xl border border-red-100 mb-8 max-w-sm">
          <p className="text-gray-800 mb-4 font-medium leading-relaxed">
            Antes de iniciar qualquer dieta de exclusão de glúten, é fundamental realizar exames para descartar a <strong>Doença Celíaca</strong>.
          </p>
          <p className="text-gray-600 text-xs italic">
            A retirada prematura do glúten pode mascarar resultados em biópsias e exames de sangue.
          </p>
        </div>
        <button
          onClick={() => setStep('quiz')}
          className="w-full bg-red-600 text-white py-4 rounded-2xl font-bold text-lg hover:bg-red-700 transition-all shadow-lg active:scale-95"
        >
          Entendi, quero prosseguir
        </button>
      </div>
    );
  }

  if (step === 'result') {
     const score = calculateScore();
     let message = "";
     let color = "";

     if (score < 10) {
        message = "Baixa probabilidade de sensibilidade, mas a reconexão alimentar sempre traz clareza.";
        color = "text-green-600";
     } else if (score < 25) {
        message = "Sintomas moderados. Sua essência pode estar reagindo a inflamatórios comuns.";
        color = "text-yellow-600";
     } else {
        message = "Alta indicação de sensibilidade. Seu corpo está pedindo por um período de descanso.";
        color = "text-orange-600";
     }

     return (
        <div className="p-6 flex flex-col items-center justify-center min-h-[80vh] animate-in fade-in duration-700">
            <div className="w-20 h-20 bg-nature-100 rounded-full flex items-center justify-center mb-6">
               <Sparkles className="text-nature-600" size={40} />
            </div>

            <h2 className="text-3xl font-serif text-nature-800 mb-2">Sua Jornada Começa</h2>
            <div className="text-6xl font-bold text-nature-600 mb-4 tabular-nums">{score} <span className="text-lg text-gray-400 font-normal">pts</span></div>
            <p className={`text-center text-base mb-8 ${color} font-medium max-w-xs`}>{message}</p>

            <div className="w-full max-w-xs space-y-4 mb-8">
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <User size={18} className="text-nature-300" />
                </div>
                <input
                  type="text"
                  placeholder="Como devemos te chamar?"
                  value={userName}
                  onChange={(e) => setUserName(e.target.value)}
                  className="block w-full pl-10 pr-3 py-3 border border-nature-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-nature-500 focus:border-nature-500 sm:text-sm transition-all shadow-inner"
                />
              </div>
              <p className="text-center text-gray-400 text-[10px] italic">
                O ciclo de 21 dias focará em "limpar" o organismo e silenciar ruídos inflamatórios.
              </p>
            </div>

            <button 
                className="w-full max-w-xs bg-nature-600 text-white py-4 rounded-2xl font-bold shadow-xl shadow-nature-100 hover:bg-nature-700 active:scale-95 transition-all flex items-center justify-center gap-2"
                onClick={handleStartJourney}
            >
                <CheckCircle size={20} /> Iniciar 21 Dias
            </button>
        </div>
     )
  }

  return (
    <div className="min-h-screen bg-sand-50">
      <div className="sticky top-0 z-30 bg-sand-50/95 backdrop-blur-md border-b border-nature-100 p-4 space-y-4">
        <header className="pt-2">
          <h2 className="text-2xl font-serif text-nature-800">Sinais do Corpo</h2>
          <p className="text-nature-600 text-sm">Escute o que sua essência está tentando dizer.</p>
        </header>

        {/* Search Bar */}
        <div className="relative group">
          <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
            <Search size={16} className="text-nature-400 group-focus-within:text-nature-600 transition-colors" />
          </div>
          <input
            type="text"
            placeholder="Buscar sintoma..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-10 py-2.5 bg-white border border-nature-100 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-nature-200 focus:border-nature-300 transition-all shadow-sm"
          />
          {searchQuery && (
            <button 
              onClick={() => setSearchQuery('')}
              className="absolute inset-y-0 right-3 flex items-center text-nature-300 hover:text-nature-500"
            >
              <X size={16} />
            </button>
          )}
        </div>

        {/* Category Filter */}
        <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
          {CATEGORIES.map((cat) => {
            const count = getCategoryCount(cat.id);
            return (
              <button
                key={cat.id}
                onClick={() => setActiveCategory(cat.id)}
                className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold transition-all border flex items-center gap-2 ${
                  activeCategory === cat.id 
                    ? 'bg-nature-600 text-white border-nature-600 shadow-md' 
                    : 'bg-white text-nature-400 border-nature-100 hover:border-nature-300'
                }`}
              >
                {cat.label}
                {count > 0 && (
                  <span className={`w-4 h-4 rounded-full flex items-center justify-center text-[9px] ${activeCategory === cat.id ? 'bg-white text-nature-600' : 'bg-nature-500 text-white'}`}>
                    {count}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      <div className="p-4 pb-40 space-y-3">
        {filteredSymptoms.length > 0 ? (
          filteredSymptoms.map((symptom) => (
            <div 
              key={symptom.id}
              onClick={() => handleToggleSymptom(symptom.id)}
              className={`p-4 rounded-2xl border-2 flex items-center justify-between cursor-pointer transition-all duration-300 animate-in fade-in slide-in-from-bottom-2 ${
                selectedSymptoms.includes(symptom.id) 
                  ? 'bg-nature-50 border-nature-500 shadow-md transform scale-[1.01]' 
                  : 'bg-white border-nature-50 hover:border-nature-200'
              }`}
            >
              <div className="flex-1">
                <p className={`font-bold text-sm transition-colors ${selectedSymptoms.includes(symptom.id) ? 'text-nature-900' : 'text-gray-700'}`}>
                  {symptom.name}
                </p>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[9px] text-nature-300 uppercase font-black tracking-widest">{symptom.category}</span>
                  {selectedSymptoms.includes(symptom.id) && (
                    <span className="text-[9px] text-nature-500 font-bold bg-nature-100 px-1.5 py-0.5 rounded uppercase">Selecionado</span>
                  )}
                </div>
              </div>
              <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${selectedSymptoms.includes(symptom.id) ? 'bg-nature-600 border-nature-600 scale-110' : 'border-nature-100'}`}>
                {selectedSymptoms.includes(symptom.id) && <CheckCircle className="text-white" size={16} />}
              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-20 flex flex-col items-center gap-4 animate-in fade-in">
            <div className="p-4 bg-white rounded-full shadow-inner border border-nature-50 text-nature-200">
              <Search size={40} />
            </div>
            <p className="text-nature-400 italic text-sm">Nenhum sintoma encontrado para sua busca.</p>
            <button 
              onClick={() => { setSearchQuery(''); setActiveCategory('todos'); }}
              className="text-nature-600 font-bold text-xs underline underline-offset-4"
            >
              Limpar todos os filtros
            </button>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 left-0 w-full p-6 bg-gradient-to-t from-sand-50 via-sand-50 to-transparent pt-10">
        <button
          onClick={handleFinish}
          disabled={selectedSymptoms.length === 0}
          className="w-full max-w-md mx-auto bg-nature-800 text-white py-4 rounded-2xl font-bold text-lg hover:bg-nature-900 shadow-2xl disabled:opacity-50 disabled:grayscale transition-all active:scale-95 flex items-center justify-center gap-3"
        >
          Avaliar Sensibilidade
          <span className="bg-white/20 px-2 py-0.5 rounded-lg text-sm">{selectedSymptoms.length}</span>
        </button>
      </div>
    </div>
  );
};

export default Diagnosis;

import React, { useState, useRef, useMemo } from 'react';
import { Heart, MessageCircle, Share2, Image as ImageIcon, Video as VideoIcon, X, Check, Users, Send, Clock, UserPlus, UserCheck, TrendingUp, Sparkles, PlayCircle, Edit3, Save } from 'lucide-react';
import { CommunityPost, Comment } from '../types';

