import { GoogleGenAI, Type, Modality } from "@google/genai";
import { DailyLog } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const modelId = "gemini-3-flash-preview";
const ttsModelId = "gemini-2.5-flash-preview-tts";

export const generateDailyContent = async () => {
  try {
    const prompt = `
      Atue como um Guia de Nutrição Ancestral. Crie um plano alimentar diário para reconexão com a essência.
      Restrições estritas: Sem glúten, Sem leite/caseína, Sem açúcar refinado.

      Gere um objeto JSON com:
      1. MENU COM 4 RECEITAS (Café da Manhã, Almoço, Lanche, Jantar). Títulos devem ser poéticos (ex: "O Despertar da Terra").
      2. Uma "Frase de Poder" focada em cura celular e silêncio interior.
      3. Um "Desafio Ritualístico" focado em conexão com os elementos (ex: "Conversar com uma planta", "Beber água olhando o reflexo").
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            menu: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  title: { type: Type.STRING },
                  ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
                  instructions: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            motivation: { type: Type.STRING },
            dailyChallenge: { type: Type.STRING }
          }
        }
      }
    });

    if (response.text) return JSON.parse(response.text);
    throw new Error("Empty response");
  } catch (error) {
    console.error(error);
    return {
      menu: [{ type: "Desjejum", title: "Elixir de Sol e Frutas", ingredients: ["Frutas da estação", "Hortelã"], instructions: ["Agradeça", "Pique as frutas", "Sinta o sabor"] }],
      motivation: "Você é um fragmento sagrado da natureza.",
      dailyChallenge: "Escute o silêncio por 5 minutos."
    };
  }
};

export const analyzeUserLogs = async (logs: DailyLog[]) => {
  try {
    const logsText = logs.slice(-5).map(l => 
      `Dia ${l.date}: Sintomas[${l.symptomsPresent.join(', ')}]. Humor[${l.mood}/5]. Aterramento: ${l.completedActions.earthing}.`
    ).join('\n');

    const prompt = `
      Atue como um Oráculo de Saúde Holística. Analise estes registros:
      ${logsText}

      Identifique uma conexão sutil entre as escolhas do usuário e seu bem-estar. 
      Responda com um "Insight Intuitivo" curto (máx 200 caracteres), poético e encorajador. 
      Use metáforas da natureza (rios, árvores, estações).
    `;

    const response = await ai.models.generateContent({ model: modelId, contents: prompt });
    return response.text;
  } catch (e) {
    return "O rio da sua saúde está encontrando seu curso. Continue fluindo com paciência.";
  }
}

export const generateSpeech = async (text: string) => {
  try {
    const response = await ai.models.generateContent({
      model: ttsModelId,
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Puck' }, // Puck has a more 'ethereal/neutral' vibe
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    return null;
  }
};

