  const [breathingBuffers, setBreathingBuffers] = useState<{ [key: string]: AudioBuffer | null }>({
    inspire: null,
    hold: null,
    exhale: null,
    holdEmpty: null
  });

  // Ref Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Advanced Audio Player State
  const [contentAudio, setContentAudio] = useState<AudioBuffer | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackSpeed, setPlaybackSpeed] = useState(1);

  const sourceRef = useRef<AudioBufferSourceNode | null>(null);
  const startTimeRef = useRef<number>(0);
  const offsetRef = useRef<number>(0);
  const animationFrameRef = useRef<number | null>(null);

  // Load saved meditations
  useEffect(() => {
    const saved = localStorage.getItem('savedMeditations');
    if (saved) {
      try {
        setSavedMeditations(JSON.parse(saved));
      } catch (e) {
        console.error("Error loading saved meditations", e);
      }
    }
  }, []);

  // Save meditations to localStorage
  useEffect(() => {
    localStorage.setItem('savedMeditations', JSON.stringify(savedMeditations));
  }, [savedMeditations]);

  useEffect(() => {
    localStorage.setItem('breathingPattern', pattern);
  }, [pattern]);

  const initAudioContext = async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }
  };

  // Advanced Player Logic
  const updateProgress = () => {
    if (!isPlaying || !audioContextRef.current) return;

    const elapsed = (audioContextRef.current.currentTime - startTimeRef.current) * playbackSpeed;
    const currentPos = offsetRef.current + elapsed;

    if (currentPos >= duration) {
      setIsPlaying(false);
      setCurrentTime(duration);
      offsetRef.current = 0;
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      return;
    }

    setCurrentTime(currentPos);
    animationFrameRef.current = requestAnimationFrame(updateProgress);
  };

  const playAudio = async (buffer: AudioBuffer, startOffset: number = 0) => {
    await initAudioContext();
    stopAudio();

    const source = audioContextRef.current!.createBufferSource();
    source.buffer = buffer;
    source.playbackRate.value = playbackSpeed;
    source.connect(audioContextRef.current!.destination);

    startTimeRef.current = audioContextRef.current!.currentTime;
    offsetRef.current = startOffset;

    source.start(0, startOffset);
    sourceRef.current = source;
    setIsPlaying(true);

    animationFrameRef.current = requestAnimationFrame(updateProgress);

    source.onended = () => {
      const elapsed = (audioContextRef.current!.currentTime - startTimeRef.current) * playbackSpeed;
      if (offsetRef.current + elapsed >= duration - 0.1) {
        setIsPlaying(false);
        setCurrentTime(duration);
        offsetRef.current = 0;
      }
    };
  };

  const stopAudio = () => {
    if (sourceRef.current) {
      try { sourceRef.current.stop(); } catch (e) {}
      sourceRef.current.disconnect();
      sourceRef.current = null;
    }
    if (animationFrameRef.current) {
      cancelAnimationFrame(animationFrameRef.current);
    }
    setIsPlaying(false);
  };

  const togglePlayback = () => {
    if (isPlaying) {
      const elapsed = (audioContextRef.current!.currentTime - startTimeRef.current) * playbackSpeed;
      offsetRef.current += elapsed;
      stopAudio();
    } else {
      if (contentAudio) {
        const targetOffset = currentTime >= duration ? 0 : currentTime;
        playAudio(contentAudio, targetOffset);
      }
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newTime = parseFloat(e.target.value);
    setCurrentTime(newTime);
    if (contentAudio) {
      if (isPlaying) {
        playAudio(contentAudio, newTime);
      } else {
        offsetRef.current = newTime;
      }
    }
  };

  const skipTime = (seconds: number) => {
    const newTime = Math.min(Math.max(0, currentTime + seconds), duration);
    setCurrentTime(newTime);
    if (contentAudio && isPlaying) {
      playAudio(contentAudio, newTime);
    } else {
      offsetRef.current = newTime;
    }
  };

  const changeSpeed = () => {
    const speeds = [0.75, 1, 1.25, 1.5];
    const currentIndex = speeds.indexOf(playbackSpeed);
    const nextSpeed = speeds[(currentIndex + 1) % speeds.length];
    setPlaybackSpeed(nextSpeed);

    if (isPlaying && contentAudio) {
      const elapsed = (audioContextRef.current!.currentTime - startTimeRef.current) * playbackSpeed;
      const currentPos = offsetRef.current + elapsed;
      if (sourceRef.current) {
        sourceRef.current.playbackRate.value = nextSpeed;
        startTimeRef.current = audioContextRef.current!.currentTime;
        offsetRef.current = currentPos;
      }
    }
  };

  const formatTime = (time: number) => {
    const mins = Math.floor(time / 60);
    const secs = Math.floor(time % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleTabChange = (tab: 'breathing' | 'meditation' | 'emotional' | 'healing-ritual') => {
    setActiveTab(tab);
    setIsBreathing(false);
    setRitualStep('idle');
    setGeneratedContent(null);
    setCurrentBase64(null);
    setContentAudio(null);
    stopAudio();
  };

  // Ritual Logic
  const startHealingRitual = async () => {
    setLoading(true);
    setRitualStep('preparing');
    await initAudioContext();

    try {
      const scripts = {
        feeling: "Feche os olhos... Respire fundo... Agora, entre em contato com a sua maior dor emocional neste momento... Localize-a no seu corpo... Não fuja dela, apenas sinta... Veja agora a cena e a pessoa que te feriu...",
        forgiving: "Com os olhos fechados, olhe para quem te feriu e diga de coração: Eu te perdoo porque você deu o seu melhor naquele momento. Eu te libero e me libero para seguir em paz.",
        affirming: "Agora, diga para si mesmo, com toda a sua alma: Foi muito doloroso, mas eu sobrevivi. Eu venci. Eu me tornei muito mais forte e resiliente. Eu sou o capitão da minha cura.",
        checking: "Verifique seu estado agora. Feche os olhos e tente ver a cena novamente. Se ainda sentir qualquer dor, repetiremos o rito até que sua essência esteja em total paz."
      };

      const buffers: { [key: string]: AudioBuffer } = {};
      for (const [key, text] of Object.entries(scripts)) {
        const base64 = await generateSpeech(text);
        if (base64) {
          const bytes = decodeBase64(base64);
          buffers[key] = await decodeAudioData(bytes, audioContextRef.current!, 24000, 1);
        }
      }
      setRitualAudio(buffers);
      runRitualCycle(buffers);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const runRitualCycle = async (buffers = ritualAudio) => {
    setRitualStep('feeling');
    if (buffers.feeling) {
      setDuration(buffers.feeling.duration);
      setContentAudio(buffers.feeling);
      await playAudio(buffers.feeling, 0);
      await new Promise(r => setTimeout(r, (buffers.feeling!.duration / playbackSpeed) * 1000 + 500));
    }

    setRitualStep('forgiving');
    if (buffers.forgiving) {
      setDuration(buffers.forgiving.duration);
      setContentAudio(buffers.forgiving);
      await playAudio(buffers.forgiving, 0);
      await new Promise(r => setTimeout(r, (buffers.forgiving!.duration / playbackSpeed) * 1000 + 500));
    }

    setRitualStep('affirming');
    if (buffers.affirming) {
      setDuration(buffers.affirming.duration);
      setContentAudio(buffers.affirming);
      await playAudio(buffers.affirming, 0);
      await new Promise(r => setTimeout(r, (buffers.affirming!.duration / playbackSpeed) * 1000 + 500));
    }

    setRitualStep('checking');
    if (buffers.checking) {
      setDuration(buffers.checking.duration);
      setContentAudio(buffers.checking);
      await playAudio(buffers.checking, 0);
    }
  };

  // Breathing simple play (for cues)
  const playCue = async (buffer: AudioBuffer) => {
    await initAudioContext();
    const source = audioContextRef.current!.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContextRef.current!.destination);
    source.start();
  };

  const preloadBreathingAudio = async () => {
    if (breathingBuffers.inspire && breathingBuffers.hold && breathingBuffers.exhale) return;
    setLoadingAudio(true);
    try {
      await initAudioContext();
      const phrases = {
        inspire: "Inspire devagar... trazendo calma...",
        hold: "Segure o ar... sinta a paz...",
        exhale: "Solte o ar... relaxando tudo...",
        holdEmpty: "Fique no vazio... apenas sinta..."
      };
      const newBuffers = { ...breathingBuffers };
      for (const [key, text] of Object.entries(phrases)) {
        if (!newBuffers[key]) {
          const base64 = await generateBreathingVoice(text);
          if (base64) {
            const bytes = decodeBase64(base64);
            const buffer = await decodeAudioData(bytes, audioContextRef.current!, 24000, 1);
            newBuffers[key] = buffer;
          }
        }
      }
      setBreathingBuffers(newBuffers);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingAudio(false);
    }
  };

  const handleGenerateMeditation = async () => {
    setLoading(true);
    setGeneratedContent(null);
    setCurrentBase64(null);
    setContentAudio(null);
    stopAudio();
    try {
      const script = await generateMeditationScript('consciência corporal');
      setGeneratedContent(script);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleListenGuide = async () => {
    if (!generatedContent) return;
    if (contentAudio) {
      togglePlayback();
      return;
    }
    setLoadingAudio(true);
    try {
      await initAudioContext();
      const audioBase64 = await generateSpeech(generatedContent);
      if (audioBase64) {
        setCurrentBase64(audioBase64);
        const bytes = decodeBase64(audioBase64);
        const buffer = await decodeAudioData(bytes, audioContextRef.current!, 24000, 1);
        setContentAudio(buffer);
        setDuration(buffer.duration);
        setCurrentTime(0);
        playAudio(buffer, 0);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingAudio(false);
    }
  };

  const handleSaveMeditation = () => {
    if (!generatedContent || !currentBase64) {
      alert("Por favor, ouça o guia primeiro para gerar o áudio.");
      return;
    }
    const newMeditation: SavedMeditation = {
      id: Date.now().toString(),
      title: `Meditação Corporal - ${new Date().toLocaleDateString('pt-BR')}`,
      script: generatedContent,
      audioBase64: currentBase64,
      timestamp: Date.now()
    };
    setSavedMeditations([newMeditation, ...savedMeditations]);
    alert("Meditação salva!");
  };

  const playSavedMeditation = async (meditation: SavedMeditation) => {
    setGeneratedContent(meditation.script);
    setCurrentBase64(meditation.audioBase64);
    await initAudioContext();
    const bytes = decodeBase64(meditation.audioBase64);
    const buffer = await decodeAudioData(bytes, audioContextRef.current!, 24000, 1);
    setContentAudio(buffer);
    setDuration(buffer.duration);
    setCurrentTime(0);
    playAudio(buffer, 0);
  };

  const deleteSavedMeditation = (id: string) => {
    if (confirm("Deseja remover esta meditação?")) {
      setSavedMeditations(savedMeditations.filter(m => m.id !== id));
    }
  };

  useEffect(() => {
    if (isBreathing) {
      const runCycle = async () => {
        const cue = (key: string) => breathingBuffers[key] && playCue(breathingBuffers[key]!);
        if (pattern === '478') {
          setBreathPhase('Inspire (4s)'); cue('inspire');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Segure (7s)'); cue('hold');
          await new Promise(r => timerRef.current = setTimeout(r, 7000));
          if (!isBreathing) return;
          setBreathPhase('Expire (8s)'); cue('exhale');
          await new Promise(r => timerRef.current = setTimeout(r, 8000));
        } else if (pattern === 'box') {
          setBreathPhase('Inspire (4s)'); cue('inspire');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Segure (4s)'); cue('hold');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Expire (4s)'); cue('exhale');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
          if (!isBreathing) return;
          setBreathPhase('Vazio (4s)'); cue('holdEmpty');
          await new Promise(r => timerRef.current = setTimeout(r, 4000));
        } else if (pattern === 'coherence') {
          setBreathPhase('Inspire (6s)'); cue('inspire');
          await new Promise(r => timerRef.current = setTimeout(r, 6000));
          if (!isBreathing) return;
          setBreathPhase('Expire (6s)'); cue('exhale');
          await new Promise(r => timerRef.current = setTimeout(r, 6000));
        }
        if (isBreathing) runCycle();
      };
      runCycle();
    } else {
      if (timerRef.current) clearTimeout(timerRef.current);
      setBreathPhase('Pronto');
    }
  }, [isBreathing, pattern, breathingBuffers]);

  return (
    <div className="p-4 pb-24 max-w-2xl mx-auto">
      <header className="mb-6">
        <h2 className="text-2xl font-serif text-nature-800">Santuário Interior</h2>
        <p className="text-nature-600 text-sm">Cura profunda e reconexão.</p>
      </header>

      <div className="flex bg-gray-100 p-1 rounded-xl mb-6 overflow-x-auto gap-1">
        <button onClick={() => handleTabChange('breathing')} className={`flex-1 py-2 text-[10px] font-bold rounded-lg transition-all whitespace-nowrap px-3 ${activeTab === 'breathing' ? 'bg-white shadow text-blue-600' : 'text-gray-500'}`}>Respiração</button>
        <button onClick={() => handleTabChange('meditation')} className={`flex-1 py-2 text-[10px] font-bold rounded-lg transition-all whitespace-nowrap px-3 ${activeTab === 'meditation' ? 'bg-white shadow text-emerald-600' : 'text-gray-500'}`}>Meditação</button>
        <button onClick={() => handleTabChange('emotional')} className={`flex-1 py-2 text-[10px] font-bold rounded-lg transition-all whitespace-nowrap px-3 ${activeTab === 'emotional' ? 'bg-white shadow text-pink-600' : 'text-gray-500'}`}>Afirmações</button>
        <button onClick={() => handleTabChange('healing-ritual')} className={`flex-1 py-2 text-[10px] font-bold rounded-lg transition-all whitespace-nowrap px-3 ${activeTab === 'healing-ritual' ? 'bg-white shadow text-rose-600' : 'text-gray-500'}`}>Ritual de Cura</button>
      </div>

      {activeTab === 'breathing' && (
        <div className="bg-gradient-to-br from-blue-50 to-indigo-50 p-6 rounded-2xl flex flex-col items-center justify-center text-center relative overflow-hidden min-h-[350px]">
          <div className={`absolute bg-blue-200 rounded-full blur-2xl opacity-40 transition-all ease-in-out duration-1000 ${breathPhase.includes('Inspire') ? 'w-64 h-64' : breathPhase.includes('Segure') || breathPhase.includes('Vazio') ? 'w-60 h-60' : 'w-32 h-32'}`}></div>
          <div className="z-10 w-full mb-4">
            <div className="flex justify-center gap-2 mb-4">
              {(Object.keys(PATTERNS) as BreathingPattern[]).map((p) => (
                <button key={p} onClick={() => { setIsBreathing(false); setPattern(p); }} className={`text-[10px] px-3 py-1 rounded-full border transition-colors ${pattern === p ? 'bg-blue-500 text-white border-blue-500' : 'bg-white text-blue-400 border-blue-200 hover:bg-blue-50'}`}>{PATTERNS[p].name}</button>
              ))}
            </div>
          </div>
          <Wind className={`text-blue-500 mb-4 z-10 transition-transform duration-[4000ms] ${breathPhase.includes('Inspire') ? 'scale-125' : 'scale-100'}`} size={32} />
          <h3 className="font-serif text-xl text-blue-900 mb-1 z-10">{PATTERNS[pattern].name}</h3>
          <div className="text-3xl font-bold text-blue-800 mb-8 z-10 h-10 flex items-center justify-center">{loadingAudio ? <Loader2 className="animate-spin" /> : breathPhase}</div>
          <button onClick={async () => { await initAudioContext(); if (!isBreathing) await preloadBreathingAudio(); setIsBreathing(!isBreathing); }} disabled={loadingAudio} className="bg-white text-blue-600 px-8 py-3 rounded-full font-bold shadow-sm flex items-center gap-2 hover:shadow-md transition-all z-10 disabled:opacity-70">
            {isBreathing ? <Pause size={18}/> : <Play size={18}/>} {isBreathing ? 'Pausar' : 'Iniciar'}
          </button>
        </div>
      )}

      {activeTab === 'meditation' && (
        <div className="space-y-6">
          <div className="bg-gradient-to-br from-emerald-50 to-teal-50 p-6 rounded-2xl border border-emerald-100">
            <div className="flex items-center gap-3 mb-4"><Flower2 className="text-emerald-500" /><h3 className="font-serif text-xl text-emerald-900">Meditação Guiada</h3></div>
            <p className="text-emerald-800/70 text-sm mb-6">Geraremos uma meditação personalizada focada na sua consciência corporal.</p>
            <button onClick={handleGenerateMeditation} disabled={loading} className="w-full bg-emerald-600 text-white py-3 rounded-xl font-bold shadow-lg shadow-emerald-100 hover:bg-emerald-700 disabled:opacity-50 transition-all flex items-center justify-center gap-2">{loading ? <Loader2 className="animate-spin" /> : <Sparkles size={18} />} Gerar Nova Meditação</button>
          </div>
          {generatedContent && (
             <div className="mt-4 p-6 bg-white rounded-2xl shadow-lg border border-nature-100 animate-in fade-in slide-in-from-bottom-4">
               <div className="flex justify-between items-start mb-4"><span className="text-[10px] font-black uppercase tracking-widest text-emerald-300">{isPlaying ? 'Tocando Agora' : 'Roteiro Gerado'}</span><button onClick={handleSaveMeditation} className="flex items-center gap-1.5 text-xs font-bold text-emerald-600 hover:text-emerald-700 transition-colors"><Bookmark size={16} /> Salvar</button></div>
               <div className="max-h-32 overflow-y-auto mb-6 text-center border-b border-nature-50 pb-4"><p className="font-serif text-sm leading-relaxed text-gray-500 italic">"{generatedContent}"</p></div>
               {!contentAudio && !loadingAudio ? (
                 <div className="flex justify-center py-4"><button onClick={handleListenGuide} className="flex items-center gap-3 bg-emerald-50 text-emerald-700 px-8 py-4 rounded-2xl font-bold shadow-sm hover:bg-emerald-100 transition-all group"><Headphones size={24} className="group-hover:scale-110 transition-transform" /> Ouvir Guia</button></div>
               ) : loadingAudio ? (
                 <div className="flex flex-col items-center gap-3 py-6"><Loader2 className="animate-spin text-emerald-500" size={32} /><p className="text-xs text-emerald-600 font-medium animate-pulse">Sintonizando voz da essência...</p></div>
               ) : (
                 <div className="space-y-4">
                   <div className="flex items-center gap-4 text-[10px] font-bold text-emerald-500 uppercase tracking-wider mb-2"><span>{formatTime(currentTime)}</span><input type="range" min="0" max={duration} step="0.1" value={currentTime} onChange={handleSeek} className="flex-1 h-1.5 bg-emerald-100 rounded-lg appearance-none cursor-pointer accent-emerald-500" /><span>{formatTime(duration)}</span></div>
                   <div className="flex items-center justify-between"><button onClick={changeSpeed} className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-emerald-50 text-emerald-600 text-[10px] font-bold"><Timer size={14} /> {playbackSpeed}x</button>
                   <div className="flex items-center gap-4"><button onClick={() => skipTime(-15)} className="p-2 text-emerald-300 hover:text-emerald-500"><SkipBack size={20} /></button><button onClick={togglePlayback} className="w-12 h-12 flex items-center justify-center bg-emerald-500 text-white rounded-full shadow-lg shadow-emerald-100 hover:scale-110 transition-transform">{isPlaying ? <Pause size={24} fill="white" /> : <Play size={24} fill="white" className="ml-1" />}</button><button onClick={() => skipTime(15)} className="p-2 text-emerald-300 hover:text-emerald-500"><SkipForward size={20} /></button></div><div className="w-[60px]"></div></div>
                 </div>
               )}
             </div>
          )}
        </div>
      )}

      {activeTab === 'emotional' && (
        <div className="space-y-6">
           <div className="bg-gradient-to-br from-pink-50 to-rose-50 p-6 rounded-2xl">
              <div className="flex items-center gap-3 mb-4"><Heart className="text-pink-400" /><h3 className="font-serif text-xl text-pink-900">Espelho da Alma</h3></div>
              <p className="text-pink-800/70 text-sm mb-4">Gere uma afirmação de cura profunda para o que você está sentindo (Técnica inspirada em Louise Hay).</p>
              <input type="text" onChange={(e) => (window as any)._personalMsg = e.target.value} placeholder="Ex: Medo, Culpa, Dor no estômago..." className="w-full p-3 rounded-lg border-pink-100 bg-white/80 mb-3 text-pink-900 placeholder:text-pink-300" />
              <button onClick={async () => {
                setLoading(true); setGeneratedContent(null); stopAudio();
                const msg = (window as any)._personalMsg || "";
                const textResult = await generateLouiseHayAffirmation(msg);
                setGeneratedContent(textResult);
                const audioBase64 = await generateSpeech(textResult);
                if (audioBase64) {
                  const bytes = decodeBase64(audioBase64);
                  const buffer = await decodeAudioData(bytes, audioContextRef.current!, 24000, 1);
                  setContentAudio(buffer); setDuration(buffer.duration); setCurrentTime(0); playAudio(buffer, 0); 
                }
                setLoading(false);
              }} disabled={loading} className="w-full bg-pink-400 text-white py-3 rounded-lg font-bold hover:bg-pink-500 transition-colors">Gerar Afirmação</button>
           </div>
           {generatedContent && (
             <div className="mt-4 p-6 bg-white rounded-2xl shadow-lg border border-nature-100 animate-in fade-in slide-in-from-bottom-4">
               <p className="text-center font-serif text-lg leading-relaxed text-gray-700 italic mb-6">"{generatedContent}"</p>
               {contentAudio && (
                 <div className="space-y-4">
                   <div className="flex items-center gap-4 text-xs font-bold text-pink-400 uppercase tracking-wider mb-2"><span>{formatTime(currentTime)}</span><input type="range" min="0" max={duration} step="0.1" value={currentTime} onChange={handleSeek} className="flex-1 h-2 bg-pink-100 rounded-lg appearance-none cursor-pointer accent-pink-500" /><span>{formatTime(duration)}</span></div>
                   <div className="flex items-center justify-between"><button onClick={changeSpeed} className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-pink-50 text-pink-600 text-[10px] font-bold"><Timer size={14} /> {playbackSpeed}x</button>
                   <div className="flex items-center gap-4"><button onClick={() => skipTime(-15)} className="p-2 text-pink-300 hover:text-pink-500"><SkipBack size={20} /></button><button onClick={togglePlayback} className="w-12 h-12 flex items-center justify-center bg-pink-500 text-white rounded-full shadow-lg shadow-pink-100 hover:scale-110 transition-transform">{isPlaying ? <Pause size={24} fill="white" /> : <Play size={24} fill="white" className="ml-1" />}</button><button onClick={() => skipTime(15)} className="p-2 text-pink-300 hover:text-pink-500"><SkipForward size={20} /></button></div><div className="w-[60px]"></div></div>
                 </div>
               )}
             </div>
           )}
        </div>
      )}

      {activeTab === 'healing-ritual' && (
        <div className="space-y-6">
           {ritualStep === 'idle' ? (
             <div className="bg-gradient-to-br from-rose-50 to-red-50 p-6 rounded-2xl border border-rose-100">
                <h3 className="font-serif text-xl text-rose-900 mb-2 flex items-center gap-2"><Heart className="text-rose-500" fill="currentColor" /> Ritual de Cura Profunda</h3>
                <p className="text-rose-800/70 text-sm mb-6 leading-relaxed">Feche os olhos, entre em contato com a sua maior dor neste momento, veja quem te feriu e libere o perdão para se tornar mais forte.</p>
                <button onClick={startHealingRitual} disabled={loading} className="w-full bg-rose-600 text-white py-4 rounded-xl font-bold shadow-lg shadow-rose-200 flex items-center justify-center gap-2">{loading ? <Loader2 className="animate-spin" /> : <Sparkles size={20} />} Iniciar Ritual Sagrado</button>
             </div>
           ) : (
