export const generateSpeech = async (text: string) => {
  try {
    // Adicionando instrução de estilo para voz suave e clara
    const styledText = `Diga com uma voz suave, clara, pausada e profundamente acolhedora: ${text}`;

    const response = await ai.models.generateContent({
      model: ttsModelId,
      contents: [{ parts: [{ text: styledText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            // Kore é reconhecida por ser uma voz clara e suave, excelente para meditação
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    console.error("Erro no TTS:", error);
    return null;
  }
};

