          />
          {searchQuery && (
            <button 
              onClick={() => setSearchQuery('')}
              className="absolute inset-y-0 right-3 flex items-center text-nature-300 hover:text-nature-500"
            >
              <X size={16} />
            </button>
          )}
        </div>

        {/* Category Filter */}
        <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
          {CATEGORIES.map((cat) => {
            const stats = cat.id === 'todos' ? null : getCategoryStats(cat.id);
            const totalSelected = selectedSymptoms.length;

            return (
              <button
                key={cat.id}
                onClick={() => setActiveCategory(cat.id)}
                className={`whitespace-nowrap px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border flex items-center gap-2 ${
                  activeCategory === cat.id 
                    ? 'bg-nature-800 text-white border-nature-800 shadow-md' 
                    : 'bg-white text-nature-400 border-nature-100 hover:border-nature-300'
                }`}
              >
                {cat.label}
                {cat.id === 'todos' ? (
                  totalSelected > 0 && <span className="bg-nature-500 text-white px-1.5 rounded-full text-[8px]">{totalSelected}</span>
                ) : (
                  <span className={`px-1.5 rounded-full text-[8px] ${activeCategory === cat.id ? 'bg-white/20 text-white' : 'bg-nature-50 text-nature-400'}`}>
                    {stats?.selected} / {stats?.total}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      <div className="p-4 pb-48 space-y-8">
        {Object.keys(groupedFilteredSymptoms).length > 0 ? (
          CATEGORIES.filter(c => c.id !== 'todos' && groupedFilteredSymptoms[c.id]).map((cat) => (
            <section key={cat.id} className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
              <div className="flex items-center justify-between px-2">
                <h3 className="text-xs font-black uppercase tracking-[0.2em] text-nature-300 flex items-center gap-2">
                  <div className="w-1 h-3 bg-nature-200 rounded-full"></div>
                  {cat.label}
                </h3>
                <span className="text-[10px] font-bold text-nature-200 italic">
                  {getCategoryStats(cat.id).selected} de {getCategoryStats(cat.id).total} selecionados
                </span>
              </div>

              <div className="grid grid-cols-1 gap-3">
                {groupedFilteredSymptoms[cat.id].map((symptom) => (
                  <div 
                    key={symptom.id}
                    onClick={() => handleToggleSymptom(symptom.id)}
                    className={`p-4 rounded-2xl border-2 flex items-center justify-between cursor-pointer transition-all duration-300 ${
                      selectedSymptoms.includes(symptom.id) 
                        ? 'bg-nature-50 border-nature-500 shadow-md transform scale-[1.01]' 
                        : 'bg-white border-nature-50 hover:border-nature-200'
                    }`}
                  >
                    <div className="flex-1">
                      <p className={`font-bold text-sm transition-colors ${selectedSymptoms.includes(symptom.id) ? 'text-nature-900' : 'text-gray-700'}`}>
                        {symptom.name}
                      </p>
                    </div>
                    <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${selectedSymptoms.includes(symptom.id) ? 'bg-nature-800 border-nature-800 scale-110' : 'border-nature-100'}`}>
                      {selectedSymptoms.includes(symptom.id) && <CheckCircle className="text-white" size={16} />}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          ))
        ) : (
          <div className="text-center py-20 flex flex-col items-center gap-4 animate-in fade-in">
            <div className="p-4 bg-white rounded-full shadow-inner border border-nature-50 text-nature-200">
              <Search size={40} />
            </div>
            <p className="text-nature-400 italic text-sm">Nenhum sintoma encontrado para sua busca.</p>
            <button 
              onClick={() => { setSearchQuery(''); setActiveCategory('todos'); }}
              className="text-nature-600 font-bold text-xs underline underline-offset-4"
            >
              Limpar todos os filtros
            </button>
          </div>
        )}

        <div className="text-center pt-8 pb-4">
           <p className="text-[10px] text-nature-300 font-medium italic">Este exercício visa o desenvolvimento da consciência corporal.</p>
        </div>
      </div>

      <div className="fixed bottom-0 left-0 w-full p-6 bg-gradient-to-t from-sand-50 via-sand-50 to-transparent pt-10 z-20">
        <button
          onClick={handleFinish}
          disabled={selectedSymptoms.length === 0}
          className="w-full max-w-md mx-auto bg-nature-800 text-white py-4 rounded-2xl font-bold text-lg hover:bg-nature-900 shadow-2xl disabled:opacity-50 disabled:grayscale transition-all active:scale-95 flex items-center justify-center gap-3"
        >
          Avaliar Sensibilidade
          <span className="bg-white/20 px-2 py-0.5 rounded-lg text-sm">{selectedSymptoms.length}</span>
        </button>
      </div>
    </div>
  );
};

