  { id: '8', name: 'Dermatites, acne ou coceiras', category: 'pele', weight: 2 },
  { id: '17', name: 'Eczema ou psoríase', category: 'pele', weight: 3 },
  { id: '18', name: 'Olheiras profundas ou rosto inchado', category: 'pele', weight: 1 },
  { id: '19', name: 'Unhas fracas ou queda de cabelo', category: 'pele', weight: 1 },

