  { id: '20', name: 'Alterações bruscas de humor', category: 'emocional', weight: 2 },
  { id: '21', name: 'Desânimo ou fadiga emocional', category: 'emocional', weight: 2 },

  // Outro
  { id: '6', name: 'Cansaço extremo após comer', category: 'outro', weight: 2 },
  { id: '7', name: 'Dores articulares sem causa aparente', category: 'outro', weight: 2 },
  { id: '10', name: 'Congestão nasal ou rinite frequente', category: 'outro', weight: 1 },
  { id: '22', name: 'Vontade incontrolável de doces', category: 'outro', weight: 2 },
];

const CATEGORIES = [
  { id: 'todos', label: 'Todos', icon: LayoutGrid },
  { id: 'digestivo', label: 'Digestivo', icon: Activity },
  { id: 'neurologico', label: 'Neurológico', icon: Brain },
  { id: 'pele', label: 'Pele', icon: Wind },
  { id: 'emocional', label: 'Emocional', icon: Heart },
  { id: 'outro', label: 'Outro', icon: Shapes },
];

const Diagnosis: React.FC<DiagnosisProps> = ({ onComplete, userProfile }) => {
  const [selectedSymptoms, setSelectedSymptoms] = useState<string[]>([]);
  const [step, setStep] = useState<'warning' | 'quiz' | 'result'>('warning');
  const [activeCategory, setActiveCategory] = useState<string>('todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [userName, setUserName] = useState('');

  const handleToggleSymptom = (id: string) => {
    setSelectedSymptoms(prev => 
      prev.includes(id) ? prev.filter(s => s !== id) : [...prev, id]
    );
  };

  const calculateScore = () => {
    return selectedSymptoms.reduce((acc, id) => {
      const symptom = SYMPTOMS.find(s => s.id === id);
      return acc + (symptom?.weight || 0);
    }, 0);
  };

  const handleFinish = () => {
    setStep('result');
  };

  const handleStartJourney = () => {
    const score = calculateScore();
    const finalName = userName.trim() || 'Viajante';
    onComplete(score, finalName);
  };

  const getCategoryStats = (categoryId: string) => {
    const categorySymptoms = SYMPTOMS.filter(s => s.category === categoryId);
    const selectedInCategory = categorySymptoms.filter(s => selectedSymptoms.includes(s.id)).length;
    return {
      selected: selectedInCategory,
      total: categorySymptoms.length
    };
  };

  const groupedFilteredSymptoms = useMemo(() => {
    const groups: Record<string, Symptom[]> = {};

    SYMPTOMS.forEach(s => {
      const matchesCategory = activeCategory === 'todos' || s.category === activeCategory;
      const matchesSearch = s.name.toLowerCase().includes(searchQuery.toLowerCase());

      if (matchesCategory && matchesSearch) {
        if (!groups[s.category]) groups[s.category] = [];
        groups[s.category].push(s);
      }
    });

    return groups;
  }, [activeCategory, searchQuery]);

  if (step === 'warning') {
    return (
      <div className="p-6 bg-nature-50 min-h-screen flex flex-col justify-center items-center text-center animate-in fade-in duration-500">
        <div className="bg-white p-8 rounded-[3rem] shadow-xl border border-nature-100 max-w-sm space-y-6">
          <div className="flex flex-col items-center">
            <AlertTriangle size={48} className="text-red-500 mb-4" />
            <h2 className="text-xl font-bold text-gray-900 uppercase tracking-tight">Segurança Primeiro</h2>
            <p className="text-gray-600 text-sm mt-2 leading-relaxed">
              Antes de excluir o glúten, é vital descartar a <strong>Doença Celíaca</strong> com exames médicos. A retirada precoce pode mascarar diagnósticos clínicos.
            </p>
          </div>

          <div className="h-px bg-nature-100 w-full"></div>

          <div className="flex flex-col items-center">
            <Info size={40} className="text-nature-500 mb-4" />
            <h2 className="text-xl font-bold text-nature-900 uppercase tracking-tight">Sobre este Teste</h2>
            <p className="text-nature-700 text-sm mt-2 leading-relaxed italic">
              Este não é um diagnóstico médico. É uma ferramenta de <strong>consciência corporal</strong> projetada para ajudar você a escutar e entender os sinais do seu próprio corpo.
            </p>
          </div>

          <button
            onClick={() => setStep('quiz')}
            className="w-full bg-nature-800 text-white py-4 rounded-2xl font-bold text-lg hover:bg-nature-900 transition-all shadow-lg active:scale-95"
          >
            Compreendo e aceito
          </button>
        </div>
      </div>
    );
  }

  if (step === 'result') {
     const score = calculateScore();
     let message = "";
     let color = "";

     if (score < 10) {
        message = "Baixa probabilidade de sensibilidade, mas a reconexão alimentar sempre traz clareza.";
        color = "text-green-600";
     } else if (score < 25) {
        message = "Sintomas moderados. Sua essência pode estar reagindo a inflamatórios comuns.";
        color = "text-yellow-600";
     } else {
        message = "Alta indicação de sensibilidade. Seu corpo está pedindo por um período de descanso.";
        color = "text-orange-600";
     }

     return (
        <div className="p-6 flex flex-col items-center justify-center min-h-[80vh] animate-in fade-in duration-700">
            <div className="w-20 h-20 bg-nature-100 rounded-full flex items-center justify-center mb-6">
               <Sparkles className="text-nature-600" size={40} />
            </div>

            <h2 className="text-3xl font-serif text-nature-800 mb-2">Sua Jornada Começa</h2>
            <div className="text-6xl font-bold text-nature-600 mb-4 tabular-nums">{score} <span className="text-lg text-gray-400 font-normal">pts</span></div>
            <p className={`text-center text-base mb-8 ${color} font-medium max-w-xs`}>{message}</p>

            <div className="w-full max-w-xs space-y-4 mb-8">
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <User size={18} className="text-nature-300" />
                </div>
                <input
                  type="text"
                  placeholder="Como devemos te chamar?"
                  value={userName}
                  onChange={(e) => setUserName(e.target.value)}
                  className="block w-full pl-10 pr-3 py-3 border border-nature-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-nature-500 focus:border-nature-500 sm:text-sm transition-all shadow-inner"
                />
              </div>
              <p className="text-center text-gray-400 text-[10px] italic">
                O ciclo de 21 dias focará em "limpar" o organismo e silenciar ruídos inflamatórios.
              </p>
            </div>

            <button 
                className="w-full max-w-xs bg-nature-600 text-white py-4 rounded-2xl font-bold shadow-xl shadow-nature-100 hover:bg-nature-700 active:scale-95 transition-all flex items-center justify-center gap-2 mb-6"
                onClick={handleStartJourney}
            >
                <CheckCircle size={20} /> Iniciar 21 Dias
            </button>

            <div className="max-w-xs text-center border-t border-nature-100 pt-6">
              <p className="text-nature-400 text-[10px] leading-relaxed italic">
                Nota: Os resultados acima refletem percepções de consciência corporal coletadas pelo teste e não constituem um diagnóstico clínico. Consulte sempre um profissional de saúde qualificado.
              </p>
            </div>
        </div>
     )
  }

  return (
    <div className="min-h-screen bg-sand-50">
      <div className="sticky top-0 z-30 bg-sand-50/95 backdrop-blur-md border-b border-nature-100 p-4 space-y-4">
        <header className="pt-2 flex justify-between items-end">
          <div>
            <h2 className="text-2xl font-serif text-nature-800">Sinais do Corpo</h2>
            <p className="text-nature-600 text-xs font-medium italic">O que sua essência tenta dizer?</p>
          </div>
          <div className="bg-nature-800 text-white px-3 py-1.5 rounded-xl text-[10px] font-bold">
            {selectedSymptoms.length} Sinais
          </div>
        </header>

        {/* Search Bar */}
        <div className="relative group">
          <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
            <Search size={16} className="text-nature-400 group-focus-within:text-nature-600 transition-colors" />
          </div>
          <input
            type="text"
            placeholder="Buscar sintoma ou sinal..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-10 py-3 bg-white border border-nature-100 rounded-2xl text-sm focus:outline-none focus:ring-4 focus:ring-nature-100/50 transition-all shadow-sm"
          />
          {searchQuery && (
            <button 
              onClick={() => setSearchQuery('')}
              className="absolute inset-y-0 right-3 flex items-center text-nature-300 hover:text-nature-500"
            >
              <X size={16} />
            </button>
          )}
        </div>

        {/* Category Filter with Counters */}
        <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
          {CATEGORIES.map((cat) => {
            const stats = cat.id === 'todos' ? null : getCategoryStats(cat.id);
            const totalSelected = selectedSymptoms.length;
            const CategoryIcon = cat.icon;

            return (
              <button
                key={cat.id}
                onClick={() => setActiveCategory(cat.id)}
                className={`whitespace-nowrap px-4 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border flex items-center gap-2 shadow-sm ${
                  activeCategory === cat.id 
                    ? 'bg-nature-800 text-white border-nature-800' 
                    : 'bg-white text-nature-400 border-nature-50 hover:border-nature-200'
                }`}
              >
                <CategoryIcon size={14} />
                {cat.label}
                {cat.id === 'todos' ? (
                  totalSelected > 0 && (
                    <span className="bg-nature-500 text-white px-1.5 py-0.5 rounded-lg text-[8px] font-bold">
                      {totalSelected}
                    </span>
                  )
                ) : (
                  <span className={`px-1.5 py-0.5 rounded-lg text-[8px] font-bold ${activeCategory === cat.id ? 'bg-white/20 text-white' : 'bg-nature-50 text-nature-400'}`}>
                    {stats?.selected} / {stats?.total}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      <div className="p-4 pb-48 space-y-10">
        {Object.keys(groupedFilteredSymptoms).length > 0 ? (
          CATEGORIES.filter(c => c.id !== 'todos' && groupedFilteredSymptoms[c.id]).map((cat) => (
            <section key={cat.id} className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
              <div className="flex items-center justify-between px-2">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-white rounded-xl shadow-sm border border-nature-50">
                      <cat.icon size={16} className="text-nature-400" />
                   </div>
                   <h3 className="text-lg font-serif text-nature-900 tracking-tight">
                    {cat.label}
                  </h3>
                </div>
                <div className="text-right">
                  <span className="text-[10px] font-black text-nature-300 uppercase tracking-widest block">
                    {getCategoryStats(cat.id).selected} selecionados
                  </span>
                  <div className="w-20 h-1 bg-nature-100 rounded-full mt-1 overflow-hidden">
                    <div 
                      className="h-full bg-nature-500 transition-all duration-700" 
                      style={{ width: `${(getCategoryStats(cat.id).selected / getCategoryStats(cat.id).total) * 100}%` }}
                    />
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-3">
                {groupedFilteredSymptoms[cat.id].map((symptom) => (
                  <div 
                    key={symptom.id}
                    onClick={() => handleToggleSymptom(symptom.id)}
                    className={`p-5 rounded-[1.8rem] border-2 flex items-center justify-between cursor-pointer transition-all duration-300 ${
                      selectedSymptoms.includes(symptom.id) 
                        ? 'bg-nature-50 border-nature-600 shadow-lg translate-y-[-2px]' 
                        : 'bg-white border-nature-50 hover:border-nature-100'
                    }`}
                  >
                    <div className="flex-1 pr-4">
                      <p className={`font-bold text-[15px] transition-colors leading-tight ${selectedSymptoms.includes(symptom.id) ? 'text-nature-900' : 'text-gray-700'}`}>
                        {symptom.name}
                      </p>
                    </div>
                    <div className={`w-7 h-7 rounded-2xl border-2 flex items-center justify-center transition-all shrink-0 ${selectedSymptoms.includes(symptom.id) ? 'bg-nature-800 border-nature-800 rotate-12' : 'border-nature-100'}`}>
                      {selectedSymptoms.includes(symptom.id) ? <CheckCircle className="text-white" size={18} /> : <div className="w-2 h-2 rounded-full bg-nature-50" />}
                    </div>
                  </div>
                ))}
              </div>
            </section>
          ))
        ) : (
          <div className="text-center py-24 flex flex-col items-center gap-6 animate-in fade-in">
            <div className="p-6 bg-white rounded-full shadow-inner border border-nature-50 text-nature-200">
              <Search size={48} />
            </div>
            <div className="space-y-1">
              <p className="text-nature-900 font-serif text-lg">Nenhum sinal encontrado.</p>
              <p className="text-nature-400 text-sm italic">Sua busca não revelou padrões conhecidos.</p>
