            <button 
              onClick={() => { setSearchQuery(''); setActiveCategory('todos'); }}
              className="px-6 py-2 bg-nature-50 text-nature-800 rounded-full font-bold text-xs uppercase tracking-widest border border-nature-100"
            >
              Limpar Filtros
            </button>
          </div>
        )}

        <div className="text-center pt-8 pb-12 border-t border-nature-50">
           <p className="text-[10px] text-nature-300 font-medium italic max-w-xs mx-auto">
             Este quiz é uma ferramenta de mapeamento de consciência corporal. Agradecemos sua honestidade consigo mesmo.
           </p>
