    if (!currentAudioBuffer) return;
    const newOffset = Math.max(0, Math.min(duration, currentTime + seconds));
    setCurrentTime(newOffset);
    if (isPlaying) {
      playAudio(currentAudioBuffer, newOffset);
    } else {
      offsetRef.current = newOffset;
    }
  };

