                    {ritualStep === 'forgiving' && "Diga para quem te feriu: Eu te perdoo porque você deu o seu melhor naquele momento."}
                    {ritualStep === 'affirming' && "Diga para si: Foi muito doloroso, mas eu sobrevivi e me tornei muito mais forte e resiliente."}
                    {ritualStep === 'checking' && "Visualize a cena novamente. Se ainda houver dor, repetiremos o ciclo para limpar sua alma."}
                 </p>
               </div>

               {ritualStep === 'checking' && (
                 <div className="grid grid-cols-1 gap-4 w-full animate-in fade-in slide-in-from-bottom-2">
                    <button onClick={() => runRitualCycle()} className="w-full bg-nature-100 text-nature-800 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-nature-200 transition-all">
                       <RotateCcw size={20} /> Ainda sinto dor (Nova Camada)
                    </button>
                    <button onClick={() => setRitualStep('idle')} className="w-full bg-nature-800 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-nature-100 transition-transform active:scale-95">
                       <CheckCircle size={20} /> Estou em Paz e Soberano
                    </button>
