function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number = 24000, numChannels: number = 1): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const Wellness: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'breathing' | 'meditation' | 'emotional' | 'healing-ritual'>('breathing');
  const [generatedContent, setGeneratedContent] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [loadingAudio, setLoadingAudio] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);

  // Audio Player State
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1);
  const [currentAudioBuffer, setCurrentAudioBuffer] = useState<AudioBuffer | null>(null);

  const progressAnimationRef = useRef<number | null>(null);
  const startTimeRef = useRef<number>(0);
  const offsetRef = useRef<number>(0);

  // Ritual State
  const [ritualStep, setRitualStep] = useState<'idle' | 'preparing' | 'feeling' | 'affirming' | 'forgiving' | 'checking'>('idle');
  const [ritualAudio, setRitualAudio] = useState<{ [key: string]: AudioBuffer | null }>({});
  const [isEyesClosed, setIsEyesClosed] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const sourceRef = useRef<AudioBufferSourceNode | null>(null);

  const initAudioContext = async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      gainNodeRef.current = audioContextRef.current.createGain();
      gainNodeRef.current.gain.value = 1.8;
      gainNodeRef.current.connect(audioContextRef.current.destination);
    }
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }
  };

  const updateProgress = () => {
    if (!audioContextRef.current || !isPlaying) return;

    const now = audioContextRef.current.currentTime;
    const elapsed = (now - startTimeRef.current) * playbackRate;
    const newTime = offsetRef.current + elapsed;

    setCurrentTime(Math.min(newTime, duration));

    if (newTime < duration) {
      progressAnimationRef.current = requestAnimationFrame(updateProgress);
    } else {
      setIsPlaying(false);
      setCurrentTime(duration);
    }
  };

  const playAudio = async (buffer: AudioBuffer, startOffset: number = 0): Promise<void> => {
    await initAudioContext();
    stopAudioSource();

    const source = audioContextRef.current!.createBufferSource();
    source.buffer = buffer;
    source.playbackRate.value = playbackRate;

    if (gainNodeRef.current) {
      source.connect(gainNodeRef.current);
    }

    setCurrentAudioBuffer(buffer);
    setDuration(buffer.duration);
    offsetRef.current = startOffset;
    startTimeRef.current = audioContextRef.current!.currentTime;

    source.onended = () => {
      const now = audioContextRef.current!.currentTime;
      const totalElapsed = offsetRef.current + (now - startTimeRef.current) * playbackRate;
      if (totalElapsed >= buffer.duration - 0.1) {
        setIsPlaying(false);
        if (progressAnimationRef.current) cancelAnimationFrame(progressAnimationRef.current);
      }
    };

    source.start(0, startOffset);
    sourceRef.current = source;
    setIsPlaying(true);

    progressAnimationRef.current = requestAnimationFrame(updateProgress);
  };

  const stopAudioSource = () => {
    if (sourceRef.current) {
      try {
        sourceRef.current.stop();
        sourceRef.current.disconnect();
      } catch (e) {}
      sourceRef.current = null;
    }
    if (progressAnimationRef.current) {
      cancelAnimationFrame(progressAnimationRef.current);
    }
  };

  const stopAudioFull = () => {
    stopAudioSource();
    setIsPlaying(false);
    setCurrentTime(0);
    offsetRef.current = 0;
  };

  const handleSeek = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!currentAudioBuffer) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const percentage = x / rect.width;
    const newOffset = percentage * duration;

    setCurrentTime(newOffset);
    if (isPlaying) {
      playAudio(currentAudioBuffer, newOffset);
    } else {
      offsetRef.current = newOffset;
    }
  };

  const handleSkip = (seconds: number) => {
    if (!currentAudioBuffer) return;
    const newOffset = Math.max(0, Math.min(duration, currentTime + seconds));
    setCurrentTime(newOffset);
    if (isPlaying) {
      playAudio(currentAudioBuffer, newOffset);
    } else {
      offsetRef.current = newOffset;
    }
  };

  const handleRateChange = (newRate: number) => {
    setPlaybackRate(newRate);
    if (isPlaying && currentAudioBuffer) {
      playAudio(currentAudioBuffer, currentTime);
    }
  };

  const handleTabChange = (tab: any) => {
    setActiveTab(tab);
    setRitualStep('idle');
    stopAudioFull();
    setGeneratedContent(null);
    setCurrentAudioBuffer(null);
  };

  const formatTime = (time: number) => {
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes}:${seconds.toString().padStart(2, '0')}`;
  };

  // Helper to render the shared Advanced Player UI
  const renderAdvancedPlayer = () => {
    if (!generatedContent || !currentAudioBuffer) return null;

    return (
      <div className="bg-nature-900 rounded-[3rem] p-8 shadow-2xl space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="flex items-center justify-between text-white/60 text-[10px] font-black uppercase tracking-widest px-1">
           <div className="flex items-center gap-2"><Headphones size={14} /> Áudio Espiritual</div>
           <div className="bg-white/10 px-2 py-0.5 rounded-md tabular-nums">{formatTime(currentTime)} / {formatTime(duration)}</div>
        </div>

        <div 
          className="relative h-3 bg-white/10 rounded-full cursor-pointer group overflow-hidden"
          onClick={handleSeek}
        >
          <div 
            className="absolute inset-y-0 left-0 bg-nature-400 group-hover:bg-nature-300 transition-all duration-100 ease-linear rounded-full"
            style={{ width: `${(currentTime / duration) * 100}%` }}
          />
          <div 
            className="absolute top-1/2 -translate-y-1/2 w-1 h-full bg-white opacity-0 group-hover:opacity-50"
            style={{ left: `${(currentTime / duration) * 100}%` }}
