                 <Play size={20} fill="currentColor" /> Iniciar Rito Sagrado
               </button>
            </div>
          ) : (
            <div className="bg-white p-10 rounded-[3rem] border border-nature-100 shadow-xl flex flex-col items-center text-center space-y-8 animate-in zoom-in duration-700">
               <div className="relative">
                 <div className={`w-28 h-28 rounded-full flex items-center justify-center transition-all duration-1000 ${isEyesClosed ? 'bg-nature-900 shadow-[0_0_30px_rgba(0,0,0,0.1)]' : 'bg-nature-100'}`}>
                    {isEyesClosed ? <EyeOff size={40} className="text-white animate-pulse" /> : <Eye size={40} className="text-nature-500" />}
                 </div>
                 {loading && <div className="absolute inset-0 flex items-center justify-center"><Loader2 className="text-nature-800 animate-spin" /></div>}
               </div>
               <h4 className="font-serif text-2xl text-nature-900">
                  {ritualStep === 'feeling' && "Acolha a Dor"}
                  {ritualStep === 'forgiving' && "O Poder do Perdão"}
                  {ritualStep === 'affirming' && "Reconhecimento de Si"}
                  {ritualStep === 'checking' && "Verificação de Paz"}
               </h4>
               <div className="min-h-[100px] flex items-center justify-center px-4">
                 <p className="text-nature-600 text-lg italic leading-relaxed font-light">
                    {ritualStep === 'feeling' && "Feche os olhos. Entre em contato com sua maior dor. Veja quem te feriu."}
                    {ritualStep === 'forgiving' && "Diga para quem te feriu: Eu te perdoo porque você deu o seu melhor naquele momento."}
                    {ritualStep === 'affirming' && "Diga para si: Foi muito doloroso, mas eu sobrevivi e me tornei muito mais forte e resiliente."}
                    {ritualStep === 'checking' && "Visualize a cena novamente. Se ainda houver dor, repetiremos o ciclo para limpar sua alma."}
                 </p>
               </div>
               {ritualStep === 'checking' && (
                 <div className="grid grid-cols-1 gap-4 w-full animate-in fade-in slide-in-from-bottom-2">
                    <button onClick={() => runRitualCycle()} className="w-full bg-nature-100 text-nature-800 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-nature-200 transition-all"><RotateCcw size={20} /> Ainda sinto dor (Nova Camada)</button>
                    <button onClick={() => setRitualStep('idle')} className="w-full bg-nature-800 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-nature-100 transition-transform active:scale-95"><CheckCircle size={20} /> Estou em Paz e Soberano</button>
                 </div>
               )}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

