                  {post.commentList && post.commentList.length > 0 ? (
                    getGroupedComments(post.commentList).map((group) => (
                      <div key={group.dateKey} className="space-y-4">
                        {/* Date Header */}
                        <div className="flex items-center gap-4 py-1">
                          <div className="flex-1 h-px bg-nature-100"></div>
                          <span className="text-[10px] font-black text-nature-300 uppercase tracking-[0.2em] px-2">
                            {formatDateHeader(group.timestamp)}
                          </span>
                          <div className="flex-1 h-px bg-nature-100"></div>
                        </div>

                        {/* Comments List */}
                        <div className="space-y-4">
                          {group.items.map(comment => (
                            <div key={comment.id} className="flex gap-4 items-start group/comment animate-in fade-in duration-300">
                              <img src={comment.avatar} className="w-9 h-9 rounded-full object-cover shrink-0 border-2 border-white shadow-sm transition-transform group-hover/comment:scale-110" alt={comment.author} />
                              <div className="bg-white p-4 rounded-2xl rounded-tl-none shadow-sm text-sm flex-1 border border-nature-100/50 transition-all hover:shadow-md">
                                <div className="flex justify-between items-center mb-1.5">
