export const analyzeUserLogs = async (logs: DailyLog[]) => {
  try {
    const logsText = logs.slice(-5).map(l => 
      `Dia ${l.date}: Sintomas[${l.symptomsPresent.join(', ')}]. Vibração[${l.mood}/5]. Ações: ${JSON.stringify(l.completedActions)}.`
    ).join('\n');

    const prompt = `
      Atue como um Oráculo de Sabedoria Ancestral. Analise estes registros de jornada:
      ${logsText}

      Traduza os sintomas físicos em mensagens da alma. Identifique o padrão espiritual.
      Responda com um "Insight de Ascensão" poético e profundo (máx 200 caracteres). 
      Fale sobre energia, fluxo e o despertar do poder interior.
    `;

    const response = await ai.models.generateContent({ model: modelId, contents: prompt });
    return response.text;
  } catch (e) {
    return "Sua luz interior está limpando os canais antigos. Permaneça em silêncio e observe a transformação.";
  }
}

export const generateSpeech = async (text: string) => {
  try {
    const styledText = `Diga com uma voz suave, clara, pausada e profundamente acolhedora: ${text}`;

    const response = await ai.models.generateContent({
      model: ttsModelId,
      contents: [{ parts: [{ text: styledText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    console.error("Erro no TTS:", error);
    return null;
  }
};

export const generateAffirmation = async (feeling: string) => {
