const Guidance: React.FC = () => {
  const [content, setContent] = useState<DailyContent | null>(null);
  const [loading, setLoading] = useState(true);
  const [sharingId, setSharingId] = useState<number | null>(null);
  const [refreshingIds, setRefreshingIds] = useState<Set<number>>(new Set());

  useEffect(() => {
    const load = async () => {
        setLoading(true);
        const data = await generateDailyContent();
        setContent(data);
        setLoading(false);
    };
    load();
  }, []);

  const handleShare = async (recipe: Recipe, index: number) => {
    const shareText = `Confira esta receita da Alquimia Nutritiva no ReViva: ${recipe.title}. Ingredientes: ${recipe.ingredients.join(', ')}.`;
    const shareUrl = `https://reviva.app/receitas/${recipe.title.toLowerCase().replace(/\s+/g, '-')}`;

    setSharingId(index);

    if (navigator.share) {
      try {
        await navigator.share({
          title: `ReViva - ${recipe.title}`,
          text: shareText,
          url: shareUrl,
        });
      } catch (err) {
        console.log('Erro ao compartilhar ou cancelado:', err);
      } finally {
        setSharingId(null);
      }
    } else {
      try {
        await navigator.clipboard.writeText(`${shareText} Link: ${shareUrl}`);
        alert('Conteúdo da receita copiado para a área de transferência! ✨');
      } catch (err) {
        console.error('Falha ao copiar:', err);
      } finally {
        setTimeout(() => setSharingId(null), 2000);
      }
    }
  };

  const handleRefreshRecipe = async (index: number, mealType: string) => {
    if (refreshingIds.has(index)) return;

    setRefreshingIds(prev => new Set(prev).add(index));

    try {
      const newRecipe = await generateSingleRecipe(mealType);

      setContent(prev => {
        if (!prev) return null;
        const newMenu = [...prev.menu];
        newMenu[index] = newRecipe;
        return { ...prev, menu: newMenu };
      });
    } catch (error) {
      console.error("Erro ao trocar receita:", error);
    } finally {
      setRefreshingIds(prev => {
        const next = new Set(prev);
        next.delete(index);
        return next;
      });
    }
  };

  if (loading) {
    return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-4">
            <div className="relative w-16 h-16">
              <div className="absolute inset-0 border-4 border-nature-100 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-nature-500 rounded-full border-t-transparent animate-spin"></div>
            </div>
            <p className="text-nature-600 font-serif italic animate-pulse">Tecendo o menu da sua alma...</p>
        </div>
    );
  }

  return (
    <div className="p-6 pb-28 max-w-2xl mx-auto space-y-10 animate-in fade-in duration-1000">
       <header className="space-y-1">
          <h2 className="text-3xl font-serif text-nature-900 leading-tight">Guia da Essência</h2>
          <p className="text-nature-500 text-sm font-medium">Alimento para as células e para o espírito.</p>
       </header>

      {/* Mantra Card */}
      <section className="bg-sand-100/50 p-8 rounded-[3rem] border border-sand-200 relative overflow-hidden group">
        <Sun className="text-sand-300 absolute -top-4 -right-4 w-32 h-32 opacity-10 group-hover:scale-110 transition-transform duration-1000" />
        <div className="relative z-10 space-y-4">
          <div className="flex items-center gap-2 text-[10px] font-bold text-sand-600 uppercase tracking-[0.2em]">
            <Sparkles size={14} /> Mantra do Dia
          </div>
          <p className="text-xl font-serif text-sand-900 leading-relaxed italic">
            "{content?.motivation}"
          </p>
        </div>
      </section>

      {/* Ritual Challenge */}
      <section className="bg-nature-50 p-6 rounded-[2.5rem] border border-nature-100 flex items-center gap-5">
         <div className="w-14 h-14 bg-white rounded-2xl flex items-center justify-center shadow-sm shrink-0">
            <Footprints className="text-nature-600" size={28} />
         </div>
         <div className="space-y-1">
            <h3 className="font-bold text-nature-900 text-sm">Ritual de Conexão</h3>
            <p className="text-nature-600 text-xs leading-relaxed">{content?.dailyChallenge}</p>
         </div>
      </section>

      {/* Recipes */}
      <section className="space-y-8">
        <h3 className="text-2xl font-serif text-nature-900 px-2 flex items-center gap-3">
          <Utensils size={24} className="text-nature-400" /> Alquimia Nutritiva
        </h3>

        <div className="space-y-8">
          {content?.menu.map((recipe, index) => (
            <div key={index} className="relative bg-white rounded-[2.5rem] shadow-sm border border-nature-50 overflow-hidden group hover:shadow-xl transition-all duration-500">

               {/* Overlay de carregamento individual */}
               {refreshingIds.has(index) && (
                 <div className="absolute inset-0 bg-white/70 backdrop-blur-[2px] z-20 flex flex-col items-center justify-center animate-in fade-in duration-300">
                    <Loader2 className="text-nature-600 animate-spin mb-2" size={32} />
