                            <div className="w-1 h-1 bg-nature-300 rounded-full"></div>
                            {ing}
                          </li>
                        ))}
                      </ul>
                    </div>

                    <div className="space-y-4">
                      <h5 className="text-[10px] font-bold text-nature-400 uppercase tracking-widest flex items-center gap-2">
                        <Sparkles size={14} /> Processo
                      </h5>
                      <div className="space-y-3">
                        {recipe.instructions.map((inst, i) => (
                          <p key={i} className="text-xs text-nature-600 leading-relaxed pl-4 border-l border-nature-100">
                            {inst}
