type FilterType = 'recent' | 'liked' | 'following';

const Community: React.FC = () => {
  const [posts, setPosts] = useState<CommunityPost[]>(MOCK_POSTS);
  const [activeFilter, setActiveFilter] = useState<FilterType>('recent');
  const [likedPosts, setLikedPosts] = useState<Set<string>>(new Set());
  const [followedAuthors, setFollowedAuthors] = useState<Set<string>>(new Set());
  const [expandedComments, setExpandedComments] = useState<Set<string>>(new Set());
  const [commentInputs, setCommentInputs] = useState<{ [key: string]: string }>({});
  const [newPost, setNewPost] = useState('');
  const [newCaption, setNewCaption] = useState('');

  const [editingCaptionId, setEditingCaptionId] = useState<string | null>(null);
  const [editCaptionValue, setEditCaptionValue] = useState('');

  const [selectedVideo, setSelectedVideo] = useState<File | null>(null);
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [mediaPreview, setMediaPreview] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [isSharing, setIsSharing] = useState<string | null>(null);

  const [menuOpenPostId, setMenuOpenPostId] = useState<string | null>(null);
  const [reportingPostId, setReportingPostId] = useState<string | null>(null);

  const videoInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const commentInputRefs = useRef<{ [key: string]: HTMLInputElement | null }>({});

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (activeFilter === 'recent') {
      result.sort((a, b) => b.timestamp - a.timestamp);
    } else if (activeFilter === 'liked') {
      result.sort((a, b) => b.likes - a.likes);
    } else if (activeFilter === 'following') {
      result = result.filter(post => followedAuthors.has(post.author) || post.author === 'Você' || post.author === 'Guia Essência');
      result.sort((a, b) => b.timestamp - a.timestamp);
    }
    return result;
  }, [posts, activeFilter, followedAuthors]);

  const formatDateHeader = (timestamp: number) => {
    const date = new Date(timestamp);
    const today = new Date();
    const yesterday = new Date();
    yesterday.setDate(today.getDate() - 1);
    if (date.toDateString() === today.toDateString()) return 'Hoje';
    if (date.toDateString() === yesterday.toDateString()) return 'Ontem';
    return date.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric' });
  };

  const getGroupedComments = (comments: Comment[] = []) => {
    const sorted = [...comments].sort((a, b) => a.timestamp - b.timestamp);
    const groups: { dateKey: string; timestamp: number; items: Comment[] }[] = [];
    sorted.forEach(comment => {
      const dateKey = new Date(comment.timestamp).toDateString();
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.dateKey === dateKey) {
        lastGroup.items.push(comment);
      } else {
        groups.push({ dateKey, timestamp: comment.timestamp, items: [comment] });
      }
    });
    return groups;
  };

  const handleLike = (postId: string) => {
    const isAlreadyLiked = likedPosts.has(postId);
    setPosts(prevPosts =>
      prevPosts.map(post => post.id === postId ? {
        ...post,
        likes: isAlreadyLiked ? post.likes - 1 : post.likes + 1
      } : post)
    );
    setLikedPosts(prev => {
      const next = new Set(prev);
      if (isAlreadyLiked) next.delete(postId);
      else next.add(postId);
      return next;
    });
  };

  const toggleFollow = (authorName: string) => {
    setFollowedAuthors(prev => {
      const next = new Set(prev);
      if (next.has(authorName)) next.delete(authorName);
      else next.add(authorName);
      return next;
    });
  };

  const toggleComments = (postId: string) => {
    const isExpanding = !expandedComments.has(postId);
    setExpandedComments(prev => {
      const next = new Set(prev);
      if (next.has(postId)) next.delete(postId);
      else next.add(postId);
      return next;
    });
    if (isExpanding) {
      setTimeout(() => commentInputRefs.current[postId]?.focus(), 300);
    }
  };

  const handleCommentSubmit = (postId: string) => {
    const text = commentInputs[postId];
    if (!text?.trim()) return;
    const newComment: Comment = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      text: text,
      timestamp: Date.now()
    };
    setPosts(prevPosts =>
      prevPosts.map(post => post.id === postId ? {
        ...post,
        comments: (post.commentList?.length || 0) + 1,
        commentList: [...(post.commentList || []), newComment]
      } : post)
    );
    setCommentInputs(prev => ({ ...prev, [postId]: '' }));
    if (!expandedComments.has(postId)) {
      setExpandedComments(prev => new Set(prev).add(postId));
    }
  };

  const handlePost = async () => {
    if (!newPost.trim() && !selectedVideo && !selectedImage) return;
    setIsUploading(true);
    await new Promise(r => setTimeout(r, 800));
    let videoUrl: string | undefined = undefined;
    let imageUrl: string | undefined = undefined;
    if (selectedVideo) videoUrl = URL.createObjectURL(selectedVideo);
    if (selectedImage) imageUrl = URL.createObjectURL(selectedImage);
    const post: CommunityPost = {
      id: Date.now().toString(),
      author: 'Você',
      avatar: 'https://picsum.photos/50/50?random=99',
      content: newPost,
      likes: 0,
      comments: 0,
      commentList: [],
      timestamp: Date.now(),
      video: videoUrl,
      image: imageUrl,
      caption: (selectedVideo || selectedImage) ? newCaption : undefined
    };
    setPosts([post, ...posts]);
    setNewPost('');
    setNewCaption('');
    setSelectedVideo(null);
    setSelectedImage(null);
    setMediaPreview(null);
    setIsUploading(false);
    setActiveFilter('recent');
  };

  const handleVideoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedVideo(file);
      setSelectedImage(null);
      setMediaPreview(URL.createObjectURL(file));
    }
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedImage(file);
      setSelectedVideo(null);
      setMediaPreview(URL.createObjectURL(file));
    }
  };

  const clearMedia = () => {
    setSelectedVideo(null);
    setSelectedImage(null);
    setMediaPreview(null);
    setNewCaption('');
  };

  const startEditingCaption = (post: CommunityPost) => {
    setEditingCaptionId(post.id);
    setEditCaptionValue(post.caption || '');
  };

  const saveCaption = (postId: string) => {
    setPosts(prev => prev.map(p => p.id === postId ? { ...p, caption: editCaptionValue } : p));
    setEditingCaptionId(null);
  };

  const handleShare = async (post: CommunityPost) => {
    const shareUrl = `https://reviva.app/tribo/${post.id}`;
    const shareData: any = {
      title: 'Tribo Essência - ReViva',
      text: `${post.author} compartilhou na Tribo Essência: "${post.content.substring(0, 80)}..."`,
      url: shareUrl,
    };
    const mediaUrl = post.image || post.video;
    setIsSharing(post.id);
    try {
      if (navigator.share) {
        if (mediaUrl) {
          try {
            const response = await fetch(mediaUrl);
            const blob = await response.blob();
            const extension = post.image ? 'png' : 'mp4';
            const fileName = `media-${post.id}.${extension}`;
            const file = new File([blob], fileName, { type: blob.type });
            if (navigator.canShare && navigator.canShare({ files: [file] })) {
              shareData.files = [file];
            }
          } catch (fetchError) {
            console.warn("Mídia não pôde ser incluída no compartilhamento.", fetchError);
          }
        }
        await navigator.share(shareData);
      } else {
        await navigator.clipboard.writeText(shareUrl);
        alert("Link da postagem copiado!");
      }
    } catch (err) {
      if ((err as Error).name !== 'AbortError') console.error('Erro ao compartilhar:', err);
    } finally {
      setIsSharing(null);
    }
  };

  const confirmReport = () => {
    alert("Obrigado. Nossa equipe de moderação analisará esta postagem em breve.");
    setReportingPostId(null);
  };

  return (
    <div className="p-4 pb-24 max-w-2xl mx-auto space-y-6 bg-sand-50/30">
      <header className="flex flex-col gap-1">
        <h2 className="text-3xl font-serif text-nature-800 tracking-tight">Tribo Essência</h2>
        <p className="text-nature-600 text-sm font-medium">Compartilhe sua jornada e inspire outros corações.</p>
      </header>

      {/* New Post Input */}
      <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-nature-100/50 transition-all hover:shadow-md">
        <div className="flex gap-3 mb-4">
          <img src="https://picsum.photos/50/50?random=99" className="w-10 h-10 rounded-full border-2 border-nature-50 shadow-sm" alt="Você" />
          <textarea
            className="w-full bg-sand-50/50 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-nature-200 outline-none resize-none border border-transparent focus:border-nature-100 transition-all placeholder:text-nature-300"
            placeholder="O que sua essência quer dizer hoje?"
            rows={3}
            value={newPost}
            onChange={(e) => setNewPost(e.target.value)}
          />
        </div>

        {mediaPreview && (
          <div className="mt-2 mb-4 relative rounded-2xl overflow-hidden border border-nature-200 shadow-inner group">
            {selectedVideo ? (
              <video src={mediaPreview} className="w-full h-56 object-cover" />
            ) : (
              <img src={mediaPreview} className="w-full h-56 object-cover" alt="Preview" />
            )}
            <button onClick={clearMedia} className="absolute top-3 right-3 p-1.5 bg-black/60 text-white rounded-full backdrop-blur-sm transition-transform hover:scale-110">
              <X size={16} />
            </button>
            <div className="absolute bottom-0 left-0 w-full p-3 bg-gradient-to-t from-black/80 to-transparent">
              <input
                className="w-full p-2 text-xs bg-transparent text-white border-b border-white/20 focus:border-white focus:outline-none placeholder:text-white/60"
                placeholder="Escreva uma legenda poética..."
                value={newCaption}
                onChange={(e) => setNewCaption(e.target.value)}
              />
            </div>
          </div>
        )}

        <div className="flex justify-between items-center border-t border-nature-50 pt-4">
          <div className="flex gap-1">
            <button onClick={() => imageInputRef.current?.click()} className="p-2.5 text-nature-500 hover:bg-nature-50 hover:text-nature-700 rounded-full transition-all group">
              <ImageIcon size={22} className="group-active:scale-90" />
              <input type="file" ref={imageInputRef} hidden accept="image/*" onChange={handleImageSelect} />
            </button>
            <button onClick={() => videoInputRef.current?.click()} className="p-2.5 text-nature-500 hover:bg-nature-50 hover:text-nature-700 rounded-full transition-all group">
              <VideoIcon size={22} className="group-active:scale-90" />
              <input type="file" ref={videoInputRef} hidden accept="video/*" onChange={handleVideoSelect} />
            </button>
          </div>
          <button 
            onClick={handlePost}
            disabled={isUploading || (!newPost.trim() && !mediaPreview)}
            className="bg-nature-600 text-white px-8 py-2.5 rounded-full font-bold text-sm shadow-lg shadow-nature-100 hover:bg-nature-700 active:scale-95 disabled:opacity-50 disabled:grayscale transition-all flex items-center gap-2"
          >
            {isUploading ? <><Sparkles size={16} className="animate-spin" /> Postando...</> : <><Send size={16} /> Compartilhar</>}
          </button>
        </div>
      </div>

      {/* Feed Filters */}
      <div className="flex gap-2 px-1">
        {(['recent', 'liked', 'following'] as FilterType[]).map(f => (
          <button
            key={f}
            onClick={() => setActiveFilter(f)}
            className={`px-5 py-2.5 rounded-full text-xs font-bold transition-all border ${
              activeFilter === f 
                ? 'bg-nature-800 text-white border-nature-800 shadow-md' 
                : 'bg-white text-nature-500 border-nature-100 hover:border-nature-300 hover:text-nature-700'
            }`}
          >
            {f === 'recent' ? 'Recentes' : f === 'liked' ? 'Populares' : 'Tribo Seguida'}
          </button>
        ))}
      </div>

      {/* Posts List */}
      <div className="space-y-8">
        {filteredPosts.map(post => (
          <div key={post.id} className="bg-white rounded-[2.5rem] shadow-sm border border-nature-50 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500 relative">
            <div className="p-5 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="relative">
                  <img src={post.avatar} className="w-12 h-12 rounded-full object-cover border-2 border-nature-50" alt={post.author} />
                  <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-nature-600 rounded-full border-2 border-white flex items-center justify-center">
                    <Check size={10} className="text-white" strokeWidth={4} />
                  </div>
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <h4 className="font-bold text-nature-900 text-[15px]">{post.author}</h4>
                    {post.author !== 'Você' && (
                      <button 
                        onClick={() => toggleFollow(post.author)}
                        className={`ml-2 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest transition-all duration-300 transform active:scale-95 ${
                          followedAuthors.has(post.author) 
                            ? 'bg-nature-900 text-white shadow-lg ring-1 ring-nature-900' 
                            : 'bg-nature-50 text-nature-600 border border-nature-100 hover:bg-nature-100 hover:border-nature-200'
                        }`}
                      >
                        {followedAuthors.has(post.author) ? 'Seguindo' : 'Seguir'}
                      </button>
                    )}
                  </div>
                  <div className="flex items-center gap-1.5 text-[10px] text-nature-300 font-bold uppercase tracking-wider">
                    <Clock size={10} /> {new Date(post.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-1">
                <div className="relative">
                  <button 
                    onClick={() => setMenuOpenPostId(menuOpenPostId === post.id ? null : post.id)}
                    className="p-2.5 text-nature-300 hover:text-nature-600 hover:bg-nature-50 rounded-full transition-all"
                  >
                    <MoreVertical size={20} />
                  </button>
                  {menuOpenPostId === post.id && (
                    <div className="absolute right-0 top-full mt-1 w-48 bg-white border border-nature-100 rounded-2xl shadow-xl z-20 animate-in fade-in zoom-in-95 duration-200 overflow-hidden">
                      <button 
                        onClick={() => {
                          setReportingPostId(post.id);
                          setMenuOpenPostId(null);
                        }}
                        className="w-full flex items-center gap-3 px-4 py-3 text-sm text-red-600 hover:bg-red-50 transition-colors text-left"
                      >
                        <AlertCircle size={16} />
                        Denunciar postagem
                      </button>
                      {post.author === 'Você' && (
                         <button className="w-full flex items-center gap-3 px-4 py-3 text-sm text-nature-600 hover:bg-nature-50 transition-colors text-left">
                            <Edit3 size={16} />
                            Editar postagem
                         </button>
                      )}
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="px-6 pb-4">
              <p className="text-nature-800 text-[15px] leading-relaxed font-medium">{post.content}</p>
            </div>

            {post.image && (
              <div className="px-3">
                <img src={post.image} className="w-full h-80 object-cover rounded-[1.5rem] shadow-sm" alt="Conteúdo" />
              </div>
            )}

            {post.video && (
              <div className="px-3">
                <div className="relative rounded-[1.5rem] overflow-hidden bg-nature-900 group">
                  <video src={post.video} controls className="w-full h-80 object-cover" />
                </div>
              </div>
            )}

            {/* Editable Caption Section */}
            {(post.image || post.video) && (
              <div className="px-6 pt-3 flex items-start gap-3 group/caption">
                <Sparkles size={14} className="text-sand-400 mt-0.5 shrink-0" />
                {editingCaptionId === post.id ? (
                  <div className="flex-1 flex gap-2 animate-in slide-in-from-left-2">
                    <input 
                      className="flex-1 text-xs border-b-2 border-nature-100 focus:border-nature-500 focus:outline-none py-1 bg-transparent placeholder:text-nature-200" 
                      placeholder="Descreva este momento..."
                      value={editCaptionValue} 
                      onChange={(e) => setEditCaptionValue(e.target.value)} 
                    />
                    <button onClick={() => saveCaption(post.id)} className="text-nature-600 hover:scale-110 transition-transform p-1"><Save size={18} /></button>
                  </div>
                ) : (
                  <div className="flex-1 flex justify-between items-center">
                    {post.caption ? (
                      <p className="text-xs text-nature-400 italic font-medium leading-relaxed">"{post.caption}"</p>
                    ) : (
                      post.author === 'Você' && (
                        <button 
                          onClick={() => startEditingCaption(post)}
                          className="text-xs text-nature-200 hover:text-nature-400 italic flex items-center gap-1 transition-colors"
                        >
                          <PlusCircle size={12} /> Adicionar legenda...
                        </button>
                      )
                    )}
                    {post.author === 'Você' && post.caption && (
                      <button 
                        onClick={() => startEditingCaption(post)} 
                        className="opacity-0 group-hover/caption:opacity-100 text-nature-200 hover:text-nature-500 transition-all p-1"
                      >
                        <Edit3 size={14} />
                      </button>
                    )}
                  </div>
                )}
              </div>
            )}

            <div className="p-5 border-t border-nature-50 flex items-center justify-between bg-sand-50/20">
              <div className="flex gap-5">
                <button 
                  onClick={() => handleLike(post.id)}
                  className={`flex items-center gap-2 text-xs font-black transition-all active:scale-150 ${likedPosts.has(post.id) ? 'text-rose-500' : 'text-nature-300 hover:text-rose-400'}`}
                >
                  <Heart size={22} fill={likedPosts.has(post.id) ? 'currentColor' : 'none'} className="transition-all" />
                  {post.likes}
                </button>
                <button 
                  onClick={() => toggleComments(post.id)}
                  className={`flex items-center gap-2 text-xs font-black transition-all active:scale-110 ${expandedComments.has(post.id) ? 'text-nature-700' : 'text-nature-300 hover:text-nature-600'}`}
                >
                  <MessageCircle size={22} fill={expandedComments.has(post.id) ? 'currentColor' : 'none'} fillOpacity={0.1} />
                  {post.comments}
                </button>
              </div>
              <button 
                onClick={() => handleShare(post)}
                className={`transition-all p-2 rounded-full hover:bg-nature-50 ${isSharing === post.id ? 'text-nature-600 scale-125' : 'text-nature-200 hover:text-nature-600'}`}
              >
                <Share2 size={20} className={isSharing === post.id ? 'animate-pulse' : ''} />
              </button>
            </div>

            {/* Comments Section */}
            {expandedComments.has(post.id) && (
              <div className="bg-nature-50/50 p-6 border-t border-nature-100/50 space-y-5 animate-in slide-in-from-top-4 duration-500">
                <div className="max-h-80 overflow-y-auto pr-2 custom-scrollbar space-y-6">
                  {post.commentList && post.commentList.length > 0 ? (
                    getGroupedComments(post.commentList).map((group) => (
                      <div key={group.dateKey} className="space-y-4">
                        <div className="flex items-center gap-4 py-1">
                          <div className="flex-1 h-px bg-nature-100"></div>
                          <span className="text-[10px] font-black text-nature-300 uppercase tracking-[0.2em] px-2">
                            {formatDateHeader(group.timestamp)}
                          </span>
                          <div className="flex-1 h-px bg-nature-100"></div>
                        </div>
                        <div className="space-y-4">
                          {group.items.map(comment => (
                            <div key={comment.id} className="flex gap-4 items-start group/comment animate-in fade-in duration-300">
                              <img src={comment.avatar} className="w-9 h-9 rounded-full object-cover shrink-0 border-2 border-white shadow-sm transition-transform group-hover/comment:scale-110" alt={comment.author} />
                              <div className="bg-white p-4 rounded-2xl rounded-tl-none shadow-sm text-sm flex-1 border border-nature-100/50 transition-all hover:shadow-md">
                                <div className="flex justify-between items-center mb-1.5">
                                  <span className="font-black text-nature-900 text-xs">{comment.author}</span>
                                  <span className="text-[9px] text-nature-300 font-bold">
                                    {new Date(comment.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                  </span>
                                </div>
                                <p className="text-nature-700 leading-relaxed text-[13px]">{comment.text}</p>
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-8 flex flex-col items-center gap-2">
                      <div className="w-12 h-12 bg-nature-100 rounded-full flex items-center justify-center text-nature-300">
                        <MessageCircle size={24} />
                      </div>
                      <p className="text-nature-400 text-xs font-bold italic tracking-wide">
                        Ninguém falou nada ainda... Seja a primeira voz! ✨
                      </p>
                    </div>
                  )}
                </div>
                <div className="flex gap-3 items-center pt-4 border-t border-nature-100/30">
                  <img src="https://picsum.photos/50/50?random=99" className="w-9 h-9 rounded-full border-2 border-white shadow-sm" alt="Você" />
                  <div className="relative flex-1 group">
                    <input
                      ref={(el) => (commentInputRefs.current[post.id] = el)}
                      className="w-full bg-white border border-nature-100 rounded-full px-5 py-3 text-xs focus:ring-4 focus:ring-nature-100/50 outline-none pr-12 transition-all shadow-inner placeholder:text-nature-200"
                      placeholder="Deixe uma palavra de cura e apoio..."
                      value={commentInputs[post.id] || ''}
                      onChange={(e) => setCommentInputs({ ...commentInputs, [post.id]: e.target.value })}
                      onKeyPress={(e) => e.key === 'Enter' && handleCommentSubmit(post.id)}
                    />
                    <button 
                      onClick={() => handleCommentSubmit(post.id)} 
                      disabled={!commentInputs[post.id]?.trim()}
                      className="absolute right-2 top-1/2 -translate-y-1/2 text-nature-600 disabled:text-nature-100 p-2 hover:scale-110 active:scale-90 transition-all"
                    >
                      <Send size={18} />
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>

      {/* Report Confirmation Modal */}
      {reportingPostId && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-nature-900/60 backdrop-blur-sm" onClick={() => setReportingPostId(null)}></div>
          <div className="relative bg-white w-full max-w-sm rounded-[3rem] p-8 shadow-2xl space-y-6 animate-in zoom-in-95 duration-300">
            <div className="flex flex-col items-center text-center space-y-4">
              <div className="w-20 h-20 bg-red-50 text-red-500 rounded-full flex items-center justify-center">
                <ShieldAlert size={40} />
              </div>
              <h3 className="text-2xl font-serif text-nature-900 leading-tight">Denunciar Postagem?</h3>
              <p className="text-nature-600 text-sm leading-relaxed">
                Você acredita que esta postagem viola as diretrizes da Tribo Essência? Nossa equipe revisará o conteúdo imediatamente.
              </p>
            </div>
            <div className="flex flex-col gap-3">
              <button 
                onClick={confirmReport}
                className="w-full bg-red-600 text-white py-4 rounded-2xl font-bold text-base shadow-lg shadow-red-100 hover:bg-red-700 active:scale-95 transition-all"
              >
                Confirmar Denúncia
              </button>
              <button 
                onClick={() => setReportingPostId(null)}
                className="w-full bg-nature-50 text-nature-600 py-4 rounded-2xl font-bold text-base hover:bg-nature-100 active:scale-95 transition-all"
              >
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Community;

{
  "name": "ReViva Agora",
  "description": "Um guia jornada de autoconhecimento, saúde intestinal e reconexão com a essência através de nutrição consciente e cura emocional.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React, { useState, useRef, useMemo } from 'react';
import { Heart, MessageCircle, Share2, Image as ImageIcon, Video as VideoIcon, X, Check, Send, Clock, Sparkles, Edit3, Save, MoreVertical, AlertCircle, ShieldAlert, PlusCircle, Camera, Play, Maximize2 } from 'lucide-react';
import { CommunityPost, Comment } from '../types';

const MOCK_POSTS: CommunityPost[] = [
  {
    id: '0',
    author: 'Guia Essência',
    avatar: 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=100&auto=format&fit=crop',
