    likes: 156,
    comments: 3,
    commentList: [
      { id: 'c1', author: 'Ana Clara', avatar: 'https://picsum.photos/50/50?random=10', text: 'Dica maravilhosa!', timestamp: Date.now() - 600000 },
      { id: 'c2', author: 'Ricardo M.', avatar: 'https://picsum.photos/50/50?random=15', text: 'Beber água com limão ajuda.', timestamp: Date.now() - 300000 }
    ],
    timestamp: Date.now() - 1800000,
