    diet: false,
    meditation: false,
    exercise: false,
    earthing: false,
    emotionalWork: false
  });

  const handleSave = () => {
    onSaveLog({
      date,
      meals,
      symptomsPresent: symptoms,
      relievedSymptoms: relievedSymptoms,
      mood,
      waterIntake: waterGlasses,
      completedActions: { 
        diet: habits.diet,
        diary: true, // Auto-completed by saving
        meditationOrBreathing: habits.meditation,
        emotionalWork: habits.emotionalWork,
        exercise: habits.exercise,
        earthing: habits.earthing,
        waterGoal: waterGlasses >= 8 
      }
    });
    alert("Registro salvo com sucesso!");
