  const [loadingAudio, setLoadingAudio] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);

  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1);
  const [currentAudioBuffer, setCurrentAudioBuffer] = useState<AudioBuffer | null>(null);

  const progressAnimationRef = useRef<number | null>(null);
  const startTimeRef = useRef<number>(0);
  const offsetRef = useRef<number>(0);

  // Ritual State
  const [ritualStep, setRitualStep] = useState<'idle' | 'preparing' | 'feeling' | 'forgiving' | 'affirming' | 'checking' | 'completed'>('idle');
  const [ritualAudio, setRitualAudio] = useState<{ [key: string]: AudioBuffer | null }>({});
  const [isEyesClosed, setIsEyesClosed] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const sourceRef = useRef<AudioBufferSourceNode | null>(null);

  const initAudioContext = async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      gainNodeRef.current = audioContextRef.current.createGain();
      gainNodeRef.current.gain.value = 1.8;
      gainNodeRef.current.connect(audioContextRef.current.destination);
    }
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }
  };

  const updateProgress = () => {
    if (!audioContextRef.current || !isPlaying) return;

    const now = audioContextRef.current.currentTime;
    const elapsed = (now - startTimeRef.current) * playbackRate;
    const newTime = offsetRef.current + elapsed;

    setCurrentTime(Math.min(newTime, duration));

    if (newTime < duration) {
      progressAnimationRef.current = requestAnimationFrame(updateProgress);
    } else {
      setIsPlaying(false);
      setCurrentTime(duration);
    }
  };

  const playAudio = async (buffer: AudioBuffer, startOffset: number = 0): Promise<void> => {
    await initAudioContext();
    stopAudioSource();

    const source = audioContextRef.current!.createBufferSource();
    source.buffer = buffer;
    source.playbackRate.value = playbackRate;

    if (gainNodeRef.current) {
      source.connect(gainNodeRef.current);
    }

    setCurrentAudioBuffer(buffer);
    setDuration(buffer.duration);
    offsetRef.current = startOffset;
    startTimeRef.current = audioContextRef.current!.currentTime;

    return new Promise((resolve) => {
      source.onended = () => {
        const now = audioContextRef.current!.currentTime;
        const totalElapsed = offsetRef.current + (now - startTimeRef.current) * playbackRate;
        if (totalElapsed >= buffer.duration - 0.1) {
          setIsPlaying(false);
          if (progressAnimationRef.current) cancelAnimationFrame(progressAnimationRef.current);
          resolve();
        }
      };

      source.start(0, startOffset);
      sourceRef.current = source;
      setIsPlaying(true);
      progressAnimationRef.current = requestAnimationFrame(updateProgress);
    });
  };

  const stopAudioSource = () => {
    if (sourceRef.current) {
      try {
        sourceRef.current.stop();
        sourceRef.current.disconnect();
      } catch (e) {}
      sourceRef.current = null;
    }
    if (progressAnimationRef.current) {
      cancelAnimationFrame(progressAnimationRef.current);
    }
  };

