        </div>

        <div className="px-1 pt-2">
          <div className="relative h-2 bg-white/10 rounded-full cursor-pointer group" onClick={(e) => {
            const rect = e.currentTarget.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const newOffset = (x / rect.width) * duration;
            setCurrentTime(newOffset);
            if (isPlaying) playAudio(currentAudioBuffer, newOffset);
            else offsetRef.current = newOffset;
          }}>
