          </div>
        </div>

        <div className="flex flex-col gap-6">
          <div className="flex items-center justify-center gap-8">
            <button onClick={() => {
              const newOffset = Math.max(0, currentTime - 15);
              setCurrentTime(newOffset);
              if (isPlaying) playAudio(currentAudioBuffer, newOffset);
              else offsetRef.current = newOffset;
            }} className="text-white/40 hover:text-white transition-all p-2 relative">
              <RotateCcw size={28} />
              <span className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-[8px] font-black mt-1">15</span>
            </button>

            <button 
              onClick={async () => {
                if (isPlaying) {
                  stopAudioSource();
                  setIsPlaying(false);
                  offsetRef.current = currentTime;
                } else {
                  playAudio(currentAudioBuffer, currentTime >= duration ? 0 : currentTime);
                }
              }}
              className={`w-20 h-20 flex items-center justify-center rounded-full transition-all shadow-2xl transform hover:scale-105 active:scale-95 ${isPlaying ? 'bg-nature-700 text-white' : 'bg-white text-nature-900'}`}
            >
              {isPlaying ? <Square size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
            </button>

            <button onClick={() => {
              const newOffset = Math.min(duration, currentTime + 15);
              setCurrentTime(newOffset);
              if (isPlaying) playAudio(currentAudioBuffer, newOffset);
              else offsetRef.current = newOffset;
            }} className="text-white/40 hover:text-white transition-all p-2 relative">
              <RotateCw size={28} />
              <span className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-[8px] font-black mt-1">15</span>
            </button>
