      )}

      {activeTab === 'emotional' && (
        <div className="bg-white p-8 rounded-[3rem] border border-nature-50 shadow-sm space-y-6">
          <div className="flex items-center gap-3"><Heart className="text-nature-500" /><h3 className="font-serif text-xl text-nature-900">Espelho da Alma</h3></div>
          <p className="text-nature-500 text-sm">Qual sombra você deseja iluminar agora?</p>
          <input type="text" id="feeling-input" placeholder="Ex: Medo, Escassez..." className="w-full p-4 rounded-xl border border-nature-100 bg-nature-50 text-sm focus:outline-none focus:ring-4 focus:ring-nature-100/50 transition-all" />
