function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number = 24000, numChannels: number = 1): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const BREATHING_PATTERNS = [
  { id: 'square', name: 'Quadrada', desc: 'Foco e Alerta', inhale: 4, hold1: 4, exhale: 4, hold2: 4 },
  { id: 'relax', name: 'Relaxante (4-7-8)', desc: 'Sono e Calma', inhale: 4, hold1: 7, exhale: 8, hold2: 0 },
  { id: 'energy', name: 'Energia (4-4-8)', desc: 'Despertar Vital', inhale: 4, hold1: 4, exhale: 8, hold2: 0 },
  { id: 'balance', name: 'Equilíbrio (5-5)', desc: 'Coerência Cardíaca', inhale: 5, hold1: 0, exhale: 5, hold2: 0 },
];

const Wellness: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'breathing' | 'meditation' | 'emotional' | 'healing-ritual'>('breathing');
  const [loading, setLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);

  // Breathing
  const [activePattern, setActivePattern] = useState(BREATHING_PATTERNS[0]);
  const [breathPhase, setBreathPhase] = useState<'inhale' | 'hold1' | 'exhale' | 'hold2' | 'idle'>('idle');
  const [breathTimer, setBreathTimer] = useState(0);
  const [guidanceOn, setGuidanceOn] = useState(true);

  // Ritual
  const [ritualStep, setRitualStep] = useState<'idle' | 'breathing' | 'feeling' | 'forgiving' | 'affirming' | 'checking' | 'completed'>('idle');

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceRef = useRef<AudioBufferSourceNode | null>(null);
  const intervalRef = useRef<number | null>(null);

  const initAudio = async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();
  };

  const playVoice = async (text: string) => {
    if (!guidanceOn) return;
    await initAudio();
    const base64 = await generateSpeech(text);
    if (base64) {
      const buffer = await decodeAudioData(decodeBase64(base64), audioContextRef.current!);
      const source = audioContextRef.current!.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current!.destination);
      source.start();
      sourceRef.current = source;
    }
  };

  const startBreathing = async () => {
    await initAudio();
    setIsPlaying(true);
    let currentPhase: any = 'inhale';
    setBreathPhase(currentPhase);
    setBreathTimer(activePattern.inhale);
    playVoice("Inspire profundamente pelo nariz.");

    intervalRef.current = window.setInterval(async () => {
      setBreathTimer(prev => {
        if (prev > 1) return prev - 1;

        // Transition logic
        if (currentPhase === 'inhale') {
          if (activePattern.hold1 > 0) {
            currentPhase = 'hold1';
            setBreathTimer(activePattern.hold1);
            playVoice("Segure o ar.");
          } else {
            currentPhase = 'exhale';
            setBreathTimer(activePattern.exhale);
            playVoice("Solte o ar devagar.");
          }
        } else if (currentPhase === 'hold1') {
          currentPhase = 'exhale';
          setBreathTimer(activePattern.exhale);
          playVoice("Solte o ar pela boca.");
        } else if (currentPhase === 'exhale') {
          if (activePattern.hold2 > 0) {
            currentPhase = 'hold2';
            setBreathTimer(activePattern.hold2);
            playVoice("Mantenha sem ar.");
          } else {
            currentPhase = 'inhale';
            setBreathTimer(activePattern.inhale);
            playVoice("Inspire novamente.");
          }
        } else {
          currentPhase = 'inhale';
          setBreathTimer(activePattern.inhale);
          playVoice("Reiniciando o ciclo.");
        }
        setBreathPhase(currentPhase);
        return prev;
      });
    }, 1000);
  };

  const stopPractice = () => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    if (sourceRef.current) sourceRef.current.stop();
    setIsPlaying(false);
    setBreathPhase('idle');
  };

  return (
    <div className="p-4 pb-32 max-w-2xl mx-auto space-y-10">
      <header className="px-4 text-center">
        <h2 className="text-4xl font-serif text-white tracking-tighter">Santuário Etéreo</h2>
        <p className="text-nature-400 text-xs uppercase tracking-[0.4em] font-black mt-2">Passe de Mágica Interno</p>
      </header>

      <div className="flex glass-mystic p-1 rounded-3xl gap-1 mx-4">
        {['breathing', 'meditation', 'healing-ritual'].map(t => (
          <button 
            key={t}
            onClick={() => { setActiveTab(t as any); stopPractice(); }}
            className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest rounded-2xl transition-all ${activeTab === t ? 'bg-white text-nature-900 shadow-xl' : 'text-ethereal-400'}`}
          >
            {t === 'breathing' ? 'Pulsar' : t === 'meditation' ? 'Vibrar' : 'Curar'}
          </button>
        ))}
      </div>

      {activeTab === 'breathing' && (
        <div className="space-y-12 animate-in fade-in duration-1000">
           <div className="relative flex flex-col items-center justify-center py-10 min-h-[400px]">
              {/* Hypnotic Visualizer */}
              <div className="absolute inset-0 flex items-center justify-center overflow-hidden pointer-events-none">
                 <div className={`w-64 h-64 rounded-full border border-nature-400/20 transition-all duration-[4000ms] ${breathPhase === 'inhale' ? 'scale-[2.5] opacity-100' : 'scale-50 opacity-0'}`} />
                 <div className={`w-64 h-64 rounded-full bg-nature-400/5 transition-all duration-[4000ms] ${breathPhase === 'inhale' ? 'scale-[2] opacity-100' : 'scale-50 opacity-0'}`} />
                 <div className={`absolute w-40 h-40 bg-nature-400/10 rounded-full blur-3xl animate-pulse`} />
              </div>

              <div className={`w-48 h-48 glass-mystic rounded-full flex flex-col items-center justify-center relative z-10 transition-all duration-1000 ${breathPhase !== 'idle' ? 'border-nature-400 shadow-[0_0_60px_rgba(127,163,101,0.2)]' : 'border-white/5'}`}>
                 <span className="text-6xl font-serif text-white mb-2">{breathPhase === 'idle' ? <Wind size={60} className="text-nature-300" /> : breathTimer}</span>
                 <span className="text-[10px] font-black uppercase tracking-[0.3em] text-nature-400">
                   {breathPhase === 'inhale' ? 'Inspire' : breathPhase === 'hold1' ? 'Segure' : breathPhase === 'exhale' ? 'Exale' : breathPhase === 'hold2' ? 'Vazio' : 'Respire'}
                 </span>
              </div>

              <div className="mt-12 text-center z-10">
                <h3 className="text-2xl font-serif text-white">{activePattern.name}</h3>
                <p className="text-ethereal-500 italic text-sm mt-1">{activePattern.desc}</p>
              </div>
           </div>

           <div className="grid grid-cols-2 gap-4 px-4">
              {BREATHING_PATTERNS.map(p => (
                <button 
                  key={p.id}
                  onClick={() => { setActivePattern(p); stopPractice(); }}
                  className={`p-5 rounded-[2rem] border transition-all text-left ${activePattern.id === p.id ? 'bg-nature-900 border-nature-400' : 'glass-mystic border-white/5'}`}
                >
                  <h4 className="font-bold text-white text-sm">{p.name}</h4>
