                </button>
              ))}
           </div>

           <div className="px-6 space-y-4">
             <button 
                onClick={isPlaying ? stopPractice : startBreathing}
                className={`w-full py-5 rounded-3xl font-bold transition-all shadow-2xl flex items-center justify-center gap-3 ${isPlaying ? 'bg-nature-800 text-white' : 'bg-white text-nature-950 hover:scale-[1.02]'}`}
