import React, { useState, useEffect } from 'react';
import Navigation from './components/Navigation';
import Diagnosis from './components/Diagnosis';
import Dashboard from './components/Dashboard';
import Tracker from './components/Tracker';
import Wellness from './components/Wellness';
import Guidance from './components/Guidance';
import Community from './components/Community';
import { AppView, UserProfile, DailyLog } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DIAGNOSIS);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Viajante',
    startDate: null,
    diagnosisScore: 0,
    hasSeenWarning: false,
    isOnDiet: false,
  });
  const [logs, setLogs] = useState<DailyLog[]>([]);

  useEffect(() => {
    const savedProfile = localStorage.getItem('userProfile');
    const savedLogs = localStorage.getItem('userLogs');

    if (savedProfile) {
      const parsedProfile = JSON.parse(savedProfile);
      setUserProfile(parsedProfile);
      if (parsedProfile.isOnDiet) {
        setCurrentView(AppView.DASHBOARD);
      }
    }
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem('userProfile', JSON.stringify(userProfile));
  }, [userProfile]);

  useEffect(() => {
    localStorage.setItem('userLogs', JSON.stringify(logs));
  }, [logs]);

  const handleDiagnosisComplete = (score: number, name: string) => {
    setUserProfile(prev => ({
      ...prev,
      name: name,
      diagnosisScore: score,
      hasSeenWarning: true,
      startDate: new Date().toISOString(),
      isOnDiet: true
    }));
    setTimeout(() => setCurrentView(AppView.DASHBOARD), 1000);
  };

  const handleSaveLog = (log: DailyLog) => {
    setLogs(prev => {
      const exists = prev.findIndex(l => l.date === log.date);
      if (exists >= 0) {
        const newLogs = [...prev];
        newLogs[exists] = log;
        return newLogs;
      }
      return [...prev, log];
    });
  };

  const renderView = () => {
    switch (currentView) {
      case AppView.DIAGNOSIS:
        return <Diagnosis onComplete={handleDiagnosisComplete} userProfile={userProfile} />;
      case AppView.DASHBOARD:
        return <Dashboard userProfile={userProfile} logs={logs} />;
      case AppView.TRACKER:
        return <Tracker onSaveLog={handleSaveLog} logs={logs} />;
      case AppView.WELLNESS:
        return <Wellness />;
      case AppView.GUIDANCE:
        return <Guidance />;
      case AppView.COMMUNITY:
        return <Community />;
      default:
        return <Dashboard userProfile={userProfile} logs={logs} />;
    }
  };

  return (
    <div className="min-h-screen bg-ethereal-950 text-gray-100 font-sans selection:bg-nature-400/30">
      <main className="mx-auto max-w-md bg-transparent min-h-screen shadow-2xl relative overflow-x-hidden">
        <div className="relative z-10">{renderView()}</div>

        {/* Hypnotic Background Glows */}
        <div className="fixed top-[-10%] left-[-10%] w-full h-full bg-nature-400/5 blur-[150px] pointer-events-none rounded-full" />
        <div className="fixed bottom-[-10%] right-[-10%] w-full h-full bg-ethereal-500/5 blur-[150px] pointer-events-none rounded-full" />
      </main>

      {userProfile.isOnDiet && (
        <Navigation currentView={currentView} setView={setCurrentView} />
      )}
    </div>
  );
};

export default App;

