      runRitualCycle(buffers);
    } catch (e) {
      setRitualStep('idle');
    } finally {
      setLoading(false);
    }
  };

  const runRitualCycle = async (buffers: any) => {
    setIsEyesClosed(true);
    const sequence: (typeof ritualStep)[] = ['breathing', 'feeling', 'forgiving', 'affirming', 'checking'];

    for (const step of sequence) {
        setRitualStep(step);
