  { id: '7', name: 'Dores articulares sem causa aparente', category: 'outro', weight: 2 },
];

const CATEGORIES = [
  { id: 'todos', label: 'Todos', icon: LayoutGrid },
  { id: 'digestivo', label: 'Digestivo', icon: Activity },
  { id: 'neurologico', label: 'Mente', icon: Brain },
  { id: 'emocional', label: 'Alma', icon: Heart },
  { id: 'outro', label: 'Corpo', icon: Shapes },
];

interface DiagnosisProps {
  onComplete: (score: number, name: string) => void;
  userProfile: UserProfile;
}

const Diagnosis: React.FC<DiagnosisProps> = ({ onComplete, userProfile }) => {
  const [selectedSymptoms, setSelectedSymptoms] = useState<string[]>([]);
  const [step, setStep] = useState<'warning' | 'quiz' | 'result'>('warning');
  const [activeCategory, setActiveCategory] = useState<string>('todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [userName, setUserName] = useState('');

  const calculateScore = () => {
    return selectedSymptoms.reduce((acc, id) => {
      const symptom = SYMPTOMS.find(s => s.id === id);
      return acc + (symptom?.weight || 0);
    }, 0);
  };

  const handleToggleSymptom = (id: string) => {
    setSelectedSymptoms(prev => 
      prev.includes(id) ? prev.filter(s => s !== id) : [...prev, id]
    );
  };

  const groupedSymptoms = useMemo(() => {
    const groups: Record<string, Symptom[]> = {};
    SYMPTOMS.forEach(s => {
      const matchesSearch = s.name.toLowerCase().includes(searchQuery.toLowerCase());
      if (matchesSearch) {
        if (!groups[s.category]) groups[s.category] = [];
        groups[s.category].push(s);
      }
    });
    return groups;
  }, [searchQuery]);

  if (step === 'warning') {
    return (
      <div className="p-6 min-h-screen flex flex-col justify-center items-center text-center animate-in fade-in duration-1000">
        <div className="glass-mystic p-8 rounded-[3rem] shadow-2xl max-w-sm space-y-8 relative overflow-hidden">
          <div className="absolute top-0 inset-x-0 h-1 bg-gradient-to-r from-red-500/50 via-nature-400/50 to-red-500/50"></div>

          <div className="w-20 h-20 bg-red-900/30 rounded-full flex items-center justify-center mx-auto border border-red-500/20 shadow-[0_0_30px_rgba(239,68,68,0.2)]">
            <AlertTriangle size={36} className="text-red-400" />
          </div>

          <div className="space-y-4">
            <h2 className="text-2xl font-serif text-white tracking-tight uppercase italic">Aviso de Segurança</h2>
            <p className="text-ethereal-300 text-sm leading-relaxed">
              Antes de qualquer mudança na dieta, é imprescindível realizar exames médicos para descartar a <strong>Doença Celíaca</strong>. A exclusão prematura do glúten impede diagnósticos precisos.
            </p>
          </div>

          <div className="h-px bg-white/10 w-full"></div>

          <div className="space-y-4">
            <div className="flex items-center justify-center gap-2 text-nature-400">
              <Sparkles size={20} className="animate-pulse" />
              <h2 className="text-lg font-serif tracking-tight">Consciência Corporal</h2>
            </div>
            <p className="text-ethereal-400 text-xs leading-relaxed italic">
              Este app é uma ferramenta de <strong>autocompreensão</strong> e reconexão. Os resultados são informativos e não substituem o diagnóstico de um profissional de saúde.
            </p>
          </div>

          <button
            onClick={() => setStep('quiz')}
            className="w-full bg-white text-nature-950 py-5 rounded-2xl font-bold text-lg hover:scale-[1.02] transition-all shadow-xl active:scale-95"
          >
            Compreendo e Desejo Seguir
          </button>
        </div>
      </div>
    );
  }

  if (step === 'result') {
    const score = calculateScore();
    return (
      <div className="p-6 flex flex-col items-center justify-center min-h-screen animate-in zoom-in duration-1000">
        <div className="relative mb-12">
          <div className="absolute inset-0 bg-nature-400/20 blur-3xl rounded-full animate-pulse"></div>
          <div className="w-40 h-40 glass-mystic rounded-full flex items-center justify-center relative z-10 border border-white/10 shadow-[0_0_50px_rgba(255,255,255,0.05)]">
            <div className="flex flex-col items-center">
                <span className="text-[10px] font-black uppercase tracking-widest text-nature-400 mb-1">Vibração</span>
                <h3 className="text-6xl font-serif font-bold text-white">{score}</h3>
            </div>
          </div>
        </div>
        <h2 className="text-3xl font-serif text-white mb-4">Mapeamento Concluído</h2>
        <p className="text-ethereal-300 text-center mb-8 max-w-xs italic text-sm">
          Seu templo sagrado enviou sinais que captamos. A jornada focará em silenciar as sombras e elevar seu brilho interior.
        </p>

        <div className="w-full max-w-xs space-y-4">
            <input
              type="text"
              placeholder="Como deseja ser chamado(a)?"
              value={userName}
              onChange={(e) => setUserName(e.target.value)}
              className="w-full p-5 glass-mystic rounded-2xl text-center text-white outline-none border border-white/10 focus:border-nature-400 transition-all placeholder:text-ethereal-700"
            />

            <p className="text-[10px] text-ethereal-500 text-center leading-relaxed italic uppercase tracking-[0.2em] px-2 opacity-60">
              Lembre-se: Este é um portal de autoconhecimento, não um diagnóstico clínico.
            </p>
        </div>

        <button 
          onClick={() => onComplete(score, userName.trim() || 'Viajante')}
          className="w-full max-w-xs mt-10 bg-nature-500 text-white py-6 rounded-3xl font-bold shadow-[0_20px_40px_rgba(127,163,101,0.3)] hover:bg-nature-400 transition-all flex items-center justify-center gap-3 active:scale-95"
        >
          Iniciar Portal de Cura <Zap size={22} />
        </button>
      </div>
    );
  }

  return (
    <div className="p-4 pt-12 pb-32 space-y-8 animate-in fade-in duration-700">
      <header className="px-6 space-y-1">
        <h2 className="text-4xl font-serif text-white tracking-tighter">Mapeamento</h2>
        <p className="text-ethereal-500 text-[10px] uppercase tracking-[0.4em] font-black italic">Escute as Mensagens do Templo</p>
      </header>

      <div className="px-4 relative group">
        <div className="absolute inset-y-0 left-8 flex items-center pointer-events-none">
          <Search size={18} className="text-ethereal-600" />
        </div>
        <input
          type="text"
          placeholder="Pesquisar sinal físico..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="w-full pl-12 pr-6 py-4 glass-mystic rounded-[2rem] text-sm text-white outline-none border border-white/5 focus:border-nature-400/50 transition-all placeholder:text-ethereal-700"
        />
      </div>

      <div className="flex gap-2 overflow-x-auto no-scrollbar px-6">
        {CATEGORIES.map(cat => (
          <button
            key={cat.id}
            onClick={() => setActiveCategory(cat.id)}
            className={`px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border whitespace-nowrap flex items-center gap-2 ${
              activeCategory === cat.id ? 'bg-white text-nature-950 border-white shadow-lg' : 'glass-mystic text-ethereal-500 border-white/5'
            }`}
          >
            <cat.icon size={14} />
            {cat.label}
          </button>
        ))}
      </div>

      <div className="space-y-12 px-6">
        {CATEGORIES.filter(c => c.id !== 'todos').map(cat => {
          const symptomsInCat = groupedSymptoms[cat.id] || [];
          if (activeCategory !== 'todos' && activeCategory !== cat.id) return null;
          if (symptomsInCat.length === 0) return null;

          return (
            <section key={cat.id} className="space-y-5 animate-in slide-in-from-left-4 duration-700">
              <div className="flex items-center gap-3 px-1 border-l-2 border-nature-400 pl-4">
                <cat.icon size={20} className="text-nature-400" />
                <h3 className="text-xl font-serif text-white tracking-tight uppercase">{cat.label}</h3>
              </div>
              <div className="grid grid-cols-1 gap-4">
                {symptomsInCat.map(s => (
                  <div 
                    key={s.id}
                    onClick={() => handleToggleSymptom(s.id)}
                    className={`p-6 rounded-[2.5rem] border transition-all duration-700 cursor-pointer flex justify-between items-center group ${
                      selectedSymptoms.includes(s.id) ? 'bg-nature-900 border-nature-400 shadow-[0_10px_30px_rgba(127,163,101,0.2)]' : 'glass-mystic border-white/5 hover:border-white/10'
                    }`}
                  >
                    <span className={`text-base font-medium transition-colors ${selectedSymptoms.includes(s.id) ? 'text-white' : 'text-ethereal-400'}`}>{s.name}</span>
                    <div className={`w-8 h-8 rounded-full border flex items-center justify-center transition-all ${selectedSymptoms.includes(s.id) ? 'bg-nature-400 border-nature-400 rotate-0' : 'border-white/10 rotate-180 opacity-40'}`}>
                      <CheckCircle size={18} className={selectedSymptoms.includes(s.id) ? 'text-nature-950' : 'text-transparent'} />
                    </div>
                  </div>
                ))}
              </div>
            </section>
          );
        })}
      </div>

      <div className="fixed bottom-0 left-0 w-full p-8 bg-gradient-to-t from-ethereal-950 via-ethereal-950/90 to-transparent z-50">
        <button 
          onClick={() => setStep('result')}
          disabled={selectedSymptoms.length === 0}
          className="w-full max-w-md mx-auto bg-white text-nature-950 py-6 rounded-[2.5rem] font-bold shadow-2xl disabled:opacity-20 transition-all active:scale-95 flex items-center justify-center gap-3"
        >
          Processar Resultados <Sparkles size={18} className="animate-pulse" />
        </button>
      </div>
    </div>
  );
};

export default Diagnosis;

