  const [breathPhase, setBreathPhase] = useState<'inhale' | 'hold1' | 'exhale' | 'hold2' | 'idle'>('idle');
  const [breathTimer, setBreathTimer] = useState(0);
  const [guidanceOn, setGuidanceOn] = useState(true);

  // Ritual
  const [ritualStep, setRitualStep] = useState<'idle' | 'preparing' | 'breathing' | 'feeling' | 'forgiving' | 'affirming' | 'checking' | 'completed'>('idle');
