                    {ritualStep === 'feeling' && "Sentir"}
                    {ritualStep === 'forgiving' && "Alquimia do Perdão"}
                    {ritualStep === 'affirming' && "Soberania"}
                    {ritualStep === 'checking' && "Verificação"}
                 </h4>
                 <p className="text-ethereal-300 text-xl leading-relaxed italic font-light px-4">
                    {ritualStep === 'breathing' && "Respire a luz do agora. Ancore sua presença."}
                    {ritualStep === 'feeling' && "Acolha a dor com compaixão. Onde ela dói?"}
                    {ritualStep === 'forgiving' && "Dissolva os laços. Eu te perdoo. Eu me libero."}
                    {ritualStep === 'affirming' && "Traga a mão ao peito. Sinta sua força invulnerável."}
                    {ritualStep === 'checking' && "Olhe novamente. A sombra virou luz?"}
                 </p>
               </div>

               {ritualStep === 'checking' && !loading && (
                 <div className="w-full space-y-4 animate-in fade-in">
                    <button onClick={() => runRitualCycle(ritualAudio)} className="w-full bg-white/5 border border-white/10 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-white/10 transition-all">
                      <RotateCcw size={18} /> Repetir Fase
                    </button>
                    <button onClick={() => setRitualStep('completed')} className="w-full bg-white text-nature-950 py-5 rounded-3xl font-bold shadow-2xl hover:scale-[1.02] transition-transform">
                      Selar em Paz e Luz
                    </button>
                 </div>
               )}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

