  { id: 'square', name: 'Quadrada', desc: 'Foco e Alerta (4-4-4-4)', inhale: 4, hold1: 4, exhale: 4, hold2: 4 },
  { id: 'relax', name: 'Relaxante', desc: 'Sono e Calma (4-7-8)', inhale: 4, hold1: 7, exhale: 8, hold2: 0 },
  { id: 'energy', name: 'Energia', desc: 'Despertar Vital (4-4-8)', inhale: 4, hold1: 4, exhale: 8, hold2: 0 },
