    if (loading || isPlaying) stopPractice();

    setLoading(true);
    setLoadingItem(focus);
    setActiveMeditation(focus);
    setGeneratedContent(null);

    try {
      const script = await generateMeditationScript(focus);
      setGeneratedContent(script);
      setIsPlaying(true);
      await playVoice(script);
