      console.error(e);
    } finally {
      setLoading(false);
      setLoadingItem(null);
      setIsPlaying(false);
      setActiveMeditation(null);
    }
  };

  const startHealingRitual = async () => {
    stopPractice();
    setLoading(true);
    setRitualStep('preparing');
    const ctx = await initAudio();
    try {
      const scripts = {
        breathing: "Ancoragem vital. Feche os olhos agora. Inspire luz... um, dois, três, quatro. Segure... um, dois, três, quatro. Solte o ar e o passado.",
        feeling: "Mergulhe no corpo. Onde a sombra reside? Sinta sua densidade sem julgar. Visualize agora o que causou esse peso.",
