        const base64 = await generateSpeech(text);
        if (base64) buffers[key] = await decodeAudioData(decodeBase64(base64), ctx);
      }
      setRitualAudio(buffers);
      runRitualCycle(buffers);
    } catch (e) {
      setRitualStep('idle');
    } finally {
      setLoading(false);
    }
  };

  const runRitualCycle = async (buffers: any) => {
    setIsEyesClosed(true);
    const sequence: (typeof ritualStep)[] = ['breathing', 'feeling', 'forgiving', 'affirming', 'checking'];

    for (const step of sequence) {
        setRitualStep(step);
        if (buffers[step]) {
            const source = audioContextRef.current!.createBufferSource();
            source.buffer = buffers[step];
            source.connect(audioContextRef.current!.destination);
            source.start();
            sourceRef.current = source;
            await new Promise(resolve => {
                source.onended = resolve;
            });
        }
    }
    setIsEyesClosed(false);
    setRitualStep('completed');
  };

  const handleTabChange = (tab: any) => {
    setActiveTab(tab);
    stopPractice();
  };

