      {activeTab === 'breathing' && (
        <div className="space-y-12 animate-in fade-in duration-1000">
           <div className="relative flex flex-col items-center justify-center py-10 min-h-[400px]">
              <div className="absolute inset-0 flex items-center justify-center overflow-hidden pointer-events-none">
                 <div className={`w-64 h-64 rounded-full border border-nature-400/20 transition-all duration-[4000ms] ${breathPhase === 'inhale' ? 'scale-[2.5] opacity-100' : 'scale-50 opacity-0'}`} />
                 <div className={`w-64 h-64 rounded-full bg-nature-400/5 transition-all duration-[4000ms] ${breathPhase === 'inhale' ? 'scale-[2] opacity-100' : 'scale-50 opacity-0'}`} />
                 <div className="absolute w-40 h-40 bg-nature-400/10 rounded-full blur-3xl animate-pulse" />
              </div>

              <div className={`w-48 h-48 glass-mystic rounded-full flex flex-col items-center justify-center relative z-10 transition-all duration-1000 ${breathPhase !== 'idle' ? 'border-nature-400 shadow-[0_0_60px_rgba(127,163,101,0.2)]' : 'border-white/5'}`}>
                 <span className="text-6xl font-serif text-white mb-2">{breathPhase === 'idle' ? <Wind size={60} className="text-nature-300" /> : breathTimer}</span>
