function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number = 24000, numChannels: number = 1): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const BREATHING_PATTERNS = [
  { id: 'square', name: 'Quadrada', desc: 'Foco e Alerta (4-4-4-4)', inhale: 4, hold1: 4, exhale: 4, hold2: 4 },
  { id: 'relax', name: 'Relaxante', desc: 'Sono e Calma (4-7-8)', inhale: 4, hold1: 7, exhale: 8, hold2: 0 },
  { id: 'energy', name: 'Energia', desc: 'Despertar Vital (4-4-8)', inhale: 4, hold1: 4, exhale: 8, hold2: 0 },
  { id: 'balance', name: 'Equilíbrio', desc: 'Coerência Cardíaca (5-5)', inhale: 5, hold1: 0, exhale: 5, hold2: 0 },
];

const Wellness: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'breathing' | 'meditation' | 'emotional' | 'healing-ritual'>('breathing');
  const [loading, setLoading] = useState(false);
  const [loadingItem, setLoadingItem] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [activeMeditation, setActiveMeditation] = useState<string | null>(null);

  // Breathing
  const [activePattern, setActivePattern] = useState(BREATHING_PATTERNS[0]);
  const [breathPhase, setBreathPhase] = useState<'inhale' | 'hold1' | 'exhale' | 'hold2' | 'idle'>('idle');
  const [breathTimer, setBreathTimer] = useState(0);

  // Ritual
  const [ritualStep, setRitualStep] = useState<'idle' | 'preparing' | 'breathing' | 'feeling' | 'forgiving' | 'affirming' | 'checking' | 'completed'>('idle');
  const [isEyesClosed, setIsEyesClosed] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceRef = useRef<AudioBufferSourceNode | null>(null);
  const intervalRef = useRef<number | null>(null);

  const initAudio = async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }
    return audioContextRef.current;
  };

  const stopPractice = () => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    if (sourceRef.current) {
      try { 
        sourceRef.current.onended = null;
        sourceRef.current.stop(); 
      } catch(e) {}
      sourceRef.current = null;
    }
    setIsPlaying(false);
    setBreathPhase('idle');
    setLoading(false);
    setLoadingItem(null);
    setActiveMeditation(null);
    setIsEyesClosed(false);
  };

  const playBase64Audio = async (base64: string) => {
    if (!base64) return;
    const ctx = await initAudio();
    const buffer = await decodeAudioData(decodeBase64(base64), ctx);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start();
    sourceRef.current = source;
    return new Promise((resolve) => {
      source.onended = () => {
        sourceRef.current = null;
        resolve(true);
      };
    });
  };

  const startBreathing = async () => {
    stopPractice();
    await initAudio();
    setIsPlaying(true);
    let currentPhase: any = 'inhale';
    setBreathPhase(currentPhase);
    setBreathTimer(activePattern.inhale);

    const playGuidance = async (text: string) => {
      const b64 = await generateSpeech(text);
      if (b64) await playBase64Audio(b64);
    };

    playGuidance("Inspire profundamente.");

    intervalRef.current = window.setInterval(async () => {
      setBreathTimer(prev => {
        if (prev > 1) return prev - 1;

        if (currentPhase === 'inhale') {
          if (activePattern.hold1 > 0) {
            currentPhase = 'hold1';
            setBreathTimer(activePattern.hold1);
            playGuidance("Segure.");
          } else {
            currentPhase = 'exhale';
            setBreathTimer(activePattern.exhale);
            playGuidance("Exale.");
          }
        } else if (currentPhase === 'hold1') {
          currentPhase = 'exhale';
          setBreathTimer(activePattern.exhale);
          playGuidance("Exale.");
        } else if (currentPhase === 'exhale') {
          if (activePattern.hold2 > 0) {
            currentPhase = 'hold2';
            setBreathTimer(activePattern.hold2);
            playGuidance("Vazio.");
          } else {
            currentPhase = 'inhale';
            setBreathTimer(activePattern.inhale);
            playGuidance("Inspire.");
          }
        } else if (currentPhase === 'hold2') {
          currentPhase = 'inhale';
          setBreathTimer(activePattern.inhale);
          playGuidance("Inspire.");
        }
        setBreathPhase(currentPhase);
        return prev;
      });
    }, 1000);
  };

  const handleMeditationSelect = async (focus: string) => {
    stopPractice();
    setLoading(true);
    setLoadingItem(focus);
    setActiveMeditation(focus);

    try {
      const audioB64 = await generateAndPlayMeditationAudio(focus);
      if (audioB64) {
        setIsPlaying(true);
        await playBase64Audio(audioB64);
      }
    } finally {
      setLoading(false);
      setLoadingItem(null);
      setIsPlaying(false);
      setActiveMeditation(null);
    }
  };

  const handleAffirmation = async () => {
    const input = document.getElementById('feeling-input') as HTMLInputElement;
    const feeling = input?.value || 'Paz';
    stopPractice();
    setLoading(true);
    try {
      const audioB64 = await generateAndPlayAffirmationAudio(feeling);
      if (audioB64) await playBase64Audio(audioB64);
    } finally {
      setLoading(false);
    }
  };

  const startHealingRitual = async () => {
    stopPractice();
    setLoading(true);
    setRitualStep('preparing');

    const scripts: Record<string, string> = {
      breathing: "Respire luz. Feche os olhos agora. Inspire o novo, solte o antigo.",
      feeling: "Acolha seu corpo. Onde está a sombra? Apenas observe com amor.",
      forgiving: "Eu te perdoo. Eu me libero de todo fardo passado.",
      affirming: "Mão no coração. Eu sou soberano. Eu sou luz inabalável.",
      checking: "Observe a leveza. A paz agora é sua morada.",
      completed: "Ritual selado. Volte ao agora quando quiser."
    };

    setIsEyesClosed(true);
    const sequence: (keyof typeof scripts)[] = ['breathing', 'feeling', 'forgiving', 'affirming', 'checking'];

    try {
      for (const step of sequence) {
        setRitualStep(step);
        const b64 = await generateSpeech(scripts[step]);
        if (b64) await playBase64Audio(b64);
      }
      setRitualStep('completed');
    } catch (e) {
      console.error(e);
      setRitualStep('idle');
    } finally {
      setLoading(false);
      setIsEyesClosed(false);
    }
  };

  const handleTabChange = (tab: any) => {
    setActiveTab(tab);
    stopPractice();
  };

  return (
    <div className="p-4 pb-32 max-w-2xl mx-auto space-y-10">
      <header className="px-4 text-center">
        <h2 className="text-4xl font-serif text-white tracking-tighter">Santuário Sagrado</h2>
        <p className="text-nature-400 text-xs uppercase tracking-[0.4em] font-black mt-2">Reconexão com a Essência</p>
      </header>

      <div className="flex glass-mystic p-1 rounded-3xl gap-1 mx-4">
        {[
          { id: 'breathing', label: 'Pulsar', icon: Wind },
          { id: 'meditation', label: 'Vibrar', icon: Flower2 },
          { id: 'emotional', label: 'Afirmar', icon: Heart },
          { id: 'healing-ritual', label: 'Curar', icon: Sparkle }
        ].map(t => (
          <button 
            key={t.id}
            onClick={() => handleTabChange(t.id as any)}
            className={`flex-1 py-3 flex flex-col items-center gap-1 rounded-2xl transition-all ${activeTab === t.id ? 'bg-white text-nature-900 shadow-xl' : 'text-ethereal-400'}`}
          >
            <t.icon size={16} />
            <span className="text-[9px] font-black uppercase tracking-widest">{t.label}</span>
          </button>
        ))}
      </div>

      {activeTab === 'breathing' && (
        <div className="space-y-12 animate-in fade-in duration-1000">
           <div className="relative flex flex-col items-center justify-center py-10 min-h-[400px]">
              <div className="absolute inset-0 flex items-center justify-center overflow-hidden pointer-events-none">
                 <div className={`w-64 h-64 rounded-full border border-nature-400/20 transition-all duration-[4000ms] ${breathPhase === 'inhale' ? 'scale-[2.5] opacity-100' : 'scale-50 opacity-0'}`} />
                 <div className={`w-64 h-64 rounded-full bg-nature-400/5 transition-all duration-[4000ms] ${breathPhase === 'inhale' ? 'scale-[2] opacity-100' : 'scale-50 opacity-0'}`} />
                 <div className="absolute w-40 h-40 bg-nature-400/10 rounded-full blur-3xl animate-pulse" />
              </div>

              <div className={`w-48 h-48 glass-mystic rounded-full flex flex-col items-center justify-center relative z-10 transition-all duration-1000 ${breathPhase !== 'idle' ? 'border-nature-400 shadow-[0_0_60px_rgba(127,163,101,0.2)]' : 'border-white/5'}`}>
                 <span className="text-6xl font-serif text-white mb-2">{breathPhase === 'idle' ? <Wind size={60} className="text-nature-300" /> : breathTimer}</span>
                 <span className="text-[10px] font-black uppercase tracking-[0.3em] text-nature-400">
                   {breathPhase === 'inhale' ? 'Inspire' : breathPhase === 'hold1' ? 'Segure' : breathPhase === 'exhale' ? 'Exale' : breathPhase === 'hold2' ? 'Vazio' : 'Respire'}
                 </span>
              </div>

              <div className="mt-12 text-center z-10">
                <h3 className="text-2xl font-serif text-white">{activePattern.name}</h3>
