                </button>
              ))}
           </div>

           <div className="px-6 space-y-4">
             <button 
                onClick={isPlaying ? stopPractice : startBreathing}
                className={`w-full py-5 rounded-3xl font-bold transition-all shadow-2xl flex items-center justify-center gap-3 ${isPlaying ? 'bg-nature-800 text-white' : 'bg-white text-nature-950 hover:scale-[1.02]'}`}
             >
                {isPlaying ? <><Square size={20} fill="currentColor"/> Parar</> : <><Play size={24} fill="currentColor" /> Pulsar</>}
             </button>
           </div>
        </div>
      )}

      {activeTab === 'meditation' && (
        <div className="bg-white/5 glass-mystic p-8 rounded-[3rem] space-y-8 animate-in fade-in duration-500 mx-4">
          <div className="flex items-center gap-3"><Flower2 className="text-nature-500" /><h3 className="font-serif text-xl text-white">Viagem ao Centro do Ser</h3></div>
          <p className="text-ethereal-400 text-sm italic">Áudio guiado instantâneo com volume amplificado.</p>
