                  </div>

                  <button 
                    onClick={() => handleEditPastLog(log.date)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${
                      log.date === date 
                      ? 'bg-white text-nature-950' 
                      : 'bg-white/5 text-ethereal-300 hover:bg-white/10'
                    }`}
                  >
                    {log.date === date ? 'Editando' : <><Edit3 size={14} /> Alterar</>}
                  </button>
                </div>
              ))
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

