            <span className="text-white font-serif text-lg">
              {new Date(date + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long', year: 'numeric' })}
            </span>
          </div>
        </div>
        <div className="relative">
          <input 
            type="date" 
            value={date} 
            onChange={(e) => setDate(e.target.value)}
            className="absolute inset-0 opacity-0 cursor-pointer"
          />
          <button className="bg-white/10 p-3 rounded-2xl border border-white/10 text-white hover:bg-white/20 transition-all">
            <Edit3 size={20} />
          </button>
        </div>
      </div>

      <div className="space-y-10">
        {/* Sintonias do Dia Selecionado */}
        <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-8">
