                 <label className="text-[10px] font-black uppercase tracking-widest text-ethereal-400 flex items-center gap-2">
                   <Droplets size={14} className="text-blue-400" /> Hidratação
                 </label>
                 <span className="text-xs text-blue-400 font-bold">{waterGlasses * 250}ml / 2L</span>
              </div>
              <div className="flex items-center justify-between bg-white/5 p-4 rounded-3xl border border-white/5">
                 <button onClick={() => setWaterGlasses(Math.max(0, waterGlasses - 1))} className="w-12 h-12 rounded-2xl bg-white/5 text-blue-400 flex items-center justify-center active:scale-90 transition-transform"><Minus size={20} /></button>
                 <div className="flex gap-1.5">
                   {[...Array(8)].map((_, i) => (
                      <div key={i} className={`w-3 h-10 rounded-full transition-all duration-700 ${i < waterGlasses ? 'bg-blue-400 shadow-[0_0_15px_rgba(96,165,250,0.5)]' : 'bg-white/5'}`} />
                   ))}
                 </div>
                 <button onClick={() => setWaterGlasses(waterGlasses + 1)} className="w-12 h-12 rounded-2xl bg-white/5 text-blue-400 flex items-center justify-center active:scale-90 transition-transform"><Plus size={20} /></button>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-3">
               {[
                 { id: 'diet', label: 'Nutrição Consciente', icon: Leaf },
