                 { id: 'earthing', label: 'Conexão Terra', icon: Mountain },
                 { id: 'meditation', label: 'Respiração Cósmica', icon: Wind },
                 { id: 'emotionalWork', label: 'Cura da Essência', icon: Heart },
               ].map((habit) => {
