                  return (
                    <button
                      key={habit.id}
                      onClick={() => toggleHabit(habit.id as any)}
                      className={`flex items-center justify-between p-6 rounded-[2rem] border transition-all duration-500 ${
                        habits[habit.id as keyof typeof habits] 
                          ? 'bg-nature-900 border-nature-500 text-white shadow-[inset_0_2px_10px_rgba(0,0,0,0.2)]' 
                          : 'bg-white/5 border-transparent text-ethereal-500'
