                  value={meals[meal as keyof typeof meals]}
                  onChange={(e) => setMeals({...meals, [meal]: e.target.value})}
                />
              </div>
            ))}
          </div>
        </section>

        {/* Vibração */}
        <section className="glass-mystic p-10 rounded-[3rem] border border-white/5">
