        <button 
           onClick={handleSave}
           className="w-full bg-nature-500 text-white py-7 rounded-[3rem] font-bold text-lg flex items-center justify-center gap-4 shadow-[0_20px_40px_rgba(127,163,101,0.2)] hover:scale-[1.02] transition-all active:scale-95 group"
        >
           <Save size={24} className="group-hover:rotate-12 transition-transform" />
           Fixar Memória
        </button>

        {/* LINHA DO TEMPO DA ESSÊNCIA (Histórico salvo por datas) */}
