            {sortedLogs.length === 0 ? (
              <div className="p-16 text-center glass-mystic rounded-[3rem] border border-white/5 border-dashed mx-2">
                <p className="text-ethereal-600 italic text-sm">O livro da sua jornada ainda está em branco. Comece hoje.</p>
              </div>
            ) : (
              sortedLogs.map((log, index) => (
                <div 
                  key={log.date}
                  className={`relative pl-12 transition-all duration-700 animate-in fade-in slide-in-from-left-4`}
                  style={{ animationDelay: `${index * 100}ms` }}
                >
                  {/* Ponto da Timeline */}
                  <div className={`absolute left-0 top-6 w-5 h-5 rounded-full border-4 shadow-[0_0_15px_rgba(0,0,0,0.5)] z-10 transition-all ${
                    log.date === date 
                    ? 'bg-white border-nature-400 scale-125' 
                    : 'bg-nature-950 border-white/10'
                  }`} />

                  {/* Card de Memória */}
                  <div 
                    className={`p-6 rounded-[2.5rem] border transition-all flex flex-col gap-4 group ${
                      log.date === date 
                      ? 'bg-nature-900/60 border-nature-400 shadow-2xl' 
                      : 'glass-mystic border-white/5 hover:border-white/10'
                    }`}
                  >
                    <div className="flex items-start justify-between">
                      <div className="space-y-1">
                        <span className="text-[10px] font-black uppercase tracking-widest text-nature-500 block">
                          {new Date(log.date + 'T00:00:00').toLocaleDateString('pt-BR', { weekday: 'long' })}
                        </span>
                        <h4 className="text-white font-serif text-xl">
                          {new Date(log.date + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}
                        </h4>
                      </div>
                      <div className="flex items-center gap-2">
                        <div className="flex items-center gap-1 bg-white/5 px-3 py-1.5 rounded-full border border-white/5">
                           <Zap size={12} className="text-yellow-400" />
                           <span className="text-[10px] font-black text-white">{log.mood}</span>
                        </div>
                        <button 
                          onClick={() => handleEditPastLog(log.date)}
                          className={`p-3 rounded-2xl transition-all ${
                            log.date === date 
                            ? 'bg-white text-nature-950' 
                            : 'bg-white/5 text-ethereal-400 hover:bg-white/10'
                          }`}
                        >
                          <Edit3 size={18} />
                        </button>
                      </div>
                    </div>

                    {/* Resumo de Rituais no Card */}
                    <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                      {log.completedActions.diet && <div className="p-2 bg-nature-400/10 text-nature-400 rounded-lg"><Leaf size={14} /></div>}
                      {log.completedActions.meditationOrBreathing && <div className="p-2 bg-nature-400/10 text-nature-400 rounded-lg"><Wind size={14} /></div>}
                      {log.completedActions.exercise && <div className="p-2 bg-nature-400/10 text-nature-400 rounded-lg"><Footprints size={14} /></div>}
                      {log.completedActions.earthing && <div className="p-2 bg-nature-400/10 text-nature-400 rounded-lg"><Mountain size={14} /></div>}
                      {log.completedActions.waterGoal && <div className="p-2 bg-blue-400/10 text-blue-400 rounded-lg"><Droplets size={14} /></div>}
                    </div>

                    {log.date === date && (
                      <div className="pt-2 border-t border-nature-400/20 flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-nature-400 animate-pulse">
                        <Sparkles size={12} /> Visualizando no Editor
                      </div>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

