import React, { useEffect, useState, useMemo } from 'react';
import { UserProfile, DailyLog } from '../types';
import { CheckCircle2, Sparkles, Moon, Sun, Wind, Flower2, Footprints, Leaf, Droplets, Scroll, Mountain, Heart, Star, CalendarDays, Lock } from 'lucide-react';
import { analyzeUserLogs } from '../services/geminiService';

interface DashboardProps {
  userProfile: UserProfile;
  logs: DailyLog[];
  onToggleGoal: (goalKey: keyof DailyLog['completedActions']) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ userProfile, logs, onToggleGoal }) => {
  const [insight, setInsight] = useState<string | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const todayLog = logs.find(l => l.date === todayStr);

  const todaysGoals = [
    { id: 'diet', label: 'Nutrição Sagrada', completed: todayLog?.completedActions.diet, icon: Leaf, type: 'action' },
    { id: 'waterGoal', label: 'Água Cristalina', completed: todayLog?.completedActions.waterGoal, icon: Droplets, type: 'action' },
    { id: 'meditationOrBreathing', label: 'Respiração Cósmica', completed: todayLog?.completedActions.meditationOrBreathing, icon: Wind, type: 'action' },
    { id: 'exercise', label: 'Movimento Vital', completed: todayLog?.completedActions.exercise, icon: Footprints, type: 'action' },
    { id: 'earthing', label: 'Conexão Terra', completed: todayLog?.completedActions.earthing, icon: Mountain, type: 'action' },
    { id: 'emotionalWork', label: 'Cura da Essência', completed: todayLog?.completedActions.emotionalWork, icon: Heart, type: 'action' },
    { id: 'diary', label: 'Diário da Alma', completed: todayLog?.completedActions.diary, icon: Scroll, type: 'status' },
  ];

  const completedCount = todaysGoals.filter(g => g.completed).length;

  const history = useMemo(() => {
    const last7Days = [];
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const dStr = d.toISOString().split('T')[0];
      const log = logs.find(l => l.date === dStr);
      const count = log ? Object.values(log.completedActions).filter(v => v === true).length : 0;
      last7Days.push({
        date: dStr,
        dayName: d.toLocaleDateString('pt-BR', { weekday: 'short' }).replace('.', ''),
        count,
        isToday: dStr === todayStr
      });
    }
    return last7Days;
  }, [logs, todayStr]);

  useEffect(() => {
    const fetchInsight = async () => {
      if (logs.length >= 2 && !insight) {
        setLoadingInsight(true);
        const result = await analyzeUserLogs(logs);
        setInsight(result);
        setLoadingInsight(false);
      }
    };
    fetchInsight();
  }, [logs]);

  return (
    <div className="p-6 pb-32 max-w-2xl mx-auto space-y-12 animate-in fade-in duration-1000 relative overflow-hidden">
      <div className="absolute top-20 right-0 w-64 h-64 bg-nature-400/5 blur-[120px] rounded-full pointer-events-none" />

      <header className="flex justify-between items-start relative z-10">
        <div className="space-y-1">
          <p className="text-nature-400 font-black text-[10px] uppercase tracking-[0.4em]">Compromisso Diário</p>
          <h2 className="text-4xl font-serif text-white leading-tight">Olá, {userProfile.name}</h2>
        </div>
        <div className="glass-mystic text-white px-4 py-2 rounded-2xl flex items-center gap-2 border border-white/10">
          <Star size={14} className="text-nature-300" />
          <span className="text-[10px] font-bold uppercase tracking-widest">Dia {Math.floor((new Date().getTime() - new Date(userProfile.startDate!).getTime()) / (1000 * 3600 * 24)) + 1}</span>
        </div>
      </header>

      {/* Lotus de Progresso */}
      <section className="relative flex flex-col items-center justify-center py-12 glass-mystic rounded-[4rem] border border-white/5 shadow-inner">
        <div className="relative w-48 h-48 flex items-center justify-center">
          <div className="absolute w-24 h-24 bg-nature-400 blur-[60px] opacity-10 animate-pulse"></div>
          <svg viewBox="0 0 200 200" className="w-full h-full">
            {[...Array(7)].map((_, i) => {
              const angle = (i * 360) / 7;
              const isActive = i < completedCount;
              return (
                <path
                  key={i}
                  d="M100 100 C 130 60, 170 60, 100 20 C 30 60, 70 60, 100 100"
                  fill={isActive ? '#7fa365' : '#1e293b'}
                  className="lotus-petal transition-all duration-1000"
                  transform={`rotate(${angle} 100 100)`}
                  opacity={isActive ? 1 : 0.2}
                />
              );
            })}
          </svg>
          <div className="absolute flex flex-col items-center">
            <span className="text-4xl font-serif font-bold text-white">{completedCount}/7</span>
          </div>
        </div>
        <p className="text-[10px] font-black text-ethereal-500 uppercase tracking-widest mt-4">Pactos Honrados</p>
      </section>

      {/* PACTOS DE LUZ (Ação Rápida) */}
      <section className="space-y-6">
        <div className="px-4">
          <h3 className="text-2xl font-serif text-white tracking-tight">Pactos de Luz</h3>
          <p className="text-xs text-ethereal-500 italic mt-1">Check-list rápido do que você já realizou hoje.</p>
        </div>

        <div className="grid grid-cols-1 gap-3 px-2">
          {todaysGoals.map((goal, idx) => {
            const GoalIcon = goal.icon;
            const isStatus = goal.type === 'status';

            return (
              <button 
                key={idx} 
                onClick={() => !isStatus && onToggleGoal(goal.id as any)}
                disabled={isStatus}
                className={`p-5 rounded-[2.5rem] flex items-center gap-5 border transition-all duration-300 text-left w-full active:scale-95 group ${
                  goal.completed 
                    ? 'bg-nature-900/40 border-nature-500/30' 
                    : 'glass-mystic border-white/5 hover:border-nature-400/20'
                } ${isStatus ? 'cursor-default opacity-80' : ''}`}
              >
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${
                  goal.completed ? 'bg-nature-500 text-nature-950 shadow-[0_0_15px_rgba(127,163,101,0.3)]' : 'bg-white/5 text-ethereal-600'
                }`}>
                  {goal.completed ? <CheckCircle2 size={24} /> : <GoalIcon size={24} />}
                </div>
                <div className="flex-1">
                  <span className={`font-bold text-sm tracking-tight block ${goal.completed ? 'text-nature-400' : 'text-white'}`}>
                    {goal.label}
                  </span>
                  {isStatus && !goal.completed && (
                    <span className="text-[9px] text-ethereal-600 font-bold uppercase tracking-widest flex items-center gap-1 mt-0.5">
                      <Lock size={8} /> Complete na aba Diário
                    </span>
                  )}
                </div>
                {!isStatus && !goal.completed && (
                   <div className="w-8 h-8 rounded-full border border-white/10 flex items-center justify-center text-ethereal-700 group-hover:text-nature-400 group-hover:border-nature-400 transition-all">
                      <Plus size={14} />
                   </div>
                )}
              </button>
            );
          })}
        </div>
      </section>

      {/* Histórico Semanal */}
      <section className="space-y-6 px-4">
        <h3 className="text-xl font-serif text-white flex items-center gap-2">
          <CalendarDays size={18} className="text-nature-400" /> Constância
        </h3>
        <div className="flex justify-between items-end gap-2 overflow-x-auto no-scrollbar py-2">
          {history.map((day, idx) => (
            <div key={idx} className="flex flex-col items-center gap-2 min-w-[45px]">
              <div className="w-1.5 bg-white/5 rounded-full h-20 relative overflow-hidden">
                <div 
                  className={`absolute bottom-0 left-0 right-0 rounded-full transition-all duration-1000 ${day.count === 7 ? 'bg-magic-gold shadow-[0_0_10px_rgba(212,175,55,0.5)]' : 'bg-nature-500'}`}
                  style={{ height: `${(day.count / 7) * 100}%` }}
                />
              </div>
              <span className={`text-[8px] font-black uppercase tracking-widest ${day.isToday ? 'text-nature-400' : 'text-ethereal-600'}`}>
                {day.dayName}
              </span>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

