import React, { useState, useEffect, useMemo } from 'react';
import { Calendar, Save, Plus, Minus, Droplets, Check, Info, SmilePlus, History, Edit3, ChevronRight, CalendarDays, ClipboardCheck, Clock, UtensilsCrossed, Zap, Heart, Wind, Mountain, Footprints, Leaf, Sparkles, WheatOff, MilkOff, CandyOff, Coffee, Sun, Sunset, Moon, Scroll } from 'lucide-react';
import { DailyLog, Symptom } from '../types';

const SYMPTOMS: Symptom[] = [
  { id: '1', name: 'Inchaço abdominal', category: 'digestivo', weight: 3 },
  { id: '4', name: 'Brain Fog', category: 'neurologico', weight: 3 },
  { id: '5', name: 'Dor de cabeça', category: 'neurologico', weight: 2 },
  { id: '11', name: 'Tontura', category: 'neurologico', weight: 2 },
  { id: '6', name: 'Cansaço', category: 'outro', weight: 2 },
  { id: '9', name: 'Ansiedade', category: 'emocional', weight: 1 },
];

interface TrackerProps {
  onSaveLog: (log: DailyLog) => void;
  logs: DailyLog[];
}

const Tracker: React.FC<TrackerProps> = ({ onSaveLog, logs }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [meals, setMeals] = useState({ breakfast: '', lunch: '', dinner: '', snacks: '' });
  const [symptoms, setSymptoms] = useState<string[]>([]);
  const [mood, setMood] = useState(3);
  const [waterGlasses, setWaterGlasses] = useState(0);

  // Rituais apenas para conferência (não é o foco aqui)
  const [habits, setHabits] = useState({
    diet: false,
    meditation: false,
    exercise: false,
    earthing: false,
    emotionalWork: false
  });

  const sortedLogs = useMemo(() => {
    return [...logs].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [logs]);

  useEffect(() => {
    const existingLog = logs.find(l => l.date === date);
    if (existingLog) {
      setMeals(existingLog.meals);
      setSymptoms(existingLog.symptomsPresent || []);
      setMood(existingLog.mood);
      setWaterGlasses(existingLog.waterIntake || 0);
      setHabits({
        diet: existingLog.completedActions.diet,
        meditation: existingLog.completedActions.meditationOrBreathing,
        exercise: existingLog.completedActions.exercise,
        earthing: existingLog.completedActions.earthing,
        emotionalWork: existingLog.completedActions.emotionalWork
      });
    } else {
      setMeals({ breakfast: '', lunch: '', dinner: '', snacks: '' });
      setSymptoms([]);
      setMood(3);
      setWaterGlasses(0);
      setHabits({ diet: false, meditation: false, exercise: false, earthing: false, emotionalWork: false });
    }
  }, [date, logs]);

  const handleSave = () => {
    onSaveLog({
      date,
      meals,
      symptomsPresent: symptoms,
      mood,
      waterIntake: waterGlasses,
      completedActions: { 
        ...habits,
        diet: habits.diet,
        diary: true, // AUTO-COMPLETE ao salvar
        meditationOrBreathing: habits.meditation,
        waterGoal: waterGlasses >= 8 
      }
    });
    alert(`Seu relato de cura foi eternizado! ✨`);
  };

  const handleEditPastLog = (pastDate: string) => {
    setDate(pastDate);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const toggleSymptom = (id: string) => {
    setSymptoms(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const mealConfigs = [
    { id: 'breakfast', label: 'Despertar', icon: Coffee, placeholder: 'O que nutriu seu despertar?' },
    { id: 'lunch', label: 'Sol Pleno', icon: Sun, placeholder: 'Como foi sua nutrição principal?' },
    { id: 'dinner', label: 'Crepúsculo', icon: Sunset, placeholder: 'Sua última alquimia do dia...' },
    { id: 'snacks', label: 'Pequenos Ciclos', icon: Moon, placeholder: 'Lanches e hidratação extra...' },
  ];

  return (
    <div className="p-4 pb-40 max-w-2xl mx-auto space-y-12 animate-in fade-in duration-500">
      <header className="px-4">
        <h2 className="text-4xl font-serif text-white tracking-tight">Recordatário</h2>
        <p className="text-nature-400 text-[10px] font-black uppercase tracking-[0.4em]">Profundidade do Ser</p>
      </header>

      {/* Seletor de Data */}
      <div className="glass-mystic p-6 rounded-[3rem] border border-white/10 mx-2 flex justify-between items-center shadow-xl">
        <div className="flex items-center gap-4">
          <CalendarDays className="text-nature-400" size={20} />
          <div>
            <span className="text-[10px] font-black uppercase text-ethereal-600 block">Relato de</span>
            <span className="text-white font-serif text-lg">{new Date(date + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}</span>
          </div>
        </div>
        <div className="relative">
          <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="absolute inset-0 opacity-0 cursor-pointer" />
          <div className="p-3 bg-white/5 rounded-2xl border border-white/10 text-white"><Edit3 size={18} /></div>
        </div>
      </div>

      <div className="space-y-10">
        {/* SINTOMAS */}
        <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-6">
          <h3 className="font-serif text-2xl text-white flex items-center gap-3">
             <div className="w-1.5 h-6 bg-rose-500 rounded-full"></div> Sinais do Templo
          </h3>
          <p className="text-xs text-ethereal-500 italic">Marque se sentiu algum desses sinais hoje.</p>
          <div className="grid grid-cols-2 gap-2">
            {SYMPTOMS.map(s => (
              <button
                key={s.id}
                onClick={() => toggleSymptom(s.id)}
                className={`p-4 rounded-2xl text-[11px] font-bold border transition-all text-left ${symptoms.includes(s.id) ? 'bg-rose-950/30 border-rose-500/50 text-rose-200' : 'bg-white/5 border-transparent text-ethereal-600'}`}
              >
                {s.name}
              </button>
            ))}
          </div>
        </section>

        {/* ALQUIMIA */}
        <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-8">
           <h3 className="font-serif text-2xl text-white flex items-center gap-3">
             <div className="w-1.5 h-6 bg-nature-400 rounded-full"></div> Relato Nutritivo
          </h3>
          <div className="space-y-8">
            {mealConfigs.map(config => (
              <div key={config.id} className="space-y-3">
                <div className="flex items-center gap-2 px-2">
                  <config.icon size={16} className="text-nature-400" />
                  <label className="text-sm font-serif text-white">{config.label}</label>
                </div>
                <textarea 
                  className="w-full bg-white/5 border border-white/5 rounded-3xl p-5 text-sm text-white focus:border-nature-400/30 outline-none resize-none placeholder:text-ethereal-800"
                  placeholder={config.placeholder}
                  rows={2}
                  value={meals[config.id as keyof typeof meals]}
                  onChange={(e) => setMeals({...meals, [config.id]: e.target.value})}
                />
              </div>
            ))}
          </div>
        </section>

        {/* ÁGUA E HUMOR */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-4">
           <div className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-4">
