import { GoogleGenAI, Type, Modality } from "@google/genai";
import { DailyLog, Recipe } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const modelId = "gemini-3-flash-preview"; 
const ttsModelId = "gemini-2.5-flash-preview-tts";

export const generateDailyContent = async () => {
  try {
    const prompt = `Atue como um Guia Espiritual e Nutricionista Funcional. Crie um portal de sabedoria diário (JSON): menu (4 receitas S/G, S/L, S/A), motivação e desafio diário. IMPORTANTE: Priorize receitas ultra rápidas que fiquem prontas em no máximo 5 minutos, especialmente para o café da manhã.`;
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            menu: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  title: { type: Type.STRING },
                  ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
                  instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
                  prepTime: { type: Type.STRING, description: "Tempo de preparo, ex: 5 min" }
                }
              }
            },
            motivation: { type: Type.STRING },
            dailyChallenge: { type: Type.STRING }
          }
        }
      }
    });
    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    return null;
  }
};

export const generateSingleRecipe = async (mealType: string): Promise<Recipe> => {
  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: `Gere uma receita S/G, S/L, S/A para: ${mealType}. Deve ser uma receita ultra rápida (máximo 5 minutos). JSON format.`,
      config: { 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            type: { type: Type.STRING },
            title: { type: Type.STRING },
            ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
            instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
            prepTime: { type: Type.STRING }
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    return { type: mealType, title: "Receita de Luz", ingredients: [], instructions: [], prepTime: "5 min" };
  }
};

