       </header>

      {/* Mantra Card */}
      <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 relative overflow-hidden group">
        <Sun className="text-nature-400 absolute -top-4 -right-4 w-32 h-32 opacity-5 group-hover:scale-110 transition-transform duration-1000" />
        <div className="relative z-10 space-y-4">
