            "{content?.motivation}"
          </p>
        </div>
      </section>

      {/* Challenge */}
      <section className="glass-mystic p-6 rounded-[2.5rem] border border-white/5 flex items-center gap-5">
         <div className="w-14 h-14 bg-white/5 rounded-2xl flex items-center justify-center shadow-sm shrink-0 text-nature-400 border border-white/10">
            <Footprints size={28} />
