         <div className="space-y-1">
            <h3 className="font-bold text-white text-sm">Ritual de Conexão</h3>
            <p className="text-ethereal-400 text-xs leading-relaxed">{content?.dailyChallenge}</p>
         </div>
      </section>

      {/* Recipes */}
      <section className="space-y-8">
        <div className="flex justify-between items-end px-2">
           <h3 className="text-2xl font-serif text-white flex items-center gap-3">
             <Utensils size={24} className="text-nature-400" /> Alquimia Nutritiva
           </h3>
           <span className="text-[9px] font-black text-magic-gold bg-magic-gold/10 px-3 py-1.5 rounded-full border border-magic-gold/20 uppercase tracking-widest">Ultra Rápido</span>
        </div>

        <div className="space-y-8">
          {content?.menu.map((recipe, index) => (
            <div key={index} className="relative glass-mystic rounded-[3rem] border border-white/5 overflow-hidden group hover:border-white/10 transition-all">

