import { GoogleGenAI, Type, Modality } from "@google/genai";
import { DailyLog, Recipe } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const modelId = "gemini-3-flash-preview"; 
const ttsModelId = "gemini-2.5-flash-preview-tts";

const SYSTEM_DIET_RULES = "As receitas devem ser OBRIGATORIAMENTE: Proteicas, ricas em gorduras boas (abacate, coco, sementes, nuts), Sem Glúten (S/G), Sem Leite/Lactose (S/L) e Sem Açúcar (S/A). Máximo 5 minutos de preparo.";

export const generateDailyContent = async () => {
  try {
    const prompt = `Atue como um Guia Espiritual e Nutricionista Funcional. Crie um portal de sabedoria diário (JSON): menu (4 receitas), motivação e desafio diário. ${SYSTEM_DIET_RULES}`;
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            menu: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  title: { type: Type.STRING },
                  ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
                  instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
                  prepTime: { type: Type.STRING }
                }
              }
            },
            motivation: { type: Type.STRING },
            dailyChallenge: { type: Type.STRING }
          }
        }
      }
    });
    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    return null;
  }
};

export const generateSingleRecipe = async (mealType: string): Promise<Recipe> => {
  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: `Gere uma receita para: ${mealType}. ${SYSTEM_DIET_RULES} JSON format.`,
      config: { 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            type: { type: Type.STRING },
            title: { type: Type.STRING },
            ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
            instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
            prepTime: { type: Type.STRING }
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    return { type: mealType, title: "Receita de Luz", ingredients: [], instructions: [], prepTime: "5 min" };
  }
};

export const analyzeUserLogs = async (logs: DailyLog[]) => {
  try {
    const response = await ai.models.generateContent({ 
      model: modelId, 
      contents: `Analise estes logs e dê um insight poético curto sobre a evolução da cura: ${JSON.stringify(logs.slice(-3))}` 
    });
    return response.text;
  } catch (e) {
    return "Sua essência brilha em transformação.";
  }
}

export const generateSpeech = async (text: string) => {
  try {
    const response = await ai.models.generateContent({
      model: ttsModelId,
      contents: [{ parts: [{ text: `Diga com voz clara, calma e presente: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    return null;
  }
};

