  const [loadingInsight, setLoadingInsight] = useState(false);

  const todayStr = new Date().toISOString().split('T')[0];
  const todayLog = logs.find(l => l.date === todayStr);

  const todaysGoals = [
    { id: 'diet', label: 'Nutrição Sagrada', completed: todayLog?.completedActions.diet, icon: Leaf, type: 'action' },
    { id: 'waterGoal', label: 'Água Cristalina', completed: todayLog?.completedActions.waterGoal, icon: Droplets, type: 'action' },
    { id: 'meditationOrBreathing', label: 'Respiração Cósmica', completed: todayLog?.completedActions.meditationOrBreathing, icon: Wind, type: 'action' },
    { id: 'exercise', label: 'Movimento Vital', completed: todayLog?.completedActions.exercise, icon: Footprints, type: 'action' },
    { id: 'earthing', label: 'Conexão Terra', completed: todayLog?.completedActions.earthing, icon: Mountain, type: 'action' },
    { id: 'emotionalWork', label: 'Cura da Essência', completed: todayLog?.completedActions.emotionalWork, icon: Heart, type: 'action' },
    { id: 'diary', label: 'Relato da Alma', completed: todayLog?.completedActions.diary, icon: Scroll, type: 'status' },
