                </div>
                <div className="flex-1">
                  <span className={`font-bold text-sm tracking-tight block ${goal.completed ? 'text-nature-400' : 'text-white'}`}>
                    {goal.label}
                  </span>
                  {isStatus && !goal.completed ? (
                    <span className="text-[9px] text-ethereal-600 font-bold uppercase tracking-widest flex items-center gap-1 mt-0.5">
                      <Lock size={8} className="mb-0.5" /> Registre seu Diário para desbloquear
                    </span>
                  ) : (
                    <span className="text-[9px] text-ethereal-600 font-medium uppercase tracking-widest mt-0.5">
                      {goal.completed ? 'Pacto Honrado' : 'Aguardando seu toque'}
                    </span>
                  )}
                </div>
                {!isStatus && !goal.completed && (
                   <Circle size={16} className="text-ethereal-800 group-hover:text-nature-400 transition-colors" />
                )}
              </button>
            );
          })}
        </div>
      </section>

      {/* Insight da Alma */}
      {insight && (
        <section className="px-4 animate-in slide-in-from-bottom-8">
           <div className="glass-mystic p-8 rounded-[3rem] border border-white/5 bg-nature-900/10 italic text-sm text-ethereal-300 leading-relaxed text-center relative">
              <Sparkles size={14} className="text-nature-400 absolute -top-2 left-1/2 -translate-x-1/2" />
              "{insight}"
           </div>
        </section>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { Save, Plus, Minus, Droplets, History, Edit3, CalendarDays, Coffee, Sun, Sunset, Moon, Scroll, Quote, Activity, Sparkles, Wind, Leaf, Heart } from 'lucide-react';
import { DailyLog, Symptom } from '../types';

const SYMPTOMS: Symptom[] = [
  { id: '1', name: 'Inchaço abdominal', category: 'digestivo', weight: 3 },
  { id: '4', name: 'Brain Fog', category: 'neurologico', weight: 3 },
  { id: '5', name: 'Dor de cabeça', category: 'neurologico', weight: 2 },
  { id: '11', name: 'Tontura', category: 'neurologico', weight: 2 },
  { id: '6', name: 'Cansaço', category: 'outro', weight: 2 },
  { id: '9', name: 'Ansiedade', category: 'emocional', weight: 1 },
  { id: 'other', name: 'Outros (descreva na reflexão)', category: 'outro', weight: 1 },
];

interface TrackerProps {
  onSaveLog: (log: DailyLog) => void;
  logs: DailyLog[];
}

const Tracker: React.FC<TrackerProps> = ({ onSaveLog, logs }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [meals, setMeals] = useState({ breakfast: '', lunch: '', dinner: '', snacks: '' });
  const [reflection, setReflection] = useState('');
  const [symptoms, setSymptoms] = useState<string[]>([]);
  const [mood, setMood] = useState(3);
  const [waterGlasses, setWaterGlasses] = useState(0);

  const [habits, setHabits] = useState({
    diet: false,
    meditation: false,
    exercise: false,
    earthing: false,
    emotionalWork: false
  });

  const sortedLogs = useMemo(() => {
    return [...logs].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [logs]);

  useEffect(() => {
    const existingLog = logs.find(l => l.date === date);
    if (existingLog) {
      setMeals(existingLog.meals);
      setReflection(existingLog.reflection || '');
      setSymptoms(existingLog.symptomsPresent || []);
      setMood(existingLog.mood);
      setWaterGlasses(existingLog.waterIntake || 0);
      setHabits({
        diet: existingLog.completedActions.diet,
        meditation: existingLog.completedActions.meditationOrBreathing,
        exercise: existingLog.completedActions.exercise,
        earthing: existingLog.completedActions.earthing,
        emotionalWork: existingLog.completedActions.emotionalWork
      });
    } else {
      setMeals({ breakfast: '', lunch: '', dinner: '', snacks: '' });
      setReflection('');
      setSymptoms([]);
      setMood(3);
      setWaterGlasses(0);
      setHabits({ diet: false, meditation: false, exercise: false, earthing: false, emotionalWork: false });
    }
  }, [date, logs]);

  const handleSave = () => {
    onSaveLog({
      date,
      meals,
      reflection,
      symptomsPresent: symptoms,
      mood,
      waterIntake: waterGlasses,
      completedActions: { 
        ...habits,
        diet: habits.diet,
        diary: reflection.length > 5, 
        meditationOrBreathing: habits.meditation,
        waterGoal: waterGlasses >= 8 
      }
    });
    alert(`Seu relato de cura foi eternizado! ✨`);
  };

  const handleEditPastLog = (pastDate: string) => {
    setDate(pastDate);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const toggleSymptom = (id: string) => {
    setSymptoms(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const mealConfigs = [
    { id: 'breakfast', label: 'Despertar Proteico', icon: Coffee, placeholder: 'Priorize proteínas e gorduras boas aqui.' },
    { id: 'lunch', label: 'Almoço Funcional', icon: Sun, placeholder: 'Como estava sua digestão?' },
    { id: 'dinner', label: 'Ceia Leve', icon: Sunset, placeholder: 'Última nutrição do dia...' },
    { id: 'snacks', label: 'Entre Ciclos', icon: Moon, placeholder: 'Nuts, sementes ou infusões?' },
  ];

  return (
    <div className="p-4 pb-40 max-w-2xl mx-auto space-y-12 animate-in fade-in duration-500">
      <header className="px-4">
        <h2 className="text-4xl font-serif text-white tracking-tight">Recordatário</h2>
        <p className="text-nature-400 text-[10px] font-black uppercase tracking-[0.4em]">Sintonias da Alma</p>
      </header>

      {/* Seletor de Data */}
      <div className="glass-mystic p-6 rounded-[3rem] border border-white/10 mx-2 flex justify-between items-center shadow-xl">
        <div className="flex items-center gap-4">
          <CalendarDays className="text-nature-400" size={20} />
          <div>
            <span className="text-[10px] font-black uppercase text-ethereal-600 block">Jornada de</span>
            <span className="text-white font-serif text-lg">{new Date(date + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'long' })}</span>
          </div>
        </div>
        <div className="relative">
          <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="absolute inset-0 opacity-0 cursor-pointer" />
          <div className="p-3 bg-white/5 rounded-2xl border border-white/10 text-white"><Edit3 size={18} /></div>
        </div>
      </div>

      <div className="space-y-10">
        {/* REFLEXÃO DA JORNADA */}
        <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-6">
           <h3 className="font-serif text-2xl text-white flex items-center gap-3">
             <div className="w-1.5 h-6 bg-magic-gold rounded-full"></div> Reflexão da Alma
          </h3>
          <div className="space-y-2">
            <p className="text-[10px] text-ethereal-500 uppercase font-black tracking-widest">O que escrever aqui?</p>
            <p className="text-xs text-ethereal-400 italic">Descreva seus insights, como o corpo reagiu às refeições, percepções sobre os rituais ou se notou algum sintoma "Outros" não listado.</p>
          </div>
          <textarea 
            className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-6 text-sm text-white focus:border-magic-gold/50 outline-none resize-none placeholder:text-ethereal-800 italic leading-relaxed"
            placeholder="Hoje percebi que o abacate no café me deu mais energia... Senti um desconforto ao..."
            rows={5}
            value={reflection}
            onChange={(e) => setReflection(e.target.value)}
          />
        </section>

        {/* SINTOMAS */}
        <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-6">
          <h3 className="font-serif text-2xl text-white flex items-center gap-3">
             <div className="w-1.5 h-6 bg-rose-500 rounded-full"></div> Sinais do Templo
          </h3>
          <div className="grid grid-cols-2 gap-2">
            {SYMPTOMS.map(s => (
              <button
                key={s.id}
                onClick={() => toggleSymptom(s.id)}
                className={`p-4 rounded-2xl text-[11px] font-bold border transition-all text-left flex justify-between items-center ${symptoms.includes(s.id) ? 'bg-rose-950/30 border-rose-500/50 text-rose-200' : 'bg-white/5 border-transparent text-ethereal-600'}`}
              >
                {s.name}
                {symptoms.includes(s.id) && <Activity size={10} className="animate-pulse" />}
              </button>
            ))}
          </div>
        </section>

        {/* ALQUIMIA */}
        <section className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-8">
           <h3 className="font-serif text-2xl text-white flex items-center gap-3">
             <div className="w-1.5 h-6 bg-nature-400 rounded-full"></div> Relato Nutritivo
          </h3>
          <div className="space-y-8">
            {mealConfigs.map(config => (
              <div key={config.id} className="space-y-3">
                <div className="flex items-center gap-2 px-2">
                  <config.icon size={16} className="text-nature-400" />
                  <label className="text-sm font-serif text-white">{config.label}</label>
                </div>
                <textarea 
                  className="w-full bg-white/5 border border-white/5 rounded-3xl p-5 text-sm text-white focus:border-nature-400/30 outline-none resize-none placeholder:text-ethereal-800"
                  placeholder={config.placeholder}
                  rows={2}
                  value={meals[config.id as keyof typeof meals]}
                  onChange={(e) => setMeals({...meals, [config.id]: e.target.value})}
                />
              </div>
            ))}
          </div>
        </section>

        {/* ÁGUA E HUMOR */}
        <section className="grid grid-cols-1 md:grid-cols-2 gap-4">
           <div className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-4">
              <span className="text-[10px] font-black uppercase text-blue-400 tracking-widest flex items-center gap-2"><Droplets size={12}/> Hidratação (Copos)</span>
              <div className="flex items-center justify-between bg-white/5 p-4 rounded-2xl">
                 <button onClick={() => setWaterGlasses(Math.max(0, waterGlasses - 1))} className="text-blue-400"><Minus size={18}/></button>
                 <span className="text-white font-bold">{waterGlasses * 250}ml</span>
                 <button onClick={() => setWaterGlasses(waterGlasses + 1)} className="text-blue-400"><Plus size={18}/></button>
              </div>
           </div>
           <div className="glass-mystic p-8 rounded-[3rem] border border-white/5 space-y-4 text-center">
              <span className="text-[10px] font-black uppercase text-nature-400 tracking-widest">Vibração Vital</span>
              <div className="flex justify-center gap-2">
                {[1,2,3,4,5].map(v => (
                  <button key={v} onClick={() => setMood(v)} className={`w-10 h-10 rounded-xl font-bold transition-all ${mood === v ? 'bg-white text-nature-950' : 'bg-white/5 text-ethereal-700'}`}>{v}</button>
                ))}
              </div>
           </div>
        </section>

        <button 
           onClick={handleSave}
           className="w-full bg-nature-500 text-white py-6 rounded-[3rem] font-bold text-lg flex items-center justify-center gap-4 shadow-2xl active:scale-95 transition-transform"
        >
           <Save size={24} /> Eternizar Relato
        </button>

        {/* MINHA JORNADA (LINHA DO TEMPO) */}
        <section className="space-y-8 pt-12">
          <div className="flex flex-col gap-1 px-6">
            <h3 className="text-2xl font-serif text-white">Minha Jornada</h3>
            <p className="text-[10px] text-nature-400 uppercase font-black tracking-[0.3em]">Histórico de Descobertas</p>
          </div>

          <div className="relative px-4 space-y-6">
            <div className="absolute left-10 top-0 bottom-0 w-px bg-gradient-to-b from-nature-400/20 via-white/5 to-transparent ml-[-0.5px]" />

            {sortedLogs.length === 0 ? (
              <div className="p-12 text-center glass-mystic rounded-[2rem] border border-white/5 border-dashed">
                <p className="text-ethereal-600 italic text-sm">Nenhum rastro de luz encontrado ainda.</p>
              </div>
            ) : (
              sortedLogs.map((log) => (
                <div key={log.date} className="relative pl-12">
                  <div className={`absolute left-0 top-6 w-5 h-5 rounded-full border-4 shadow-lg z-10 ${log.date === date ? 'bg-white border-nature-400 scale-125 animate-pulse' : 'bg-nature-950 border-white/10'}`} />

                  <div className={`p-6 rounded-[2.5rem] border transition-all ${log.date === date ? 'bg-nature-900 border-nature-500 shadow-xl' : 'glass-mystic border-white/5 hover:border-white/10'}`}>
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <span className="text-[10px] font-black uppercase text-nature-500">{new Date(log.date + 'T00:00:00').toLocaleDateString('pt-BR', { weekday: 'short' })}</span>
                        <h4 className="text-white font-serif text-lg">{new Date(log.date + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' })}</h4>
                      </div>
                      <button onClick={() => handleEditPastLog(log.date)} className="p-2 text-ethereal-500 hover:text-white"><Edit3 size={16} /></button>
                    </div>

                    {log.reflection && (
                      <div className="mb-4 p-4 bg-white/5 rounded-2xl border-l-2 border-magic-gold/30">
                        <Quote size={12} className="text-magic-gold opacity-30 mb-2" />
                        <p className="text-xs text-ethereal-300 italic line-clamp-2 leading-relaxed">
                          {log.reflection}
                        </p>
                      </div>
                    )}

                    <div className="flex gap-2 flex-wrap">
                      {log.completedActions.diary && <div className="p-2 bg-nature-400/10 text-nature-400 rounded-lg"><Scroll size={14} /></div>}
                      {log.completedActions.diet && <div className="p-2 bg-nature-400/10 text-nature-400 rounded-lg"><Leaf size={14} /></div>}
                      {log.completedActions.meditationOrBreathing && <div className="p-2 bg-nature-400/10 text-nature-400 rounded-lg"><Wind size={14} /></div>}
                      {log.completedActions.waterGoal && <div className="p-2 bg-blue-400/10 text-blue-400 rounded-lg"><Droplets size={14} /></div>}
                      {log.mood > 3 && <div className="p-2 bg-yellow-400/10 text-yellow-400 rounded-lg"><Sparkles size={14} /></div>}
                      {log.completedActions.emotionalWork && <div className="p-2 bg-rose-400/10 text-rose-400 rounded-lg"><Heart size={14} /></div>}
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

export default Tracker;
